# ==================== SYSTEM ROLE NORMALIZATION ====================
# Maps human-readable roles to standardized system roles for compliance logic
# 
# IMPORTANT: All compliance, training, and readiness logic MUST use system_role
# NOT the raw role field. Raw role is for display only.

class SystemRole:
    """Standardized system roles for compliance logic"""
    HCA = "HCA"      # Healthcare Assistant - general care workers
    NURSE = "NURSE"  # Registered Nurses - requires NMC registration
    UNKNOWN = "UNKNOWN"  # Unmapped roles - flagged for review

# Role to system_role mapping
# Keys are LOWERCASE for case-insensitive matching
SYSTEM_ROLE_MAP = {
    # HCA roles - with spaces
    "care assistant": SystemRole.HCA,
    "senior care assistant": SystemRole.HCA,
    "support worker": SystemRole.HCA,
    "healthcare assistant": SystemRole.HCA,
    "live-in carer": SystemRole.HCA,
    "night carer": SystemRole.HCA,
    "team leader": SystemRole.HCA,
    # HCA roles - with underscores (legacy format)
    "care_assistant": SystemRole.HCA,
    "senior_care_assistant": SystemRole.HCA,
    "support_worker": SystemRole.HCA,
    "healthcare_assistant": SystemRole.HCA,
    "live_in_carer": SystemRole.HCA,
    "night_carer": SystemRole.HCA,
    "team_leader": SystemRole.HCA,
    # NURSE roles
    "nurse": SystemRole.NURSE,
    "registered nurse": SystemRole.NURSE,
    "registered_nurse": SystemRole.NURSE,
    "nurse (registered)": SystemRole.NURSE,  # matches apply form dropdown value
    "senior nurse": SystemRole.NURSE,         # matches apply form dropdown value
    "senior_nurse": SystemRole.NURSE,
    "staff nurse": SystemRole.NURSE,
    "staff_nurse": SystemRole.NURSE,
    "district nurse": SystemRole.NURSE,
    "district_nurse": SystemRole.NURSE,
    "community nurse": SystemRole.NURSE,
    "community_nurse": SystemRole.NURSE,
    "practice nurse": SystemRole.NURSE,
    "practice_nurse": SystemRole.NURSE,
}

# Roles that should NOT automatically inherit HCA compliance
# These require explicit review before mapping
ROLES_REQUIRING_REVIEW = {
    "care coordinator",
    "administrator",
    "manager",
    "office staff",
}


def normalize_to_system_role(role: str) -> str:
    """
    Normalize a human-readable role to a system role.
    
    Args:
        role: The raw role string (e.g., "Care Assistant", "Nurse")
    
    Returns:
        SystemRole constant (HCA, NURSE, or UNKNOWN)
    
    IMPORTANT: This function logs unmapped roles for review.
    Do not silently guess - flag for manual review.
    """
    if not role:
        logger.warning(f"[ROLE_NORMALIZATION] Empty role provided, returning UNKNOWN")
        return SystemRole.UNKNOWN
    
    role_lower = role.strip().lower()
    
    # Check direct mapping
    if role_lower in SYSTEM_ROLE_MAP:
        return SYSTEM_ROLE_MAP[role_lower]
    
    # Check if role requires explicit review
    if role_lower in ROLES_REQUIRING_REVIEW:
        logger.warning(f"[ROLE_NORMALIZATION] Role '{role}' requires review - not auto-mapped")
        return SystemRole.UNKNOWN
    
    # Log unmapped role for review
    logger.warning(f"[ROLE_NORMALIZATION] Unmapped role: '{role}' - returning UNKNOWN")
    return SystemRole.UNKNOWN


def get_system_role_for_employee(employee: dict) -> str:
    """
    Get the system_role for an employee, with fallback to normalized role.
    
    Priority:
    1. Use existing system_role if set
    2. Normalize from role field
    
    Args:
        employee: Employee document dict
    
    Returns:
        SystemRole constant
    """
    # If system_role already set, use it
    if employee.get("system_role"):
        return employee["system_role"]
    
    # Otherwise normalize from role
    return normalize_to_system_role(employee.get("role", ""))


def is_nurse_role(system_role: str) -> bool:
    """Check if system_role is NURSE - use instead of string matching"""
    return system_role == SystemRole.NURSE


def is_hca_role(system_role: str) -> bool:
    """Check if system_role is HCA - use instead of string matching"""
    return system_role == SystemRole.HCA


def _is_applicant_status(status: str) -> bool:
    return status in _APPLICANT_STATUSES

def _is_employee_status(status: str) -> bool:
    return status in _EMPLOYEE_STATUSES

def _applicant_scope_filter(existing_filter: dict = None) -> dict:
    base = {"status": {"$in": _APPLICANT_STATUSES}}
    if existing_filter:
        return {**existing_filter, **base}
    return base

def _employee_scope_filter(existing_filter: dict = None) -> dict:
    base = {"status": {"$in": _EMPLOYEE_STATUSES}}
    if existing_filter:
        return {**existing_filter, **base}
    return base


class EmployeesRepository:
    """
    Central repository for scoped employee/applicant queries.
    
    RULES:
    - Staff/Employee views MUST use employee-scoped methods
    - Recruitment views MUST use applicant-scoped methods
    - Raw db.employees queries are BANNED for UI-serving endpoints
    - Profile lookups validate scope and return 404 for wrong scope
    """
    
    @staticmethod
    async def list_employees(
        filter_dict: dict = None,
        projection: dict = None,
        sort: list = None,
        limit: int = 1000,
        skip: int = 0
    ) -> list:
        """List employees only (onboarding, active, inactive)"""
        query = _employee_scope_filter(filter_dict or {})
        proj = projection or {"_id": 0}
        cursor = db.employees.find(query, proj)
        if sort:
            cursor = cursor.sort(sort)
        if skip:
            cursor = cursor.skip(skip)
        if limit:
            cursor = cursor.limit(limit)
        return await cursor.to_list(limit or 1000)
    
    @staticmethod
    async def list_applicants(
        filter_dict: dict = None,
        projection: dict = None,
        sort: list = None,
        limit: int = 1000,
        skip: int = 0
    ) -> list:
        """List applicants only (new, screening, interview, compliance_review)"""
        query = _applicant_scope_filter(filter_dict or {})
        proj = projection or {"_id": 0}
        cursor = db.employees.find(query, proj)
        if sort:
            cursor = cursor.sort(sort)
        if skip:
            cursor = cursor.skip(skip)
        if limit:
            cursor = cursor.limit(limit)
        return await cursor.to_list(limit or 1000)
    
    @staticmethod
    async def count_employees(filter_dict: dict = None) -> int:
        """Count employees only"""
        query = _employee_scope_filter(filter_dict or {})
        return await db.employees.count_documents(query)
    
    @staticmethod
    async def count_applicants(filter_dict: dict = None) -> int:
        """Count applicants only"""
        query = _applicant_scope_filter(filter_dict or {})
        return await db.employees.count_documents(query)
    
    @staticmethod
    async def get_employee_by_id(employee_id: str, projection: dict = None):
        """
        Get employee by ID - validates employee scope.
        Returns None if not found OR if record is applicant-status.
        """
        proj = projection or {"_id": 0}
        record = await db.employees.find_one({"id": employee_id}, proj)
        if not record:
            return None
        if not _is_employee_status(record.get("status", "")):
            return None  # Record exists but is applicant, not employee
        return record
    
    @staticmethod
    async def get_applicant_by_id(applicant_id: str, projection: dict = None):
        """
        Get applicant by ID - validates applicant scope.
        Returns None if not found OR if record is employee-status.
        """
        proj = projection or {"_id": 0}
        record = await db.employees.find_one({"id": applicant_id}, proj)
        if not record:
            return None
        if not _is_applicant_status(record.get("status", "")):
            return None  # Record exists but is employee, not applicant
        return record
    
    @staticmethod
    async def get_by_id_any_scope(record_id: str, projection: dict = None):
        """
        Get record by ID regardless of scope.
        Use ONLY for internal operations that need to work across scopes.
        NOT for UI-serving endpoints.
        """
        proj = projection or {"_id": 0}
        return await db.employees.find_one({"id": record_id}, proj)
    
    @staticmethod
    async def aggregate_employees(pipeline: list) -> list:
        """Run aggregation on employee-scoped records only"""
        scoped_pipeline = [{"$match": _employee_scope_filter()}] + pipeline
        return await db.employees.aggregate(scoped_pipeline).to_list(None)
    
    @staticmethod
    async def aggregate_applicants(pipeline: list) -> list:
        """Run aggregation on applicant-scoped records only"""
        scoped_pipeline = [{"$match": _applicant_scope_filter()}] + pipeline
        return await db.employees.aggregate(scoped_pipeline).to_list(None)
    
    @staticmethod
    async def search_employees(
        query_text: str,
        limit: int = 20,
        additional_filter: dict = None
    ) -> list:
        """Search employees by name/email - employee scope only"""
        import re as regex_module
        pattern = regex_module.compile(regex_module.escape(query_text), regex_module.IGNORECASE)
        search_filter = {
            "$or": [
                {"first_name": pattern},
                {"last_name": pattern},
                {"email": pattern},
                {"employee_code": pattern}
            ]
        }
        if additional_filter:
            search_filter = {**search_filter, **additional_filter}
        query = _employee_scope_filter(search_filter)
        return await db.employees.find(query, {"_id": 0}).limit(limit).to_list(limit)
    
    @staticmethod
    async def search_applicants(
        query_text: str,
        limit: int = 20,
        additional_filter: dict = None
    ) -> list:
        """Search applicants by name/email - applicant scope only"""
        import re as regex_module
        pattern = regex_module.compile(regex_module.escape(query_text), regex_module.IGNORECASE)
        search_filter = {
            "$or": [
                {"first_name": pattern},
                {"last_name": pattern},
                {"email": pattern},
                {"applicant_reference": pattern}
            ]
        }
        if additional_filter:
            search_filter = {**search_filter, **additional_filter}
        query = _applicant_scope_filter(search_filter)
        return await db.employees.find(query, {"_id": 0}).limit(limit).to_list(limit)


