# ==================== MODELS ====================

class UserRole:
    SUPER_ADMIN = "super_admin"
    ADMIN = "admin"
    BRANCH_MANAGER = "branch_manager"  # Legacy - now manages assignments
    EMPLOYEE = "employee"
    AUDITOR = "auditor"

class EmployeeStatus:
    NEW = "new"
    SCREENING = "screening"
    INTERVIEW = "interview"
    COMPLIANCE_REVIEW = "compliance_review"
    ONBOARDING = "onboarding"
    ACTIVE = "active"
    INACTIVE = "inactive"
    ARCHIVED = "archived"

# Stage Classification Constants
# Applicant = pre-hire decision, Employee = post-hire decision
APPLICANT_STATUSES = [
    EmployeeStatus.NEW,
    EmployeeStatus.SCREENING,
    EmployeeStatus.INTERVIEW,
    EmployeeStatus.COMPLIANCE_REVIEW
]

EMPLOYEE_STATUSES = [
    EmployeeStatus.ONBOARDING,
    EmployeeStatus.ACTIVE,
    EmployeeStatus.INACTIVE
]

class PersonStage:
    """Derived from status - not stored, computed at runtime"""
    APPLICANT = "applicant"
    EMPLOYEE = "employee"

def get_person_stage(status: str) -> str:
    """
    Derive person_stage from status.
    This is the SINGLE SOURCE of truth for applicant vs employee classification.
    """
    if status in APPLICANT_STATUSES:
        return PersonStage.APPLICANT
    elif status in EMPLOYEE_STATUSES:
        return PersonStage.EMPLOYEE
    elif status == EmployeeStatus.ARCHIVED:
        # Archived can be either - we default to employee for historical records
        return PersonStage.EMPLOYEE
    else:
        # Unknown status defaults to applicant (safer - can't work without approval)
        return PersonStage.APPLICANT


# ==================== SCOPED REPOSITORY LAYER ====================
# Change Set 1: Global Applicant/Employee Separation
# All UI-serving queries MUST go through this repository to enforce scope boundaries

def is_applicant_status(status: str) -> bool:
    """Check if status belongs to applicant domain"""
    return status in APPLICANT_STATUSES

def is_employee_status(status: str) -> bool:
    """Check if status belongs to employee domain"""
    return status in EMPLOYEE_STATUSES

def applicant_scope_filter(existing_filter: dict = None) -> dict:
    """Return MongoDB filter for applicant-only queries"""
    base = {"status": {"$in": APPLICANT_STATUSES}}
    if existing_filter:
        return {**existing_filter, **base}
    return base

def employee_scope_filter(existing_filter: dict = None) -> dict:
    """Return MongoDB filter for employee-only queries"""
    base = {"status": {"$in": EMPLOYEE_STATUSES}}
    if existing_filter:
        return {**existing_filter, **base}
    return base


class ScopeValidationError(HTTPException):
    """Raised when accessing a record outside its valid scope"""
    def __init__(self, detail: str = "Record not found in this scope"):
        super().__init__(status_code=404, detail=detail)


# ==================== INTERNAL HELPERS ====================
# Internal functions for use by endpoints - not exposed as API

async def get_compliance_requirements_for_employee(employee_id: str, role: str = '') -> List[dict]:
    """
    Internal helper to get compliance requirements for an employee.
    This replicates the logic from the API endpoint but without auth requirements.
    Used by: readiness calculation, dashboard summary, etc.
    """
    # Get mandatory items for this employee's role
    mandatory_items = get_mandatory_items_for_role(role)
    
    # Get all ACTIVE documents for this employee (exclude superseded/inactive)
    all_docs = await db.employee_documents.find({
        "employee_id": employee_id,
        "$or": [
            {"active": {"$exists": False}},
            {"active": True}
        ],
        "status": {"$ne": "superseded"}
    }, {"_id": 0}).to_list(500)
    
    # Get all forms for this employee
    all_forms = await db.generated_forms.find({"employee_id": employee_id}, {"_id": 0}).to_list(500)
    
    # Get training records
    raw_training = await db.training_records.find({
        "employee_id": employee_id,
        "record_status": {"$nin": ["superseded", "deleted"]}
    }, {"_id": 0}).to_list(100)
    
    requirements = []
    
    for item in mandatory_items:
        req_id = item['id']
        req_type = item.get('type', 'document')
        
        # Skip archived requirements
        if item.get('archived', False):
            continue
        
        # Build requirement result
        result = {
            "id": req_id,
            "name": item.get('name', req_id),
            "type": req_type,
            "category": item.get('category', ''),
            "priority": item.get('priority', 'secondary'),
            "status": "not_started",
            "has_evidence": False,
            "verified": False,
            "document_count": 0,
            "expiry_date": None
        }
        
        # Check documents for this requirement
        def matches_requirement(document: dict, requirement_id: str) -> bool:
            doc_req_id = (document.get('requirement_id') or '').lower()
            doc_type = (document.get('document_type') or '').lower()
            if requirement_id == 'right_to_work':
                if doc_req_id in ['right_to_work', 'right_to_work_documents', 'right_to_work_check', 'right_to_work_evidence', 'identity_rtw']:
                    return True
                return any(keyword in doc_type for keyword in ['visa', 'brp', 'share', 'work', 'rtw'])
            if requirement_id == 'identity_documents' and doc_req_id == 'identity_rtw':
                return any(keyword in doc_type for keyword in ['passport', 'licence', 'license', 'id'])
            return doc_req_id == requirement_id or doc_type == requirement_id

        matching_docs = [d for d in all_docs if matches_requirement(d, req_id)]
        
        if matching_docs:
            active_count = sum(1 for d in matching_docs if d.get('file_url') or d.get('evidence_files'))
            result["document_count"] = active_count
            
            if active_count > 0:
                result["status"] = "complete"
                result["has_evidence"] = True
                result["verified"] = all(d.get('verified') or d.get('status') == 'approved' for d in matching_docs if d.get('file_url'))
                
                # Check expiry
                for doc in matching_docs:
                    if doc.get('expiry_date'):
                        result["expiry_date"] = doc['expiry_date']
                        break
        
        # Check forms for this requirement
        if req_type == 'form':
            matching_forms = [f for f in all_forms if f.get('form_type') == req_id]
            if matching_forms:
                form = matching_forms[0]
                if form.get('status') in ['submitted', 'signed_off', 'completed']:
                    result["status"] = "complete"
                    result["has_evidence"] = bool(form.get('pdf_url'))
                    result["verified"] = form.get('status') == 'signed_off'
        
        requirements.append(result)
    
    return requirements


class DocumentStatus(str, Enum):
    NOT_STARTED = "not_started"
    REQUESTED = "requested"
    UPLOADED = "uploaded"
    UNDER_REVIEW = "under_review"
    APPROVED = "approved"
    REJECTED = "rejected"
    EXPIRED = "expired"
    NOT_APPLICABLE = "not_applicable"
    SUPERSEDED = "superseded"
    UPLOADED_IN_ERROR = "uploaded_in_error"
    VERIFIED = "verified"
    AWAITING_VERIFICATION = "awaiting_verification"
    MISFILED = "misfiled"


# =============================================================================
# GLOBAL STATUS EXCLUSION CONSTANTS - SINGLE SOURCE OF TRUTH FOR DATA SYNC
# =============================================================================
# These constants ensure Admin and Worker views are ALWAYS in sync.
# ANY change here automatically propagates to ALL queries.
# =============================================================================

# Document statuses that should be HIDDEN from active views (both Admin and Worker)
# A document with any of these statuses is considered "inactive" or "historical"
EXCLUDED_DOC_STATUSES = [
    "deleted",           # Permanently removed
    "superseded",        # Replaced by newer version
    "uploaded_in_error", # Marked as mistake by admin
    "rejected",          # Rejected and needs replacement
    "moved",             # Moved to different category
    "archived",          # Archived for historical purposes
    "misfiled",          # Filed under wrong category
    "replaced",          # Legacy: replaced by newer
    "removed",           # Legacy: soft-deleted
]

# Training record statuses that should be HIDDEN from active views
EXCLUDED_TRAINING_STATUSES = [
    "superseded",        # Replaced by newer training record
    "deleted",           # Permanently removed
]

PROOF_ROLE_VALUES = {"proof", "verification_proof", "check_proof"}
PROOF_SOURCE_TYPES = {"verification_proof", "check_proof"}


def is_proof_role_document(doc: dict, current_proof_doc_ids: Optional[set] = None) -> bool:
    role = (doc.get("document_role") or "").lower().strip()
    source_type = (doc.get("source_type") or "").lower().strip()
    doc_id = doc.get("id")
    if role in PROOF_ROLE_VALUES:
        return True
    if source_type in PROOF_SOURCE_TYPES:
        return True
    if current_proof_doc_ids and doc_id and doc_id in current_proof_doc_ids:
        return True
    return False


