def get_training_blocker_config(requirement_id: str) -> dict:
    """Get blocker configuration for a training requirement."""
    req_lower = requirement_id.lower().replace(' ', '_').replace('-', '_')
    return TRAINING_BLOCKER_CONFIG.get(req_lower, {
        "blocker_for_work": False,
        "evidence_required": True,
        "reason_code": f"{req_lower}_training_missing",
        "reason_message": f"{requirement_id} training required"
    })


# ============================================================================
# CANONICAL TRAINING EVALUATOR (Single Source of Truth)
# ============================================================================
# This function evaluates ALL training status for an employee.
# It must be used by:
# - GET /employees/{id}/training
# - GET /employees/{id}/readiness (for training blockers)
# - GET /dashboard (for training due/overdue counts)
# - Audit exports
# ============================================================================

async def evaluate_employee_training_status(employee_id: str, role: str = '') -> dict:
    """
    CANONICAL TRAINING EVALUATOR - Single Source of Truth.
    
    Evaluates all required training for an employee and returns:
    - overall: 'current' | 'due_soon' | 'overdue' | 'missing'
    - blockerCount: Number of work-blocking training items that are not passed
    - warningCount: Number of non-blocking training items that need attention
    - items: Array of detailed training item status
    
    This function is THE ONLY way to evaluate training status.
    All endpoints MUST call this function.
    """
    # Get required training for this employee
    required_training = await get_required_training_for_employee(employee_id, role)
    
    # Get all training records for this employee
    training_records = await db.training_records.find({
        "employee_id": employee_id,
        "record_status": {"$nin": ["superseded", "deleted"]}
    }, {"_id": 0}).to_list(100)
    
    # Build lookup by requirement_id, training_id, and normalized training_name
    records_by_req = {}
    for record in training_records:
        req_id = record.get('requirement_id') or record.get('training_name', '').lower().replace(' ', '_')
        if req_id not in records_by_req:
            records_by_req[req_id] = record
        # Also index by training_id (set by extractor mapping) for robust matching
        t_id = record.get('training_id')
        if t_id and t_id not in records_by_req:
            records_by_req[t_id] = record
    
    items = []
    blocker_count = 0
    warning_count = 0
    has_missing = False
    has_expired = False
    has_due_soon = False
    
    for req in required_training:
        req_id = req.get('id') or req.get('training_name', '').lower().replace(' ', '_')
        training_name = req.get('training_name') or req.get('name', req_id)
        
        # Get blocker config
        blocker_config = get_training_blocker_config(req_id)
        is_blocker = blocker_config.get('blocker_for_work', False)
        evidence_required = blocker_config.get('evidence_required', True)
        
        # Find matching record
        record = records_by_req.get(req_id)
        
        # Also check by training_name variations
        if not record:
            for alt_id in [training_name.lower().replace(' ', '_'), req_id.replace('_', '-')]:
                if alt_id in records_by_req:
                    record = records_by_req[alt_id]
                    break
        
        if not record:
            # MISSING
            items.append({
                "code": req_id,
                "title": training_name,
                "status": "missing",
                "blocker": is_blocker,
                "detail": f"{training_name} training not recorded",
                "expires_at": None,
                "verified": False,
                "evidence_required": evidence_required
            })
            has_missing = True
            if is_blocker:
                blocker_count += 1
            else:
                warning_count += 1
            continue
        
        # Compute status
        computed = compute_training_record_status(record)
        computed_status = computed.get('computed_status')
        verified = record.get('verified', False)
        expiry_date = record.get('expiry_date')
        
        # Determine final status
        if computed_status == 'not_started':
            status = 'missing'
            has_missing = True
            detail = f"{training_name} training not completed"
            if is_blocker:
                blocker_count += 1
            else:
                warning_count += 1
        elif computed_status == 'expired':
            status = 'expired'
            has_expired = True
            detail = f"{training_name} expired on {expiry_date}"
            if is_blocker:
                blocker_count += 1
            else:
                warning_count += 1
        elif computed_status == 'needs_renewal':
            status = 'due_soon'
            has_due_soon = True
            days_left = computed.get('days_until_expiry', 0)
            detail = f"{training_name} expires in {days_left} days"
            # Due soon is a warning, not a blocker
            warning_count += 1
        elif not verified and evidence_required:
            status = 'awaiting_review'
            detail = f"{training_name} submitted but awaiting verification"
            # Unverified training does NOT pass if evidence is required
            if is_blocker:
                blocker_count += 1
            else:
                warning_count += 1
        else:
            status = 'verified' if verified else 'completed'
            detail = f"{training_name} valid" + (f" until {expiry_date}" if expiry_date else "")
        
        items.append({
            "code": req_id,
            "title": training_name,
            "status": status,
            "blocker": is_blocker,
            "detail": detail,
            "expires_at": expiry_date,
            "verified": verified,
            "evidence_required": evidence_required,
            "completion_date": record.get('completion_date'),
            "days_until_expiry": computed.get('days_until_expiry'),
            "certificate_url": record.get('certificate_url')
        })
    
    # Determine overall status
    if has_expired:
        overall = 'overdue'
    elif has_missing:
        overall = 'missing'
    elif has_due_soon:
        overall = 'due_soon'
    else:
        overall = 'current'
    
    return {
        "overall": overall,
        "blockerCount": blocker_count,
        "warningCount": warning_count,
        "items": items,
        "evaluatedAt": datetime.now(timezone.utc).isoformat()
    }


async def get_training_audit_export(employee_id: str, role: str = '') -> dict:
    """
    Generate full training audit export for compliance reports.
    
    CONSUMES canonical training evaluation - does NOT recalculate.
    
    Returns structured data suitable for:
    - CQC inspection evidence
    - PDF compliance reports
    - JSON audit exports
    - Internal audit review
    
    Each item includes verification metadata for evidence traceability.
    """
    # Get canonical training evaluation (single source of truth)
    training_eval = await evaluate_employee_training_status(employee_id, role)
    
    # Get raw training records for additional audit metadata
    training_records = await db.training_records.find({
        "employee_id": employee_id,
        "record_status": {"$nin": ["superseded", "deleted"]}
    }, {"_id": 0}).to_list(100)
    
    records_by_req = {}
    for r in training_records:
        req_id = r.get('requirement_id') or r.get('training_name', '').lower().replace(' ', '_')
        records_by_req[req_id] = r
    
    # Build audit export items with full verification metadata
    audit_items = []
    for item in training_eval.get('items', []):
        code = item.get('code', '')
        record = records_by_req.get(code, {})
        
        # Get verifier information
        verifier_name = None
        verified_at = None
        if record.get('verified') or record.get('verification_status') == 'verified':
            verified_at = record.get('verified_at') or record.get('verification_date')
            verifier_id = record.get('verified_by')
            if verifier_id:
                verifier = await db.users.find_one({"id": verifier_id}, {"_id": 0, "name": 1, "email": 1})
                if verifier:
                    verifier_name = verifier.get('name') or verifier.get('email')
        
        audit_item = {
            "code": code,
            "title": item.get('title', code),
            "required_for_role": True,  # All items from evaluator are required
            "blocker_for_work": item.get('blocker', False),
            "status": item.get('status'),
            "detail": item.get('detail', ''),
            "completed_at": item.get('completion_date') or record.get('completed_at'),
            "expires_at": item.get('expires_at'),
            "days_until_expiry": item.get('days_until_expiry'),
            "verification_status": record.get('verification_status', 'awaiting_review' if record else None),
            "verified_by": verifier_name,
            "verified_at": verified_at,
            "certificate_document_id": record.get('certificate_document_id') or record.get('evidence_id'),
            "provider_name": record.get('provider_name'),
            "notes": record.get('notes')
        }
        audit_items.append(audit_item)
    
    # Map overall status to audit-friendly labels
    overall = training_eval.get('overall', 'missing')
    overall_label_map = {
        'current': 'All Training Current',
        'due_soon': 'Training Renewal Due Soon',
        'overdue': 'Training Expired/Overdue',
        'missing': 'Required Training Missing'
    }
    
    return {
        "overall_status": overall,
        "overall_status_label": overall_label_map.get(overall, overall),
        "blocker_count": training_eval.get('blockerCount', 0),
        "warning_count": training_eval.get('warningCount', 0),
        "is_work_ready_from_training": training_eval.get('blockerCount', 0) == 0,
        "blocking_reasons": [
            item.get('detail') for item in audit_items
            if item.get('blocker_for_work') and item.get('status') in ['missing', 'expired', 'awaiting_review']
        ],
        "warning_reasons": [
            item.get('detail') for item in audit_items
            if not item.get('blocker_for_work') and item.get('status') in ['missing', 'expired', 'due_soon', 'awaiting_review']
        ],
        "items": audit_items,
        "total_required": len(audit_items),
        "total_compliant": len([i for i in audit_items if i.get('status') in ['verified', 'completed']]),
        "evaluated_at": training_eval.get('evaluatedAt')
    }


async def get_or_create_training_record(
    employee_id: str, 
    requirement_id: str, 
    training_name: str,
    create_if_missing: bool = True
) -> Optional[dict]:
    """
    Get the SINGLE ACTIVE training record for an employee+requirement.
    Creates one if missing and create_if_missing=True.
    Enforces single source of truth.
    """
    # Find active record (NOT superseded or deleted)
    record = await db.training_records.find_one({
        "employee_id": employee_id,
        "requirement_id": requirement_id,
        "record_status": {"$nin": ["superseded", "deleted"]}
    }, {"_id": 0})
    
    if record:
        return record
    
    # Try by training name if not found by requirement_id
    record = await db.training_records.find_one({
        "employee_id": employee_id,
        "training_name": {"$regex": f"^{re.escape(training_name)}$", "$options": "i"},
        "record_status": {"$nin": ["superseded", "deleted"]}
    }, {"_id": 0})
    
    if record:
        # Update requirement_id if missing
        if not record.get('requirement_id'):
            await db.training_records.update_one(
                {"id": record['id']},
                {"$set": {"requirement_id": requirement_id}}
            )
            record['requirement_id'] = requirement_id
        return record
    
    if not create_if_missing:
        return None
    
    # Create new record
    # HARDENING: Do not store derived status - will be computed at runtime
    now = datetime.now(timezone.utc).isoformat()
    new_record = {
        "id": str(uuid.uuid4()),
        "employee_id": employee_id,
        "requirement_id": requirement_id,
        "training_name": training_name,
        "mandatory": True,
        # REMOVED: "status": "not_started" - derived from completion_date being None
        "record_status": "active",
        "completion_date": None,
        "expiry_date": None,
        "certificate_url": None,
        "evidence_files": [],
        "verified": False,
        "created_at": now,
        "updated_at": now
    }
    await db.training_records.insert_one(new_record)
    return new_record


async def supersede_training_record(record_id: str, user_id: str, reason: str = None):
    """Mark a training record as superseded (replaced by a newer one)."""
    now = datetime.now(timezone.utc).isoformat()
    
    record = await db.training_records.find_one({"id": record_id}, {"_id": 0})
    if not record:
        return False
    
    await db.training_records.update_one(
        {"id": record_id},
        {"$set": {
            "record_status": "superseded",
            "superseded_at": now,
            "superseded_by": user_id,
            "updated_at": now
        }}
    )
    
    await log_audit_action(user_id, "training_superseded", "training_record", record_id, {
        "training_name": record.get('training_name'),
        "employee_id": record.get('employee_id'),
        "reason": reason or "Replaced with newer record"
    })
    
    return True

