async def generate_employee_code():
    """Generate unique employee code in format EMP-XXXX (canonical generator)."""
    last_emp = await db.employees.find_one(
        {"employee_code": {"$regex": "^EMP-\\d+$"}},
        sort=[("employee_code", -1)]
    )
    if last_emp and last_emp.get("employee_code"):
        try:
            last_num = int(last_emp["employee_code"].split("-")[1])
            new_num = last_num + 1
        except (ValueError, IndexError):
            new_num = 1001
    else:
        new_num = 1001
    return f"EMP-{new_num:04d}"

async def calculate_completion_percentage(employee_id: str) -> int:
    """
    Calculate completion percentage using UNIFIED compliance logic.
    P0 FIX: Now uses get_unified_employee_status() for SINGLE SOURCE OF TRUTH.
    
    MUST return identical values to what profile/dashboard show.
    """
    try:
        # P0 FIX: Use the SINGLE unified function from unified_compliance_engine
        unified_status = await get_unified_employee_status(employee_id, db, user_role="admin", include_details=False)
        if unified_status.get("error"):
            return 0
        return unified_status["progress"]["percentage"]
    except Exception as e:
        logger.warning(f"Failed to get unified status for {employee_id}: {e}")
        # Fallback to old calculation if unified fails
        employee = await db.employees.find_one({"id": employee_id}, {"_id": 0, "role": 1})
        if not employee:
            return 0
        role = employee.get('role', '')
        compliance = await calculate_employee_compliance(employee_id, role)
        return compliance["completion_percentage"]

async def calculate_work_readiness_quick(employee_id: str, role: str) -> dict:
    """
    Quick work readiness calculation for list views.
    HARDENING: Now includes critical expiry check to match full readiness logic.
    """
    work_ready_ids = get_work_ready_items_for_role(role)
    
    # ===== CRITICAL EXPIRY CHECK (HARDENING) =====
    # Check for expired critical documents FIRST - this overrides everything
    # Reuses CRITICAL_EXPIRY_DOCS from calculate_separated_statuses()
    today_str = datetime.now(timezone.utc).strftime('%Y-%m-%d')
    
    # Check documents for critical expiry
    critical_expired_docs = await db.employee_documents.find({
        "employee_id": employee_id,
        "requirement_id": {"$in": list(CRITICAL_EXPIRY_DOCS)},
        "expiry_date": {"$exists": True, "$ne": None, "$lt": today_str},
        "verified": True,  # Only verified docs count for work readiness
        "status": {"$nin": EXCLUDED_DOC_STATUSES}
    }, {"_id": 0, "requirement_id": 1, "expiry_date": 1}).to_list(10)
    
    if critical_expired_docs:
        expired_req = critical_expired_docs[0].get('requirement_id', 'document')
        return {
            "status": "not_ready", 
            "label": f"Critical Doc Expired", 
            "color": "error",
            "reason": f"Expired: {expired_req}"
        }
    
    # Also check training records for critical training expiry
    critical_training_ids = {"safeguarding", "manual_handling", "infection_control"}
    critical_expired_training = []
    
    for train_id in critical_training_ids:
        record = await db.training_records.find_one({
            "employee_id": employee_id,
            "requirement_id": train_id,
            "verified": True,
            "expiry_date": {"$exists": True, "$ne": None}
        }, {"_id": 0, "expiry_date": 1, "requirement_id": 1, "completion_date": 1})
        
        if record and record.get('expiry_date'):
            # Check if expired using canonical logic
            exp_date = record['expiry_date']
            if isinstance(exp_date, str) and exp_date < today_str:
                critical_expired_training.append(record)
    
    if critical_expired_training:
        expired_req = critical_expired_training[0].get('requirement_id', 'training')
        return {
            "status": "not_ready",
            "label": "Training Expired",
            "color": "error", 
            "reason": f"Expired: {expired_req}"
        }
    # ===== END CRITICAL EXPIRY CHECK =====
    
    # Get documents for mandatory items
    docs = await db.employee_documents.find({
        "employee_id": employee_id,
        "requirement_id": {"$in": list(work_ready_ids)},
        "verified": True,
        # Exclude deleted/replaced/archived records
        "status": {"$nin": EXCLUDED_DOC_STATUSES}
    }, {"_id": 0, "requirement_id": 1}).to_list(100)
    
    # Get verified training for mandatory items
    training_ids = {r for r in work_ready_ids if r in ["safeguarding", "manual_handling", "infection_control"]}
    training = await db.training_records.find({
        "employee_id": employee_id,
        "requirement_id": {"$in": list(training_ids)},
        "verified": True,
        # HARDENING: Check for completion_date instead of status field
        "completion_date": {"$exists": True, "$ne": None},
        # HARDENING: Exclude superseded/deleted records
        "record_status": {"$nin": ["superseded", "deleted"]}
    }, {"_id": 0, "requirement_id": 1}).to_list(100)
    
    verified_ids = {d['requirement_id'] for d in docs}
    verified_ids.update({t['requirement_id'] for t in training})
    
    mandatory_complete = len(verified_ids.intersection(work_ready_ids))
    total_mandatory = len(work_ready_ids)
    
    # Calculate missing items for Not Ready reason
    missing_items = work_ready_ids - verified_ids
    
    # Build human-readable reason for missing items
    def get_missing_reason():
        if not missing_items:
            return None
        # Map IDs to readable names
        id_to_name = {
            "dbs_certificate": "DBS",
            "dbs_check": "DBS",
            "right_to_work_documents": "Right to Work",
            "right_to_work_check": "Right to Work",
            "safeguarding": "Safeguarding",
            "manual_handling": "Manual Handling",
            "infection_control": "Infection Control",
            "references": "References",
            "proof_of_identity": "ID",
            "proof_of_address": "Address"
        }
        names = [id_to_name.get(item, item.replace('_', ' ').title()) for item in list(missing_items)[:2]]
        if len(missing_items) > 2:
            return f"Missing: {', '.join(names)} +{len(missing_items)-2}"
        return f"Missing: {', '.join(names)}"
    
    if mandatory_complete == total_mandatory:
        return {"status": "work_ready", "label": "Ready to Work", "color": "success"}
    elif mandatory_complete >= total_mandatory - 2:
        return {"status": "supervised_start", "label": "Supervised Start Only", "color": "warning", "reason": get_missing_reason()}
    elif mandatory_complete > 0:
        return {"status": "in_progress", "label": "Not Ready", "color": "error", "reason": get_missing_reason()}
    else:
        return {"status": "not_started", "label": "Not Ready", "color": "error", "reason": get_missing_reason()}


async def calculate_work_readiness_3tier_quick(employee_id: str, employee_data: dict, role: str) -> dict:
    """
    Quick 3-tier work readiness for list views. 
    Returns simplified status without full requirements computation.
    
    CRITICAL: Applicants NEVER ready to work.
    """
    from datetime import datetime, timezone
    today = datetime.now(timezone.utc)
    today_str = today.strftime('%Y-%m-%d')
    
    hard_block_reasons = []
    conditional_reasons = []
    
    # 1. CRITICAL: Person stage check - applicants NEVER ready
    person_stage = employee_data.get('person_stage') or get_person_stage(employee_data.get('status', ''))
    if person_stage == 'applicant':
        hard_block_reasons.append({
            "type": "hard_block",
            "code": "applicant_stage",
            "message": "Applicant - not recruited"
        })
    
    # 2. Check recruitment_approved
    if not employee_data.get('recruitment_approved', False):
        hard_block_reasons.append({
            "type": "hard_block",
            "code": "recruitment_not_approved",
            "message": "Recruitment not approved"
        })
    
    # 3. Check hard block documents
    hard_block_reqs = ["right_to_work_documents", "right_to_work_check", "identity_documents", "dbs_certificate", "dbs_check"]
    
    verified_docs = await db.employee_documents.find({
        "employee_id": employee_id,
        "requirement_id": {"$in": hard_block_reqs},
        "verified": True,
        "status": {"$nin": EXCLUDED_DOC_STATUSES}
    }, {"_id": 0, "requirement_id": 1, "expiry_date": 1}).to_list(20)
    
    verified_doc_ids = set()
    for doc in verified_docs:
        req_id = doc.get('requirement_id')
        expiry = doc.get('expiry_date')
        # Check if expired
        if expiry and expiry < today_str:
            hard_block_reasons.append({
                "type": "hard_block",
                "code": f"{req_id}_expired",
                "message": f"{req_id.replace('_', ' ').title()} expired"
            })
        else:
            verified_doc_ids.add(req_id)
    
    # Check missing hard block docs
    for req_id in hard_block_reqs:
        if req_id not in verified_doc_ids:
            # Check if we haven't already flagged it as expired
            if not any(r['code'] == f"{req_id}_expired" for r in hard_block_reasons):
                hard_block_reasons.append({
                    "type": "hard_block",
                    "code": f"{req_id}_missing",
                    "message": f"{req_id.replace('_', ' ').title()} missing"
                })
    
    # 3. Check references (both must be verified)
    ref_docs = await db.employee_documents.find({
        "employee_id": employee_id,
        "requirement_id": {"$in": ["reference_1", "reference_2"]},
        "verified": True,
        "status": {"$nin": EXCLUDED_DOC_STATUSES}
    }, {"_id": 0, "requirement_id": 1}).to_list(10)
    
    ref_ids = {d['requirement_id'] for d in ref_docs}
    if "reference_1" not in ref_ids or "reference_2" not in ref_ids:
        missing = []
        if "reference_1" not in ref_ids:
            missing.append("Reference 1")
        if "reference_2" not in ref_ids:
            missing.append("Reference 2")
        hard_block_reasons.append({
            "type": "hard_block",
            "code": "references_incomplete",
            "message": f"{', '.join(missing)} missing"
        })
    
    # 4. Check overdue recurring compliance (conditional)
    recurring_items = await db.recurring_compliance.find({
        "employee_id": employee_id,
        "is_active": True,
        "next_due_date": {"$lt": today_str}
    }, {"_id": 0, "item_type": 1, "item_name": 1, "next_due_date": 1}).to_list(20)
    
    for item in recurring_items:
        item_type = item.get('item_type')
        if item_type in ['supervision', 'competency_assessment', 'spot_check', 'training_refresh', 'report_followup']:
            conditional_reasons.append({
                "type": "conditional",
                "code": f"{item_type}_overdue",
                "message": f"{item.get('item_name', item_type.replace('_', ' ').title())} overdue"
            })
    
    # Determine status
    if hard_block_reasons:
        return {
            "status": "NOT_READY",
            "label": "Not Ready",
            "color": "error",
            "reasons": hard_block_reasons[:3]  # Limit for list view
        }
    elif conditional_reasons:
        return {
            "status": "READY_WITH_CONDITIONS",
            "label": "Ready*",
            "color": "warning",
            "reasons": conditional_reasons[:2]  # Limit for list view
        }
    else:
        return {
            "status": "READY_TO_WORK",
            "label": "Ready",
            "color": "success",
            "reasons": []
        }


@api_router.post("/employees", response_model=EmployeeResponse)
async def create_employee(employee: EmployeeCreate, user: dict = Depends(require_manager_or_admin)):
    """
    Create a new employee/applicant record.
    
    Employee Code Assignment Rule:
    - Applicant-stage statuses (new, screening, interview, compliance_review): 
      NO employee_code assigned yet - they use applicant_reference instead
    - Employee-stage statuses (onboarding, active, inactive):
      Employee_code is assigned on recruitment approval or first employee-stage entry
    """
    employee_id = str(uuid.uuid4())
    now = datetime.now(timezone.utc).isoformat()
    
    # Determine initial stage based on status
    initial_status = employee.status or EmployeeStatus.NEW
    person_stage = get_person_stage(initial_status)
    
    employee_doc = {
        "id": employee_id,
        **employee.model_dump(),
        "application_source": "internal",
        "completion_percentage": 0,
        "created_at": now,
        "updated_at": now
    }
    
    # Only assign employee_code if starting at employee stage (rare - usually admin manually adding)
    # Otherwise, use applicant_reference for applicants
    if person_stage == PersonStage.EMPLOYEE:
        employee_code = await generate_employee_code()
        employee_doc["employee_code"] = employee_code
        log_details = {"employee_code": employee_code}
    else:
        # Applicant stage - generate applicant reference instead
        applicant_ref = f"APP-{uuid.uuid4().hex[:8].upper()}"
        employee_doc["applicant_reference"] = applicant_ref
        employee_doc["employee_code"] = None  # Explicitly null until approved
        log_details = {"applicant_reference": applicant_ref}
    
    await db.employees.insert_one(employee_doc)
    
    # Log action
    await log_audit_action(user['user_id'], "create_employee", "employee", employee_id, log_details)
    
    return EmployeeResponse(**employee_doc)

@api_router.get("/employees", response_model=List[EmployeeResponse])
async def get_employees(
    onboarding_status: Optional[str] = None,
    status: Optional[str] = None,
    role: Optional[str] = None,
    search: Optional[str] = None,
    include_archived: bool = False,
    missing_dbs: bool = False,
    missing_rtw: bool = False,
    missing_references: bool = False,
    unsigned_policies: bool = False,
    expiring_soon: bool = False,
    stage: Optional[str] = None,  # NEW: filter by person_stage (applicant/employee)
    user: dict = Depends(get_current_user)
):
    """
    Get all employees/applicants.
    
    Stage Filter:
    - stage=applicant: Returns only applicant-stage people (new, screening, interview, compliance_review)
    - stage=employee: Returns only employee-stage people (onboarding, active, inactive)
    - stage=None: Returns all (default behavior for backward compatibility)
    """
    start_time = time_module.time()
    source = get_read_source("employees")
    fallback_used = False
    employees = []
    
    # Determine status filter for Supabase query
    status_filter = None
    if stage == PersonStage.APPLICANT:
        status_filter = APPLICANT_STATUSES
    elif stage == PersonStage.EMPLOYEE:
        status_filter = EMPLOYEE_STATUSES
    elif status:
        status_filter = [status]
    elif not include_archived:
        status_filter = None  # Will exclude archived in query
    
    # Try Supabase if enabled
    if source == ReadSource.SUPABASE:
        try:
            employees = await read_employees_pg(
                status_filter=status_filter,
                search=search,
                limit=1000
            )
            # Convert date fields to strings for compatibility
            for emp in employees:
                if emp.get('start_date'):
                    emp['start_date'] = str(emp['start_date'])
                if emp.get('created_at'):
                    emp['created_at'] = emp['created_at'].isoformat() if hasattr(emp['created_at'], 'isoformat') else str(emp['created_at'])
                if emp.get('updated_at'):
                    emp['updated_at'] = emp['updated_at'].isoformat() if hasattr(emp['updated_at'], 'isoformat') else str(emp['updated_at'])
        except Exception as e:
            logger.warning(f"Supabase read failed, falling back to Mongo: {e}")
            source = ReadSource.MONGO
            fallback_used = True
    
    # Use MongoDB (default or fallback)
    if source == ReadSource.MONGO or not employees:
        query = {}
        
        # Stage filter - NEW for applicant vs employee separation
        if stage == PersonStage.APPLICANT:
            query["status"] = {"$in": APPLICANT_STATUSES}
        elif stage == PersonStage.EMPLOYEE:
            query["status"] = {"$in": EMPLOYEE_STATUSES}
        elif status:
            query["status"] = status
        elif not include_archived:
            # By default, exclude archived employees unless specifically requested
            query["status"] = {"$ne": EmployeeStatus.ARCHIVED}
        
        # Onboarding status filter
        if onboarding_status:
            query["onboarding_status"] = onboarding_status
        
        if role:
            query["role"] = role
        if search:
            query["$or"] = [
                {"first_name": {"$regex": search, "$options": "i"}},
                {"last_name": {"$regex": search, "$options": "i"}},
                {"email": {"$regex": search, "$options": "i"}},
                {"employee_code": {"$regex": search, "$options": "i"}},
                {"applicant_reference": {"$regex": search, "$options": "i"}}  # Also search applicant refs
            ]
        
        employees = await db.employees.find(query, {"_id": 0}).to_list(1000)
        if fallback_used:
            source = ReadSource.MONGO
    
    # Calculate completion percentages, work readiness, expiry alerts, and person_stage
    for emp in employees:
        emp['completion_percentage'] = await calculate_completion_percentage(emp['id'])
        emp['work_readiness'] = await calculate_work_readiness_quick(emp['id'], emp.get('role', ''))
        emp['work_readiness_3tier'] = await calculate_work_readiness_3tier_quick(emp['id'], emp, emp.get('role', ''))
        emp['expiry_alerts'] = await calculate_expiry_alerts_quick(emp['id'])
        # Derive person_stage from status (SINGLE SOURCE OF TRUTH)
        emp['person_stage'] = get_person_stage(emp.get('status', EmployeeStatus.NEW))
        # Add stage identity fields
        enrich_person_with_stage_identity(emp)
    
    # Log source served
    latency_ms = (time_module.time() - start_time) * 1000
    log_source_served("GET /employees", "employees", source, len(employees), fallback_used=fallback_used, latency_ms=latency_ms)
    
    return [EmployeeResponse(**emp) for emp in employees]


@api_router.get("/employees/unified-progress-summary")
async def get_employees_unified_progress_summary(
    employee_ids: Optional[str] = None,
    include_archived: bool = False,
    user: dict = Depends(get_current_user)
):
    """
    Bulk canonical readiness summary for dashboard/list surfaces.

    Uses get_unified_employee_status() for the same readiness authority as
    /employees/{employee_id}/unified-progress, but returns only summary fields.
    """
    query = {}
    if employee_ids:
        ids = [emp_id.strip() for emp_id in employee_ids.split(",") if emp_id.strip()]
        query["id"] = {"$in": ids}
    elif not include_archived:
        query["status"] = {"$ne": EmployeeStatus.ARCHIVED}

    employees = await db.employees.find(query, {"_id": 0, "id": 1}).to_list(1000)

    async def build_summary(employee_id: str) -> dict:
        unified_status = await get_unified_employee_status(
            employee_id,
            db,
            user_role="admin",
            include_details=False
        )

        if unified_status.get("error"):
            return {
                "employee_id": employee_id,
                "overall_percentage": 0,
                "is_work_ready": False,
                "can_promote": False,
                "blockers": [unified_status["error"]],
                "blocker_count": 1,
            }

        blockers = [blocker.get("reason") for blocker in unified_status.get("blockers", []) if blocker.get("reason")]
        return {
            "employee_id": employee_id,
            "overall_percentage": unified_status.get("progress", {}).get("percentage", 0),
            "is_work_ready": unified_status.get("is_work_ready", False),
            "can_promote": unified_status.get("can_promote", False),
            "blockers": blockers,
            "blocker_count": len(blockers),
        }

    return await asyncio.gather(*(build_summary(emp["id"]) for emp in employees if emp.get("id")))


