@api_router.delete("/employees/{employee_id}/purge")
async def purge_employee_completely(
    employee_id: str, 
    user: dict = Depends(require_admin)
):
    """
    GDPR-compliant complete removal of an employee and ALL related data.
    
    This permanently deletes:
    - Employee record
    - All documents
    - All form submissions
    - Training records
    - Induction items
    - Reference requests and responses
    - Agreement acknowledgements
    - Notifications
    - Generated contracts
    - Spot checks
    - Audit logs (optional - for GDPR right to erasure)
    
    USE WITH CAUTION - This cannot be undone!
    """
    # Verify employee exists
    employee = await db.employees.find_one({"id": employee_id}, {"_id": 0})
    if not employee:
        raise HTTPException(status_code=404, detail="Employee not found")
    
    employee_name = f"{employee.get('first_name', '')} {employee.get('last_name', '')}".strip()
    
    deletion_results = {
        "employee_id": employee_id,
        "employee_name": employee_name,
        "deleted_at": datetime.now(timezone.utc).isoformat(),
        "deleted_by": user.get("name", user["user_id"]),
        "records_deleted": {}
    }
    
    # Delete all related records
    collections_to_clean = [
        ("employee_documents", "employee_id"),
        ("form_submissions", "employee_id"),
        ("employee_training", "employee_id"),
        ("induction_items", "employee_id"),
        ("reference_requests", "employee_id"),
        ("reference_responses", "employee_id"),
        ("agreement_acknowledgements", "employee_id"),
        ("worker_notifications", "employee_id"),
        ("generated_contracts", "employee_id"),
        ("spot_checks", "employee_id"),
    ]
    
    for collection_name, id_field in collections_to_clean:
        try:
            collection = db[collection_name]
            result = await collection.delete_many({id_field: employee_id})
            deletion_results["records_deleted"][collection_name] = result.deleted_count
        except Exception as e:
            deletion_results["records_deleted"][collection_name] = f"Error: {str(e)}"
    
    # Delete the employee record itself
    result = await db.employees.delete_one({"id": employee_id})
    deletion_results["records_deleted"]["employees"] = result.deleted_count
    
    # Also check users collection (if employee has a user account)
    if employee.get("email"):
        user_result = await db.users.delete_many({"email": employee.get("email")})
        deletion_results["records_deleted"]["users"] = user_result.deleted_count
    
    # Log the purge action (this log entry will remain for compliance)
    await log_audit_action(
        user['user_id'], 
        "purge_employee_gdpr", 
        "employee", 
        employee_id, 
        {
            "employee_name": employee_name,
            "reason": "Complete data removal (GDPR)",
            "records_purged": deletion_results["records_deleted"]
        }
    )
    
    return {
        "success": True,
        "message": f"Employee '{employee_name}' and all related data permanently deleted",
        "details": deletion_results
    }

@api_router.post("/employees/{employee_id}/archive")
async def archive_employee(employee_id: str, user: dict = Depends(require_manager_or_admin)):
    """Archive an employee - soft delete that retains all data"""
    employee = await db.employees.find_one({"id": employee_id}, {"_id": 0})
    if not employee:
        raise HTTPException(status_code=404, detail="Employee not found")
    
    if employee.get("status") == EmployeeStatus.ARCHIVED:
        raise HTTPException(status_code=400, detail="Employee is already archived")
    
    previous_status = employee.get("status")
    update_data = {
        "status": EmployeeStatus.ARCHIVED,
        "archived_at": datetime.now(timezone.utc).isoformat(),
        "archived_by": user['user_id'],
        "previous_status": previous_status,
        "updated_at": datetime.now(timezone.utc).isoformat()
    }
    
    await db.employees.update_one({"id": employee_id}, {"$set": update_data})
    
    await log_audit_action(
        user['user_id'], 
        "archive_employee", 
        "employee", 
        employee_id, 
        {
            "employee_name": f"{employee.get('first_name')} {employee.get('last_name')}",
            "employee_code": employee.get('employee_code'),
            "previous_status": previous_status,
            "reason": "Employee archived"
        }
    )
    
    return {"message": "Employee archived successfully", "employee_id": employee_id}

@api_router.post("/employees/{employee_id}/restore")
async def restore_employee(employee_id: str, user: dict = Depends(require_manager_or_admin)):
    """Restore an archived employee to their previous status"""
    employee = await db.employees.find_one({"id": employee_id}, {"_id": 0})
    if not employee:
        raise HTTPException(status_code=404, detail="Employee not found")
    
    if employee.get("status") != EmployeeStatus.ARCHIVED:
        raise HTTPException(status_code=400, detail="Employee is not archived")
    
    restore_status = employee.get("previous_status", EmployeeStatus.INACTIVE)
    update_data = {
        "status": restore_status,
        "archived_at": None,
        "archived_by": None,
        "previous_status": None,
        "updated_at": datetime.now(timezone.utc).isoformat()
    }
    
    await db.employees.update_one({"id": employee_id}, {"$set": update_data})
    
    await log_audit_action(
        user['user_id'], 
        "restore_employee", 
        "employee", 
        employee_id, 
        {
            "employee_name": f"{employee.get('first_name')} {employee.get('last_name')}",
            "restored_to_status": restore_status
        }
    )
    
    return {"message": "Employee restored successfully", "employee_id": employee_id, "status": restore_status}


# ==================== UNIVERSAL EDIT ENDPOINTS WITH REASON LOGGING ====================

class PersonalDetailsUpdate(BaseModel):
    """Personal details update with required reason"""
    first_name: Optional[str] = None
    last_name: Optional[str] = None
    email: Optional[str] = None
    phone: Optional[str] = None
    date_of_birth: Optional[str] = None
    ni_number: Optional[str] = None
    address_line1: Optional[str] = None
    address_line2: Optional[str] = None
    city: Optional[str] = None
    postcode: Optional[str] = None
    emergency_contact_name: Optional[str] = None
    emergency_contact_phone: Optional[str] = None
    emergency_contact_relationship: Optional[str] = None
    edit_reason: str  # Required

@api_router.put("/employees/{employee_id}/personal-details")
async def update_personal_details(
    employee_id: str,
    data: PersonalDetailsUpdate,
    user: dict = Depends(require_manager_or_admin)
):
    """
    Update employee personal details with reason logging.
    
    CQC Audit Trail: Logs who changed what, when, old value, new value, and reason.
    """
    employee = await db.employees.find_one({"id": employee_id}, {"_id": 0})
    if not employee:
        raise HTTPException(status_code=404, detail="Employee not found")
    
    # Build update data (excluding edit_reason)
    update_fields = {}
    old_values = {}
    
    for field in ['first_name', 'last_name', 'email', 'phone', 'date_of_birth', 'ni_number',
                  'address_line1', 'address_line2', 'city', 'postcode']:
        value = getattr(data, field)
        if value is not None:
            old_values[field] = employee.get(field)
            update_fields[field] = value
    
    # Handle emergency contact as nested object
    emergency_update = {}
    if data.emergency_contact_name is not None:
        emergency_update['name'] = data.emergency_contact_name
    if data.emergency_contact_phone is not None:
        emergency_update['phone'] = data.emergency_contact_phone
    if data.emergency_contact_relationship is not None:
        emergency_update['relationship'] = data.emergency_contact_relationship
    
    if emergency_update:
        old_values['emergency_contact'] = employee.get('emergency_contact', {})
        update_fields['emergency_contact'] = {
            **employee.get('emergency_contact', {}),
            **emergency_update
        }
    
    if not update_fields:
        return {"message": "No fields to update"}
    
    update_fields['updated_at'] = datetime.now(timezone.utc).isoformat()
    
    # Perform update
    await db.employees.update_one({"id": employee_id}, {"$set": update_fields})
    
    # Log audit with reason
    await log_audit_action(
        user['user_id'],
        "edit_personal_details",
        "employee",
        employee_id,
        {
            "old_values": old_values,
            "new_values": {k: v for k, v in update_fields.items() if k != 'updated_at'},
            "reason": data.edit_reason,
            "employee_name": f"{employee.get('first_name')} {employee.get('last_name')}"
        }
    )
    
    return {
        "success": True,
        "message": "Personal details updated",
        "fields_updated": list(update_fields.keys()),
        "edit_logged": True
    }


