class ReferenceUpdate(BaseModel):
    """Reference update with required reason"""
    referee_name: Optional[str] = None
    referee_email: Optional[str] = None
    referee_phone: Optional[str] = None
    referee_organisation: Optional[str] = None
    referee_position: Optional[str] = None
    referee_relationship: Optional[str] = None
    referee_type: Optional[str] = None  # professional, character, personal
    period_of_supervision: Optional[str] = None
    is_direct_supervisor: Optional[bool] = None
    can_contact_before_offer: Optional[bool] = None
    edit_reason: str  # Required


async def _monitor_legacy_reference_write_usage(
    route_path: str,
    user: Optional[dict],
    employee_id: Optional[str] = None,
    details: Optional[dict] = None,
) -> None:
    """
    Monitor-first helper for legacy reference write handlers.
    Logs usage and emits audit telemetry without blocking live behavior.
    """
    payload = {
        "route_path": route_path,
        "employee_id": employee_id,
        "monitor_mode": True,
    }
    if details:
        payload.update(details)

    logger.warning(f"LEGACY_REFERENCE_WRITE_USED: {payload}")

    try:
        actor_id = (user or {}).get("user_id") or "system"
        await log_audit_action(
            actor_id,
            "legacy_reference_write_used",
            "reference",
            employee_id or "unknown",
            payload,
        )
    except Exception as e:
        logger.warning(f"Failed to audit legacy reference write usage: {e}")

@api_router.put("/employees/{employee_id}/references/{reference_id}")
async def update_reference(
    employee_id: str,
    reference_id: str,
    data: ReferenceUpdate,
    user: dict = Depends(require_manager_or_admin)
):
    """
    Update a reference with reason logging.
    
    Includes NHS-required fields:
    - Referee type (Professional/Character/Personal)
    - Period of supervision
    - Direct supervisor flag
    - Can contact before offer flag
    """
    await _monitor_legacy_reference_write_usage(
        route_path="/employees/{employee_id}/references/{reference_id}",
        user=user,
        employee_id=employee_id,
        details={"reference_id": reference_id},
    )

    employee = await db.employees.find_one({"id": employee_id}, {"_id": 0})
    if not employee:
        raise HTTPException(status_code=404, detail="Employee not found")

    refs_doc = await db.references.find_one({"employee_id": employee_id}, {"_id": 0})
    ref_key = f"ref{reference_id}"
    ref_doc = ((refs_doc or {}).get(ref_key) or {})
    declared = ref_doc.get("declared") or {}

    old_values = {
        "referee_name": declared.get("name") or employee.get(f"reference_{reference_id}_name"),
        "referee_email": declared.get("email") or employee.get(f"reference_{reference_id}_email"),
        "referee_phone": declared.get("phone") or employee.get(f"reference_{reference_id}_phone"),
        "referee_organisation": declared.get("organisation") or employee.get(f"reference_{reference_id}_company"),
        "referee_position": declared.get("job_title") or declared.get("position") or employee.get(f"reference_{reference_id}_job_title"),
        "referee_relationship": declared.get("relationship") or employee.get(f"reference_{reference_id}_relationship"),
        "referee_type": declared.get("referee_type"),
        "period_of_supervision": declared.get("period_of_supervision"),
        "is_direct_supervisor": declared.get("is_direct_supervisor"),
        "can_contact_before_offer": declared.get("can_contact_before_offer")
    }

    now = datetime.now(timezone.utc).isoformat()
    declared_payload = {
        "name": data.referee_name,
        "email": data.referee_email,
        "phone": data.referee_phone,
        "organisation": data.referee_organisation,
        "job_title": data.referee_position,
        "relationship": data.referee_relationship,
        "referee_type": data.referee_type,
        "period_of_supervision": data.period_of_supervision,
        "is_direct_supervisor": data.is_direct_supervisor,
        "can_contact_before_offer": data.can_contact_before_offer,
        "updated_at": now,
        "updated_by": user["user_id"],
    }

    await db.references.update_one(
        {"employee_id": employee_id},
        {
            "$set": {
                f"{ref_key}.declared": declared_payload,
                "updated_at": now
            },
            "$setOnInsert": {
                "employee_id": employee_id,
                "created_at": now
            }
        },
        upsert=True
    )

    await db.employees.update_one(
        {"id": employee_id},
        {
            "$set": {
                f"reference_{reference_id}_name": data.referee_name,
                f"reference_{reference_id}_email": data.referee_email,
                f"reference_{reference_id}_phone": data.referee_phone,
                f"reference_{reference_id}_company": data.referee_organisation,
                f"reference_{reference_id}_job_title": data.referee_position,
                f"reference_{reference_id}_relationship": data.referee_relationship,
                "updated_at": now
            }
        }
    )

    await log_audit_action(
        user['user_id'],
        "edit_reference",
        "reference",
        reference_id,
        {
            "employee_id": employee_id,
            "old_values": old_values,
            "new_values": {
                "referee_name": data.referee_name,
                "referee_email": data.referee_email,
                "referee_phone": data.referee_phone,
                "referee_organisation": data.referee_organisation,
                "referee_position": data.referee_position,
                "referee_relationship": data.referee_relationship,
                "referee_type": data.referee_type,
                "period_of_supervision": data.period_of_supervision,
                "is_direct_supervisor": data.is_direct_supervisor,
                "can_contact_before_offer": data.can_contact_before_offer,
            },
            "reason": data.edit_reason
        }
    )
    
    return {
        "success": True,
        "message": "Reference updated",
        "edit_logged": True
    }


class DeclarationsUpdate(BaseModel):
    """Declarations update with required reason"""
    declarations: dict  # All declarations fields
    edit_reason: str  # Required

@api_router.put("/employees/{employee_id}/declarations")
async def update_declarations(
    employee_id: str,
    data: DeclarationsUpdate,
    user: dict = Depends(require_manager_or_admin)
):
    """
    Update employee declarations with reason logging.
    
    NHS/CQC Required Declaration Fields:
    - Criminal convictions
    - Health conditions  
    - DBS consent
    - Right to work restrictions
    - Driving licence
    """
    employee = await db.employees.find_one({"id": employee_id}, {"_id": 0})
    if not employee:
        raise HTTPException(status_code=404, detail="Employee not found")
    
    old_declarations = employee.get('declarations', {})
    
    # Update declarations
    update_data = {
        'declarations': data.declarations,
        'updated_at': datetime.now(timezone.utc).isoformat()
    }
    
    await db.employees.update_one({"id": employee_id}, {"$set": update_data})

    # Invalidate employment review sign-off if declarations changed after sign-off
    if employee.get("employment_review_signed_off"):
        await db.employees.update_one({"id": employee_id}, {"$unset": {
            "employment_review_signed_off": "",
            "employment_review_signed_off_by": "",
            "employment_review_signed_off_by_name": "",
            "employment_review_signed_off_at": "",
            "employment_review_notes": "",
        }})
        await log_audit_action(
            user['user_id'],
            "employment_review_sign_off_invalidated",
            "employee",
            employee_id,
            {"reason": "declarations_edited", "triggered_by": "update_declarations"}
        )

    # Log audit with reason
    await log_audit_action(
        user['user_id'],
        "edit_declarations",
        "employee",
        employee_id,
        {
            "old_values": old_declarations,
            "new_values": data.declarations,
            "reason": data.edit_reason,
            "employee_name": f"{employee.get('first_name')} {employee.get('last_name')}"
        }
    )
    
    return {
        "success": True,
        "message": "Declarations updated",
        "edit_logged": True
    }


class SupersedeContractInput(BaseModel):
    """Input for superseding a contract"""
    reason: str  # Required - minimum 20 chars
    send_new_contract: bool = True

@api_router.post("/employees/{employee_id}/contract/supersede")
async def supersede_contract(
    employee_id: str,
    data: SupersedeContractInput,
    user: dict = Depends(require_manager_or_admin)
):
    """
    Supersede an existing contract and optionally send new one to worker.
    
    CQC Compliance:
    - Original contract is marked as "superseded", not deleted
    - Full audit trail maintained
    - Worker must sign new contract themselves
    """
    if len(data.reason.strip()) < 20:
        raise HTTPException(status_code=400, detail="Reason must be at least 20 characters")
    
    employee = await db.employees.find_one({"id": employee_id}, {"_id": 0})
    if not employee:
        raise HTTPException(status_code=404, detail="Employee not found")
    
    # Find current contract
    current_contract = await db.agreement_acknowledgements.find_one({
        "employee_id": employee_id,
        "agreement_type": "contract_acceptance",
        "status": {"$ne": "superseded"}
    }, {"_id": 0})
    
    if not current_contract:
        raise HTTPException(status_code=404, detail="No active contract found to supersede")
    
    now = datetime.now(timezone.utc)
    
    # Mark current contract as superseded
    await db.agreement_acknowledgements.update_one(
        {"id": current_contract["id"]},
        {
            "$set": {
                "status": "superseded",
                "superseded_at": now.isoformat(),
                "superseded_by": user["user_id"],
                "superseded_reason": data.reason
            }
        }
    )
    
    # Log audit
    await log_audit_action(
        user['user_id'],
        "supersede_contract",
        "agreement",
        current_contract["id"],
        {
            "employee_id": employee_id,
            "employee_name": f"{employee.get('first_name')} {employee.get('last_name')}",
            "original_completion_mode": current_contract.get("completion_mode"),
            "original_signed_at": current_contract.get("completed_at"),
            "reason": data.reason,
            "send_new_contract": data.send_new_contract
        }
    )
    
    # If requested, send new contract notification to worker
    if data.send_new_contract:
        # Create notification for worker
        notification_id = str(uuid.uuid4())
        await db.worker_notifications.insert_one({
            "id": notification_id,
            "employee_id": employee_id,
            "type": "contract_required",
            "title": "New Contract Required",
            "message": "Your previous contract has been superseded. Please sign the new employment contract.",
            "created_at": now.isoformat(),
            "read": False
        })
    
    return {
        "success": True,
        "message": "Contract superseded successfully",
        "original_contract_id": current_contract["id"],
        "new_contract_notification_sent": data.send_new_contract,
        "worker_action_required": "Worker must sign new contract in their portal"
    }


@api_router.delete("/employees/{employee_id}/permanent")
async def permanent_delete_employee(employee_id: str, user: dict = Depends(require_admin)):
    """Permanently delete an employee and all related data. Super Admin only.
    Use only for: duplicate records, test/demo records, incorrect entries."""
    
    # Only super_admin can permanently delete
    if user.get('role') != UserRole.SUPER_ADMIN:
        raise HTTPException(status_code=403, detail="Only Super Admin can permanently delete employees")
    
    employee = await db.employees.find_one({"id": employee_id}, {"_id": 0})
    if not employee:
        raise HTTPException(status_code=404, detail="Employee not found")
    
    employee_info = {
        "employee_name": f"{employee.get('first_name')} {employee.get('last_name')}",
        "employee_code": employee.get('employee_code'),
        "email": employee.get('email'),
        "status_at_deletion": employee.get('status')
    }
    
    # Delete employee record
    await db.employees.delete_one({"id": employee_id})
    
    # Delete related records
    deleted_docs = await db.employee_documents.delete_many({"employee_id": employee_id})
    deleted_forms = await db.generated_forms.delete_many({"employee_id": employee_id})
    deleted_policies = await db.policy_assignments.delete_many({"employee_id": employee_id})
    deleted_training = await db.training_records.delete_many({"employee_id": employee_id})
    
    await log_audit_action(
        user['user_id'], 
        "permanent_delete_employee", 
        "employee", 
        employee_id, 
        {
            **employee_info,
            "deleted_documents": deleted_docs.deleted_count,
            "deleted_forms": deleted_forms.deleted_count,
            "deleted_policies": deleted_policies.deleted_count,
            "deleted_training": deleted_training.deleted_count,
            "action": "PERMANENT DELETION - All employee data removed"
        }
    )
    
    return {
        "message": "Employee permanently deleted",
        "employee_id": employee_id,
        "deleted_records": {
            "documents": deleted_docs.deleted_count,
            "forms": deleted_forms.deleted_count,
            "policies": deleted_policies.deleted_count,
            "training": deleted_training.deleted_count
        }
    }


