async def create_worker_account_on_approval(employee: dict):
    """
    Create worker account in worker_accounts collection when recruitment is approved.
    This enables the worker to access the portal.
    
    No password is set initially - worker uses magic link first, then can optionally set password.
    """
    employee_id = employee.get("id")
    email = employee.get("email")
    
    if not employee_id or not email:
        logger.warning(f"Cannot create worker account - missing id or email")
        return False
    
    # Check if account already exists
    existing = await db.worker_accounts.find_one({"employee_id": employee_id})
    if existing:
        logger.info(f"Worker account already exists for {employee_id}")
        return True
    
    now = datetime.now(timezone.utc).isoformat()
    
    account_doc = {
        "id": str(uuid.uuid4()),
        "employee_id": employee_id,
        "email": email.lower(),
        "password_hash": None,  # No password initially - uses magic link
        "has_password": False,
        "account_created_at": now,
        "created_at": now,
        "updated_at": now,
        "last_login": None,
        "login_count": 0,
        "account_status": "active"
    }
    
    try:
        await db.worker_accounts.insert_one(account_doc)
        logger.info(f"Worker account created for employee {employee_id}")
        return True
    except Exception as e:
        logger.error(f"Failed to create worker account for {employee_id}: {e}")
        return False


async def try_auto_promote_worker(employee_id: str):
    """
    Internal helper to check and auto-promote an employee after significant events.
    Called automatically after document uploads, form submissions, etc.
    Does not require user auth - runs as system background task.
    
    Auto-promotion triggers when unified can_promote is true.
    """
    try:
        employee = await db.employees.find_one({"id": employee_id}, {"_id": 0})
        if not employee:
            return
        
        current_status = employee.get("status", "applicant")
        
        # Don't promote if already active.
        if current_status in (EmployeeStatus.ACTIVE, "active_employee"):
            return
        
        unified_status = await get_unified_employee_status(
            employee_id,
            db,
            user_role="admin",
            include_details=False
        )
        if unified_status.get("error"):
            logger.warning(f"Unified promotion check failed for {employee_id}: {unified_status['error']}")
            return
        
        can_promote = unified_status.get("can_promote", False)
        checks = unified_status.get("checks", {})
        
        if not can_promote:
            return  # Not ready yet
        
        # Promote to active
        now = datetime.now(timezone.utc).isoformat()
        update_data = {
            "status": EmployeeStatus.ACTIVE,
            "promoted_at": now,
            "promoted_via": "auto_unified_can_promote",
            "updated_at": now
        }
        
        await db.employees.update_one({"id": employee_id}, {"$set": update_data})
        
        # Audit log
        await log_audit_action(
            "system",
            "auto_promoted_to_active",
            "employee",
            employee_id,
            {
                "employee_name": f"{employee.get('first_name')} {employee.get('last_name')}",
                "previous_status": current_status,
                "new_status": EmployeeStatus.ACTIVE,
                "checks_passed": [k for k, v in checks.items() if v is True],
                "triggered_by": "unified_can_promote"
            }
        )
        
        # Send promotion email
        await send_promotion_email(employee)
        
        logger.info(f"Employee {employee_id} auto-promoted to active via unified can_promote")
        
    except Exception as e:
        logger.error(f"Auto-promotion check failed for {employee_id}: {e}")


