# ============================================================================
# SUPPLEMENTARY TRAINING ENDPOINTS
# All endpoints use evaluate_employee_training_status as canonical evaluator
# ============================================================================

@api_router.get("/employees/{employee_id}/training")
async def get_employee_training(
    employee_id: str,
    user: dict = Depends(get_current_user)
):
    """
    Get training status for an employee using canonical evaluator.
    
    Returns:
    - overall: 'current' | 'due_soon' | 'overdue' | 'missing'
    - blockerCount: Work-blocking training items that are not passed
    - warningCount: Non-blocking training items needing attention
    - items: Array of training item status
    """
    start_time = time_module.time()
    source = get_read_source("training")
    
    employee = await db.employees.find_one({"id": employee_id}, {"_id": 0, "role": 1})
    if not employee:
        raise HTTPException(status_code=404, detail="Employee not found")
    
    role = employee.get('role', '')
    
    # Training evaluation still uses Mongo (complex calculations)
    # We just log the intended source for observability
    training_status = await evaluate_employee_training_status(employee_id, role)
    
    # Log source served
    latency_ms = (time_module.time() - start_time) * 1000
    item_count = len(training_status.get('items', []))
    log_source_served("GET /employees/{id}/training", "training", ReadSource.MONGO, item_count, employee_id=employee_id, latency_ms=latency_ms)
    
    return training_status


@api_router.get("/employees/{employee_id}/training-records")
async def get_employee_training_records(
    employee_id: str,
    user: dict = Depends(get_current_user)
):
    """
    Get all training records for an employee with mandatory/additional categorization.
    
    This endpoint supports the EnhancedTrainingTab component, providing:
    - All training records (not superseded)
    - is_mandatory flag based on employee role
    - blocks_promotion flag for mandatory trainings
    
    Returns:
    {
        "trainings": [...],  # All training records
        "mandatory_count": X,
        "additional_count": Y,
        "mandatory_complete": Z
    }
    """
    # Get employee with role
    employee = await db.employees.find_one(
        {"id": employee_id}, 
        {"_id": 0, "id": 1, "role": 1, "first_name": 1, "last_name": 1}
    )
    if not employee:
        raise HTTPException(status_code=404, detail="Employee not found")
    
    role = employee.get('role', 'Healthcare Assistant')
    
    # Get all active training records
    records = await db.training_records.find(
        {
            "employee_id": employee_id,
            "record_status": {"$ne": "superseded"}
        },
        {"_id": 0}
    ).sort("completion_date", -1).to_list(length=500)
    
    # Categorize each training record
    trainings = []
    for record in records:
        training_id = record.get("training_id") or record.get("id", "")
        training_name = record.get("training_name", "")
        
        # Determine if mandatory using the extraction service
        is_mandatory = is_mandatory_for_role(training_id, role)
        
        # If not matched by ID, try matching by name keywords (case-insensitive)
        if not is_mandatory:
            # Normalize name: lowercase, remove special chars, collapse whitespace
            name_lower = training_name.lower().replace('&', ' and ').replace('-', ' ')
            name_lower = ' '.join(name_lower.split())  # Collapse multiple spaces
            mandatory_keywords = [
                'safeguarding', 'manual handling', 'moving handling', 
                'fire safety', 'health safety', 'health and safety',
                'basic life support', 'bls', 'resuscitation', 'infection control',
                'infection prevention'
            ]
            is_mandatory = any(kw in name_lower for kw in mandatory_keywords)
        
        record["is_mandatory"] = is_mandatory
        record["blocks_promotion"] = is_mandatory
        
        # Check expiry status
        if record.get("expiry_date"):
            try:
                expiry = datetime.fromisoformat(record["expiry_date"].replace('Z', '+00:00'))
                record["is_expired"] = expiry < datetime.now(timezone.utc)
            except:
                record["is_expired"] = False
        else:
            record["is_expired"] = False
        
        trainings.append(record)
    
    # Calculate counts from the trainings we already categorized
    mandatory_trainings = [t for t in trainings if t.get("is_mandatory")]
    additional_trainings = [t for t in trainings if not t.get("is_mandatory")]
    mandatory_complete = len([t for t in mandatory_trainings if not t.get("is_expired")])
    
    return {
        "trainings": trainings,
        "mandatory_count": len(mandatory_trainings),
        "additional_count": len(additional_trainings),
        "mandatory_complete": mandatory_complete
    }


@api_router.get("/employees/{employee_id}/training/matrix")
async def get_employee_training_matrix(
    employee_id: str,
    user: dict = Depends(get_current_user)
):
    """
    Get comprehensive training matrix for an employee.
    
    Provides detailed view of all required training with:
    - Current completion status
    - Evidence/verification status
    - Expiry tracking
    - Work-blocking indicators
    - Summary statistics
    
    Used by the TrainingMatrix frontend component.
    """
    employee = await db.employees.find_one({"id": employee_id}, {"_id": 0, "role": 1, "first_name": 1, "last_name": 1})
    if not employee:
        raise HTTPException(status_code=404, detail="Employee not found")
    
    role = employee.get('role', '')
    
    # Get canonical training evaluation
    training_eval = await evaluate_employee_training_status(employee_id, role)
    
    # Get training records for evidence details (including additional qualifications)
    training_records = await db.training_records.find({
        "employee_id": employee_id,
        "record_status": {"$nin": ["superseded", "deleted"]}
    }, {"_id": 0}).to_list(200)
    
    records_by_req = {}
    additional_records = []  # Non-mandatory training records
    
    # Define mandatory training codes (must match MANDATORY_TRAINING_HCA in unified_compliance_engine.py)
    mandatory_codes = {'safeguarding', 'manual_handling', 'infection_control', 
                      'basic_life_support', 'bls', 'fire_safety', 'health_safety',
                      'information_governance', 'prevent',
                      'safeguarding_adults', 'safeguarding_children', 'moving_handling'}
    
    for r in training_records:
        req_id = r.get('requirement_id') or r.get('training_name', '').lower().replace(' ', '_').replace('&', 'and')
        training_name_lower = r.get('training_name', '').lower()
        
        # Check if this is a mandatory training (either by code or by name pattern)
        is_mandatory = False
        for code in mandatory_codes:
            if code in req_id.lower() or code.replace('_', ' ') in training_name_lower:
                is_mandatory = True
                records_by_req[req_id] = r
                break
        
        # If not mandatory, add to additional records
        if not is_mandatory:
            additional_records.append(r)
    
    # Build enhanced matrix items
    matrix_items = []
    total_current = 0
    total_expiring = 0
    total_missing = 0
    total_blockers = 0
    
    for item in training_eval.get('items', []):
        code = item.get('code', '')
        record = records_by_req.get(code, {})
        
        # Determine evidence status
        has_evidence = bool(
            record.get('certificate_url') or 
            record.get('evidence_files') or
            record.get('certificate_document_id')
        )
        is_verified = (
            record.get('verified', False) or 
            record.get('verification_status') == 'verified'
        )
        
        # Get blocker config
        blocker_config = get_training_blocker_config(code)
        validity_days = get_training_validity_days(code)
        
        matrix_item = {
            "code": code,
            "id": record.get('id') or code,
            "title": item.get('title', code),
            "status": item.get('status', 'missing'),
            "detail": item.get('detail', ''),
            "blocker": item.get('blocker', False),
            "evidence_required": blocker_config.get('evidence_required', True),
            "completed_at": record.get('completion_date') or record.get('completed_at'),
            "expires_at": item.get('expires_at'),
            "days_until_expiry": item.get('days_until_expiry'),
            "has_evidence": has_evidence,
            "is_verified": is_verified,
            "verified": is_verified,
            "verified_by": record.get('verified_by'),
            "verified_at": record.get('verified_at'),
            "record_id": record.get('id'),
            "provider": record.get('provider_name') or record.get('provider'),
            "validity_days": validity_days,
            "source_document_id": record.get('source_document_id') or record.get('certificate_document_id'),
            "certificate_url": record.get('certificate_url')
        }
        matrix_items.append(matrix_item)
        
        # Count by status
        status = item.get('status', 'missing')
        if status in ['current', 'completed', 'verified']:
            total_current += 1
        elif status in ['expiring_soon', 'due_soon']:
            total_expiring += 1
        elif status in ['missing', 'expired', 'overdue']:
            total_missing += 1
        
        if item.get('blocker') and status not in ['current', 'completed', 'verified']:
            total_blockers += 1
    
    # Build additional qualifications list
    additional_items = []
    for record in additional_records:
        # Calculate status based on expiry
        status = 'current'
        expires_at = record.get('expiry_date') or record.get('expires_at')
        if expires_at:
            from datetime import datetime, timezone
            try:
                if isinstance(expires_at, str):
                    exp_date = datetime.fromisoformat(expires_at.replace('Z', '+00:00'))
                else:
                    exp_date = expires_at
                now = datetime.now(timezone.utc)
                days_until = (exp_date - now).days
                if days_until < 0:
                    status = 'expired'
                elif days_until <= 30:
                    status = 'expiring_soon'
            except:
                pass
        
        additional_items.append({
            "code": record.get('id', ''),
            "id": record.get('id', ''),
            "title": record.get('training_name', 'Unknown Training'),
            "status": status,
            "is_required": False,
            "is_additional": True,
            "completed_at": record.get('completion_date') or record.get('completed_at'),
            "expires_at": expires_at,
            "has_evidence": bool(record.get('certificate_url') or record.get('evidence_files') or record.get('certificate_document_id')),
            "is_verified": record.get('verified', False),
            "verified": record.get('verified', False),
            "verified_by": record.get('verified_by'),
            "verified_at": record.get('verified_at'),
            "record_id": record.get('id'),
            "provider": record.get('provider_name') or record.get('provider'),
            "source_document_id": record.get('source_document_id') or record.get('certificate_document_id'),
            "certificate_url": record.get('certificate_url'),
            "needs_review": record.get('needs_review', False)
        })
    
    return {
        "employee_id": employee_id,
        "employee_name": f"{employee.get('first_name', '')} {employee.get('last_name', '')}".strip(),
        "role": role,
        "overall": training_eval.get('overall', 'missing'),
        "items": matrix_items,
        "additional_items": additional_items,
        "summary": {
            "total": len(matrix_items),
            "current": total_current,
            "expiring": total_expiring,
            "missing": total_missing,
            "blockers": total_blockers,
            "additional_count": len(additional_items)
        },
        "evaluated_at": training_eval.get('evaluatedAt')
    }




@api_router.post("/employees/{employee_id}/training/assign")
async def assign_training(
    employee_id: str,
    training_code: str = Body(..., embed=True),
    required: bool = Body(True, embed=True),
    blocker_for_work: bool = Body(False, embed=True),
    user: dict = Depends(get_current_user)
):
    """
    Assign additional training requirement to an employee.
    Use this to add supplementary training beyond role defaults.
    """
    employee = await db.employees.find_one({"id": employee_id}, {"_id": 0, "id": 1})
    if not employee:
        raise HTTPException(status_code=404, detail="Employee not found")
    
    # Check if training exists in catalogue
    catalogue_item = await db.training_catalogue.find_one({"id": training_code}, {"_id": 0})
    if not catalogue_item:
        raise HTTPException(status_code=404, detail=f"Training '{training_code}' not found in catalogue")
    
    now = datetime.now(timezone.utc).isoformat()
    assignment = {
        "id": str(uuid.uuid4()),
        "employee_id": employee_id,
        "training_code": training_code,
        "training_name": catalogue_item.get('training_name', training_code),
        "is_required": required,
        "blocker_for_work": blocker_for_work,
        "assigned_by": user['email'],
        "assigned_at": now,
        "created_at": now
    }
    
    # Upsert - don't duplicate
    await db.employee_training_assignments.update_one(
        {"employee_id": employee_id, "training_code": training_code},
        {"$set": assignment},
        upsert=True
    )
    
    await log_audit_action(user['user_id'], "assign_training", "employee", employee_id, {
        "training_code": training_code,
        "required": required,
        "blocker_for_work": blocker_for_work
    })
    
    return {
        "status": "success",
        "message": f"Training '{training_code}' assigned to employee",
        "assignment": assignment
    }


@api_router.post("/employees/{employee_id}/training/record")
async def record_training_completion(
    employee_id: str,
    training_code: str = Body(...),
    completion_date: str = Body(...),
    provider_name: Optional[str] = Body(None),
    certificate_document_id: Optional[str] = Body(None),
    notes: Optional[str] = Body(None),
    user: dict = Depends(get_current_user)
):
    """
    Record a training completion for an employee.
    Creates or updates the training record.
    """
    employee = await db.employees.find_one({"id": employee_id}, {"_id": 0, "id": 1})
    if not employee:
        raise HTTPException(status_code=404, detail="Employee not found")
    
    # Calculate expiry date
    expiry_date = calculate_training_expiry(completion_date, training_code)
    
    now = datetime.now(timezone.utc).isoformat()
    record_id = str(uuid.uuid4())
    
    # Get training name from catalogue or use code
    catalogue_item = await db.training_catalogue.find_one({"id": training_code}, {"_id": 0})
    training_name = catalogue_item.get('training_name', training_code) if catalogue_item else training_code
    
    # Check for existing record
    existing = await db.training_records.find_one({
        "employee_id": employee_id,
        "requirement_id": training_code,
        "record_status": {"$ne": "deleted"}
    })
    
    if existing:
        # Update existing record
        await db.training_records.update_one(
            {"id": existing['id']},
            {"$set": {
                "completion_date": normalize_date_only(completion_date),
                "expiry_date": normalize_date_only(expiry_date),
                "provider_name": provider_name,
                "status": "completed",
                "verified": False,  # Reset verification on update
                "verification_status": "awaiting_review",
                "updated_at": now,
                "notes": notes
            }}
        )
        record_id = existing['id']
    else:
        # Create new record
        new_record = {
            "id": record_id,
            "employee_id": employee_id,
            "requirement_id": training_code,
            "training_name": training_name,
            "mandatory": True,
            "completion_date": normalize_date_only(completion_date),
            "expiry_date": normalize_date_only(expiry_date),
            "provider_name": provider_name,
            "status": "completed",
            "verified": False,
            "verification_status": "awaiting_review",
            "record_status": "active",
            "created_at": now,
            "updated_at": now,
            "notes": notes
        }
        
        if certificate_document_id:
            new_record['certificate_document_id'] = certificate_document_id
        
        await db.training_records.insert_one(new_record)
    
    await log_audit_action(user['user_id'], "record_training", "employee", employee_id, {
        "training_code": training_code,
        "completion_date": completion_date
    })
    
    return {
        "status": "success",
        "message": f"Training '{training_name}' recorded",
        "record_id": record_id,
        "expiry_date": expiry_date
    }



@api_router.post("/employees/{employee_id}/training/{record_id}/verify")
async def verify_training(
    employee_id: str,
    record_id: str,
    user: dict = Depends(get_current_user)
):
    """
    Verify a training record.
    Only verified training counts toward readiness where evidence is required.
    
    P0 FIX: Now accepts either:
    - record_id: The actual training record UUID (e.g., "tr_abc123")
    - training_code: The training type code (e.g., "safeguarding", "manual_handling")
    
    Also auto-completes corresponding induction checklist items.
    """
    # First try to find by exact record ID
    record = await db.training_records.find_one({
        "id": record_id,
        "employee_id": employee_id,
        "record_status": {"$ne": "deleted"}
    })
    
    # P0 FIX: If not found by ID, try by training code/name
    if not record:
        # Try matching by requirement_id or training_name patterns
        code_lower = record_id.lower().replace("_", " ")
        record = await db.training_records.find_one({
            "employee_id": employee_id,
            "record_status": {"$ne": "deleted"},
            "$or": [
                {"requirement_id": record_id},
                {"requirement_id": {"$regex": f"^{record_id}$", "$options": "i"}},
                {"code": record_id},
                {"code": {"$regex": f"^{record_id}$", "$options": "i"}},
                {"training_name": {"$regex": code_lower, "$options": "i"}}
            ]
        })
    
    if not record:
        raise HTTPException(status_code=404, detail="Training record not found")
    
    if record.get('verified'):
        raise HTTPException(status_code=400, detail="Training already verified")
    
    now = datetime.now(timezone.utc).isoformat()
    
    # P0 FIX: Get user's full name for verification stamp (not email)
    user_doc = await db.users.find_one({"user_id": user['user_id']}, {"_id": 0, "first_name": 1, "last_name": 1, "name": 1})
    if not user_doc:
        user_doc = await db.users.find_one({"id": user['user_id']}, {"_id": 0, "first_name": 1, "last_name": 1, "name": 1})
    
    user_name = "Admin"  # Default fallback
    if user_doc:
        if user_doc.get('name'):
            user_name = user_doc['name']
        elif user_doc.get('first_name'):
            user_name = f"{user_doc.get('first_name', '')} {user_doc.get('last_name', '')}".strip()
    
    # If still no name, use email but format it nicely
    if user_name == "Admin" and user.get('email'):
        email = user['email']
        # Convert email to display name: john.doe@email.com -> John Doe
        name_part = email.split('@')[0]
        user_name = ' '.join(word.capitalize() for word in name_part.replace('.', ' ').replace('_', ' ').split())
    
    await db.training_records.update_one(
        {"id": record.get("id")},  # Use actual record ID
        {"$set": {
            "verified": True,
            "verification_status": "verified",
            "verified_by": user_name,  # P0 FIX: Store name, not email
            "verified_by_id": user['user_id'],  # Store ID for audit trail
            "verified_at": now,
            "updated_at": now
        }}
    )
    
    # P0: Auto-complete corresponding induction checklist item
    training_id = record.get('requirement_id') or record.get('code') or record.get('training_name', '').lower().replace(' ', '_')
    training_name = record.get('training_name', '')
    
    induction_result = await auto_complete_induction_from_training(
        db=db,
        employee_id=employee_id,
        training_id=training_id,
        training_name=training_name,
        verified_by=user['user_id'],
        verified_by_name=user_name
    )
    
    await log_audit_action(user['user_id'], "verify_training", "employee", employee_id, {
        "record_id": record.get("id"),
        "training_name": record.get('training_name'),
        "verified_by_name": user_name,
        "induction_auto_complete": induction_result
    })
    
    return {
        "status": "success",
        "message": f"Training '{record.get('training_name')}' verified",
        "verified_by": user_name,
        "verified_at": now,
        "induction_auto_complete": induction_result
    }


