# ============================================================================
# PDF TEMPLATE MANAGEMENT & GENERATION - Template-Backed Forms Architecture
# ============================================================================

async def generate_staff_health_pdf(submission_data: dict, employee_data: dict, template_config: dict = None) -> bytes:
    """
    Generate a completed Staff Health Questionnaire PDF from structured form data.
    Uses reportlab to create a professional PDF matching the official template layout.
    
    Args:
        submission_data: The structured form data from form_submissions
        employee_data: Employee profile data for additional context
        template_config: Optional custom template configuration
    
    Returns:
        bytes: The generated PDF content
    """
    buffer = io.BytesIO()
    
    # Use the mapping config or default
    mapping = template_config or STAFF_HEALTH_PDF_MAPPING
    branding = mapping.get("company_branding", {})
    
    # Create PDF document
    doc = SimpleDocTemplate(
        buffer,
        pagesize=A4,
        rightMargin=20*mm,
        leftMargin=20*mm,
        topMargin=15*mm,
        bottomMargin=15*mm
    )
    
    # Styles
    styles = getSampleStyleSheet()
    
    # Custom styles matching Osabea branding
    section_header_style = ParagraphStyle(
        'SectionHeader',
        parent=styles['Heading2'],
        fontSize=12,
        textColor=colors.white,
        alignment=TA_LEFT,
        spaceBefore=12,
        spaceAfter=6
    )
    
    label_style = ParagraphStyle(
        'FieldLabel',
        parent=styles['Normal'],
        fontSize=10,
        textColor=colors.HexColor('#333333'),
        fontName='Helvetica-Bold'
    )
    
    value_style = ParagraphStyle(
        'FieldValue',
        parent=styles['Normal'],
        fontSize=10,
        textColor=colors.HexColor('#000000')
    )
    
    question_style = ParagraphStyle(
        'Question',
        parent=styles['Normal'],
        fontSize=9,
        textColor=colors.HexColor('#333333'),
        leftIndent=10
    )
    
    # Build story (content elements)
    story = []
    
    # Header with green background
    green_color = colors.HexColor(branding.get("header_color", "#2E7D32"))
    
    # Try to get the company logo image
    logo_element = None
    try:
        from services.pdf_service import get_logo_image
        logo_element = get_logo_image(width=35*mm, height=14*mm)
    except Exception:
        pass
    
    # Company header table - use logo image if available, otherwise text
    if logo_element:
        header_data = [[
            logo_element,
            Paragraph(f"<b>{branding.get('name', 'Osabea Healthcare Solutions Ltd')}</b><br/><font size='10'>Staff Health Questionnaire</font>", 
                      ParagraphStyle('HeaderText', fontSize=14, textColor=colors.white, alignment=TA_LEFT))
        ]]
    else:
        header_data = [[
            Paragraph(f"<b>{branding.get('logo_text', 'O')}</b>", 
                      ParagraphStyle('Logo', fontSize=24, textColor=colors.white, alignment=TA_CENTER)),
            Paragraph(f"<b>{branding.get('name', 'Osabea Healthcare Solutions Ltd')}</b><br/><font size='10'>Staff Health Questionnaire</font>", 
                      ParagraphStyle('HeaderText', fontSize=14, textColor=colors.white, alignment=TA_LEFT))
        ]]
    
    header_table = Table(header_data, colWidths=[25*mm, 145*mm])
    header_table.setStyle(TableStyle([
        ('BACKGROUND', (0, 0), (-1, -1), green_color),
        ('VALIGN', (0, 0), (-1, -1), 'MIDDLE'),
        ('ALIGN', (0, 0), (0, 0), 'CENTER'),
        ('LEFTPADDING', (0, 0), (-1, -1), 10),
        ('RIGHTPADDING', (0, 0), (-1, -1), 10),
        ('TOPPADDING', (0, 0), (-1, -1), 8),
        ('BOTTOMPADDING', (0, 0), (-1, -1), 8),
    ]))
    story.append(header_table)
    story.append(Spacer(1, 3*mm))
    
    # Confidentiality notice
    confidentiality = branding.get("confidentiality_notice", "CONFIDENTIAL - For Occupational Health Use Only")
    story.append(Paragraph(f"<i>{confidentiality}</i>", 
                          ParagraphStyle('Confidential', fontSize=8, textColor=colors.HexColor('#666666'), alignment=TA_CENTER)))
    story.append(Spacer(1, 5*mm))
    
    # Helper function to format field value
    def format_value(value, field_type="text"):
        if value is None or value == "":
            return "-"
        if field_type == "date" and value:
            try:
                # Parse ISO date and format nicely
                if 'T' in str(value):
                    dt = datetime.fromisoformat(value.replace('Z', '+00:00'))
                    return dt.strftime('%d/%m/%Y')
                return value
            except:
                return value
        if field_type == "checkbox":
            return "Yes" if value else "No"
        return str(value)
    
    # Process each section
    for section in mapping.get("sections", []):
        # Section header with green background
        section_data = [[Paragraph(f"<b>{section['title']}</b>", section_header_style)]]
        section_table = Table(section_data, colWidths=[170*mm])
        section_table.setStyle(TableStyle([
            ('BACKGROUND', (0, 0), (-1, -1), green_color),
            ('LEFTPADDING', (0, 0), (-1, -1), 8),
            ('RIGHTPADDING', (0, 0), (-1, -1), 8),
            ('TOPPADDING', (0, 0), (-1, -1), 6),
            ('BOTTOMPADDING', (0, 0), (-1, -1), 6),
        ]))
        story.append(section_table)
        story.append(Spacer(1, 2*mm))
        
        # Build field rows
        if section['id'] == 'health_questions':
            # Health questions in a special format
            for field in section.get('fields', []):
                field_id = field['field_id']
                field_type = field.get('type', 'text')
                label = field['label']
                value = submission_data.get(field_id, '')
                
                if field_type == 'yes_no':
                    answer = format_value(value)
                    details_field = field.get('details_field')
                    details = submission_data.get(details_field, '') if details_field and value == 'Yes' else ''
                    
                    q_data = [[
                        Paragraph(f"{label}", question_style),
                        Paragraph(f"<b>{answer}</b>", value_style)
                    ]]
                    q_table = Table(q_data, colWidths=[140*mm, 30*mm])
                    q_table.setStyle(TableStyle([
                        ('VALIGN', (0, 0), (-1, -1), 'TOP'),
                        ('LEFTPADDING', (0, 0), (-1, -1), 5),
                        ('BOTTOMPADDING', (0, 0), (-1, -1), 2),
                        ('GRID', (0, 0), (-1, -1), 0.5, colors.HexColor('#E0E0E0')),
                    ]))
                    story.append(q_table)
                    
                    if details:
                        details_data = [[Paragraph(f"<i>Details: {details}</i>", 
                                                   ParagraphStyle('Details', fontSize=9, textColor=colors.HexColor('#555555'), leftIndent=20))]]
                        details_table = Table(details_data, colWidths=[170*mm])
                        details_table.setStyle(TableStyle([
                            ('BACKGROUND', (0, 0), (-1, -1), colors.HexColor('#F5F5F5')),
                            ('LEFTPADDING', (0, 0), (-1, -1), 10),
                            ('TOPPADDING', (0, 0), (-1, -1), 3),
                            ('BOTTOMPADDING', (0, 0), (-1, -1), 3),
                        ]))
                        story.append(details_table)
                else:
                    # Free text field
                    value_formatted = format_value(value, field_type)
                    q_data = [[
                        Paragraph(f"{label}", question_style),
                        Paragraph(f"{value_formatted}", value_style)
                    ]]
                    q_table = Table(q_data, colWidths=[140*mm, 30*mm])
                    q_table.setStyle(TableStyle([
                        ('VALIGN', (0, 0), (-1, -1), 'TOP'),
                        ('LEFTPADDING', (0, 0), (-1, -1), 5),
                        ('BOTTOMPADDING', (0, 0), (-1, -1), 2),
                        ('GRID', (0, 0), (-1, -1), 0.5, colors.HexColor('#E0E0E0')),
                    ]))
                    story.append(q_table)
        else:
            # Regular fields in a 2-column layout
            field_rows = []
            for field in section.get('fields', []):
                field_id = field['field_id']
                field_type = field.get('type', 'text')
                label = field['label']
                value = submission_data.get(field_id, '')
                value_formatted = format_value(value, field_type)
                
                field_rows.append([
                    Paragraph(f"<b>{label}:</b>", label_style),
                    Paragraph(value_formatted, value_style)
                ])
            
            if field_rows:
                field_table = Table(field_rows, colWidths=[60*mm, 110*mm])
                field_table.setStyle(TableStyle([
                    ('VALIGN', (0, 0), (-1, -1), 'TOP'),
                    ('LEFTPADDING', (0, 0), (-1, -1), 5),
                    ('RIGHTPADDING', (0, 0), (-1, -1), 5),
                    ('TOPPADDING', (0, 0), (-1, -1), 4),
                    ('BOTTOMPADDING', (0, 0), (-1, -1), 4),
                    ('GRID', (0, 0), (-1, -1), 0.5, colors.HexColor('#E0E0E0')),
                    ('BACKGROUND', (0, 0), (0, -1), colors.HexColor('#F8F8F8')),
                ]))
                story.append(field_table)
        
        story.append(Spacer(1, 4*mm))
    
    # Footer with submission info
    story.append(Spacer(1, 5*mm))
    story.append(HRFlowable(width="100%", thickness=1, color=colors.HexColor('#E0E0E0')))
    story.append(Spacer(1, 3*mm))
    
    # Add verification stamp if verified
    if submission_data.get('_verified'):
        verified_style = ParagraphStyle(
            'VerifiedStamp',
            fontSize=10,
            textColor=colors.HexColor('#059669'),
            alignment=TA_CENTER,
            fontName='Helvetica-Bold'
        )
        story.append(Paragraph("✓ VERIFIED", verified_style))
        story.append(Spacer(1, 2*mm))
    
    submitted_at = submission_data.get('_submitted_at', '')
    if submitted_at:
        try:
            dt = datetime.fromisoformat(submitted_at.replace('Z', '+00:00'))
            submitted_at = dt.strftime('%d/%m/%Y at %H:%M')
        except Exception:
            pass
    
    footer_text = f"Generated from Osabea Compliance Portal | Form submitted: {submitted_at} | Employee: {employee_data.get('first_name', '')} {employee_data.get('last_name', '')} ({employee_data.get('employee_code', '')})"
    story.append(Paragraph(footer_text, ParagraphStyle('Footer', fontSize=8, textColor=colors.HexColor('#888888'), alignment=TA_CENTER)))
    
    # Build PDF
    doc.build(story)
    
    buffer.seek(0)
    return buffer.getvalue()


async def generate_application_form_pdf(submission_data: dict, employee_data: dict) -> bytes:
    """
    Generate a PDF from a structured application form submission.
    Creates a professional PDF with all application sections.
    
    Args:
        submission_data: The structured form data (form_data/data field)
        employee_data: Employee profile data for header info
    
    Returns:
        bytes: The generated PDF content
    """
    buffer = io.BytesIO()
    
    # Create PDF document
    doc = SimpleDocTemplate(
        buffer,
        pagesize=A4,
        rightMargin=20*mm,
        leftMargin=20*mm,
        topMargin=15*mm,
        bottomMargin=15*mm
    )
    
    # Styles
    styles = getSampleStyleSheet()
    
    title_style = ParagraphStyle(
        'ApplicationTitle',
        parent=styles['Heading1'],
        fontSize=16,
        textColor=colors.HexColor('#0F766E'),
        alignment=TA_CENTER,
        spaceAfter=10*mm
    )
    
    section_style = ParagraphStyle(
        'SectionHeader',
        parent=styles['Heading2'],
        fontSize=12,
        textColor=colors.white,
        backColor=colors.HexColor('#0F766E'),
        spaceBefore=8*mm,
        spaceAfter=4*mm,
        leftIndent=-5*mm,
        rightIndent=-5*mm,
        borderPadding=(3*mm, 5*mm, 3*mm, 5*mm)
    )
    
    label_style = ParagraphStyle(
        'FieldLabel',
        parent=styles['Normal'],
        fontSize=9,
        textColor=colors.HexColor('#666666'),
        fontName='Helvetica-Bold'
    )
    
    value_style = ParagraphStyle(
        'FieldValue',
        parent=styles['Normal'],
        fontSize=10,
        textColor=colors.HexColor('#000000')
    )
    
    subsection_style = ParagraphStyle(
        'SubsectionHeader',
        parent=styles['Heading3'],
        fontSize=10,
        textColor=colors.HexColor('#0F766E'),
        spaceBefore=4*mm,
        spaceAfter=2*mm
    )
    
    story = []

    personal = submission_data.get('personal_details') or {}
    contact = submission_data.get('contact_details') or {}
    address_section = submission_data.get('address') or {}
    role_availability = submission_data.get('role_availability') or {}
    qualifications = submission_data.get('qualifications') or {}
    emergency_contact = submission_data.get('emergency_contact') or {}

    def get_value(primary: dict, key: str, *legacy_keys: str):
        if isinstance(primary, dict):
            value = primary.get(key)
            if value not in (None, ''):
                return value
        for legacy_key in legacy_keys:
            value = submission_data.get(legacy_key)
            if value not in (None, ''):
                return value
        return None
    
    # Helper function to add a field row
    def add_field(label: str, value, story_list):
        if value is None or value == '':
            return
        if isinstance(value, bool):
            value = 'Yes' if value else 'No'
        story_list.append(Paragraph(f"<b>{label}:</b> {value}", value_style))
        story_list.append(Spacer(1, 2*mm))
    
    # Try to add company logo
    try:
        from services.pdf_service import get_logo_image
        logo = get_logo_image(width=50*mm, height=20*mm)
        if logo:
            from reportlab.platypus import Table, TableStyle
            logo_table = Table([[logo]], colWidths=[170*mm])
            logo_table.setStyle(TableStyle([('ALIGN', (0, 0), (-1, -1), 'CENTER')]))
            story.append(logo_table)
            story.append(Spacer(1, 3*mm))
    except Exception:
        # Fallback to text header
        story.append(Paragraph("Osabea Healthcare Solutions", ParagraphStyle('CompanyName', fontSize=14, textColor=colors.HexColor('#0F766E'), alignment=TA_CENTER)))
        story.append(Spacer(1, 3*mm))
    
    story.append(Paragraph("Application Form", title_style))
    
    # Status banner
    status = submission_data.get('_status', 'submitted')
    status_color = colors.HexColor('#059669') if status == 'verified' else colors.HexColor('#D97706') if status == 'submitted' else colors.HexColor('#DC2626')
    status_text = 'VERIFIED' if status == 'verified' else 'AWAITING REVIEW' if status == 'submitted' else status.upper()
    story.append(Paragraph(f"<font color='#{status_color.hexval()[2:]}'><b>Status: {status_text}</b></font>", ParagraphStyle('Status', fontSize=10, alignment=TA_CENTER)))
    story.append(Spacer(1, 5*mm))
    
    # PERSONAL DETAILS
    story.append(Paragraph("Personal Details", section_style))
    story.append(Spacer(1, 3*mm))
    
    full_name = ' '.join(filter(None, [
        get_value(personal, 'title', 'title') or '',
        get_value(personal, 'first_name', 'first_name') or '',
        get_value(personal, 'middle_name', 'middle_name') or '',
        get_value(personal, 'last_name', 'last_name') or ''
    ]))
    add_field('Full Name', full_name, story)
    add_field('Preferred Name', get_value(personal, 'preferred_name', 'preferred_name'), story)
    add_field('Date of Birth', get_value(personal, 'date_of_birth', 'date_of_birth'), story)
    add_field('National Insurance Number', get_value(personal, 'national_insurance', 'national_insurance', 'ni_number'), story)
    add_field('Email', get_value(contact, 'email', 'email'), story)
    add_field('Phone', get_value(contact, 'phone', 'phone'), story)
    
    address_parts = [
        get_value(address_section, 'address_line_1', 'address_line_1') or '',
        get_value(address_section, 'address_line_2', 'address_line_2') or '',
        get_value(address_section, 'city', 'city') or '',
        get_value(address_section, 'county', 'county') or '',
        get_value(address_section, 'postcode', 'postcode') or ''
    ]
    address = ', '.join(filter(None, address_parts))
    add_field('Address', address, story)
    add_field('Years at Current Address', get_value(address_section, 'years_at_current_address', 'years_at_current_address'), story)
    
    story.append(Spacer(1, 3*mm))
    story.append(Paragraph("Role & Availability", subsection_style))
    add_field('Role Applied For', get_value(role_availability, 'role_applied', 'role_applied'), story)
    add_field('Availability', get_value(role_availability, 'availability', 'availability'), story)
    add_field('Earliest Start Date', get_value(role_availability, 'earliest_start_date', 'earliest_start_date'), story)
    add_field('Has Driving Licence', get_value(role_availability, 'has_driving_licence', 'has_driving_licence'), story)
    add_field('Has Own Transport', get_value(role_availability, 'has_own_transport', 'has_own_transport'), story)
    
    # EMPLOYMENT HISTORY
    story.append(Paragraph("Employment History", section_style))
    story.append(Spacer(1, 3*mm))
    
    employment_history = submission_data.get('employment_history', [])
    if employment_history:
        for idx, emp in enumerate(employment_history, 1):
            story.append(Paragraph(f"<b>Employment {idx}: {emp.get('job_title', 'N/A')} at {emp.get('employer_name', 'N/A')}</b>", subsection_style))
            period = f"{emp.get('start_date', 'N/A')} - {'Present' if emp.get('is_current') else emp.get('end_date', 'N/A')}"
            add_field('Period', period, story)
            add_field('Duties', emp.get('duties'), story)
            if not emp.get('is_current'):
                add_field('Reason for Leaving', emp.get('reason_for_leaving'), story)
            add_field('Employer Address', emp.get('employer_address'), story)
            add_field('Employer Phone', emp.get('employer_phone'), story)
            add_field('Can Contact Employer', emp.get('can_contact'), story)
            story.append(Spacer(1, 2*mm))
    else:
        story.append(Paragraph("No employment history provided", value_style))
    
    if submission_data.get('has_employment_gaps'):
        story.append(Spacer(1, 2*mm))
        story.append(Paragraph("<b>Employment Gaps Declared</b>", label_style))
        add_field('Gap Explanation', submission_data.get('employment_gap_explanation'), story)
    
    # REFERENCES
    story.append(Paragraph("References", section_style))
    story.append(Spacer(1, 3*mm))
    
    references = submission_data.get('references', [])
    if references:
        for idx, ref in enumerate(references, 1):
            story.append(Paragraph(f"<b>Reference {idx}: {ref.get('referee_name', 'N/A')}</b>", subsection_style))
            add_field('Job Title', ref.get('referee_job_title'), story)
            add_field('Organisation', ref.get('referee_organisation'), story)
            add_field('Email', ref.get('referee_email'), story)
            add_field('Phone', ref.get('referee_phone'), story)
            add_field('Relationship', ref.get('relationship'), story)
            add_field('Years Known', ref.get('years_known'), story)
            add_field('Professional Reference', ref.get('is_professional'), story)
            add_field('Can Contact Before Offer', ref.get('can_contact_before_offer'), story)
            story.append(Spacer(1, 2*mm))
    else:
        story.append(Paragraph("No references provided", value_style))

    if qualifications:
        story.append(Paragraph("Qualifications & Training", section_style))
        story.append(Spacer(1, 3*mm))
        add_field('Highest Qualification', get_value(qualifications, 'highest_qualification', 'highest_qualification'), story)
        add_field('Relevant Qualifications', get_value(qualifications, 'relevant_qualifications', 'relevant_qualifications'), story)
        add_field('Care Certificate Completed', get_value(qualifications, 'care_certificate_completed', 'care_certificate_completed'), story)
        add_field('Mandatory Training Completed', get_value(qualifications, 'mandatory_training_completed', 'mandatory_training_completed'), story)
    
    # DECLARATIONS
    story.append(Paragraph("Declarations & Consent", section_style))
    story.append(Spacer(1, 3*mm))
    
    declarations = submission_data.get('declarations', {})
    add_field('Information Accurate', declarations.get('information_accurate'), story)
    add_field('Understands False Info Consequences', declarations.get('understands_false_info_consequences'), story)
    add_field('Consents to Reference Checks', declarations.get('consents_to_reference_checks'), story)
    add_field('Consents to Background Checks', declarations.get('consents_to_background_checks'), story)
    add_field('Consents to Data Processing (GDPR)', declarations.get('consents_to_data_processing'), story)
    
    if declarations.get('has_professional_registration'):
        story.append(Spacer(1, 2*mm))
        story.append(Paragraph("Professional Registration", subsection_style))
        add_field('Registration Body', declarations.get('registration_body'), story)
        add_field('Registration Number', declarations.get('registration_number'), story)
        add_field('Registration Expiry', declarations.get('registration_expiry'), story)
    
    add_field('Has Disciplinary History', declarations.get('has_disciplinary_history'), story)
    if declarations.get('has_disciplinary_history'):
        add_field('Disciplinary Details', declarations.get('disciplinary_details'), story)
    add_field('Previously Worked for NHS', declarations.get('previously_worked_nhs'), story)
    
    # HEALTH DECLARATION
    story.append(Paragraph("Health Declaration", section_style))
    story.append(Spacer(1, 3*mm))
    
    health = submission_data.get('health_declaration', {})
    add_field('Can Perform Physical Tasks', health.get('can_perform_physical_tasks'), story)
    add_field('Has Back Problems', health.get('has_back_problems'), story)
    add_field('Has Mobility Issues', health.get('has_mobility_issues'), story)
    add_field('Had Recent Infectious Illness', health.get('had_recent_infectious_illness'), story)
    if health.get('had_recent_infectious_illness'):
        add_field('Illness Details', health.get('infectious_illness_details'), story)
    
    story.append(Spacer(1, 2*mm))
    story.append(Paragraph("Vaccinations", subsection_style))
    add_field('Hepatitis B Vaccinated', health.get('hepatitis_b_vaccinated'), story)
    add_field('Flu Vaccinated', health.get('flu_vaccinated'), story)
    add_field('COVID-19 Vaccinated', health.get('covid_vaccinated'), story)
    
    add_field('Has Condition Affecting Work', health.get('has_condition_affecting_work'), story)
    if health.get('has_condition_affecting_work'):
        add_field('Condition Details', health.get('condition_details'), story)
    add_field('Requires Reasonable Adjustments', health.get('requires_reasonable_adjustments'), story)
    if health.get('requires_reasonable_adjustments'):
        add_field('Adjustment Details', health.get('adjustment_details'), story)
    add_field('Health Declaration Accurate', health.get('health_declaration_accurate'), story)
    
    # CRIMINAL DECLARATION
    story.append(Paragraph("Criminal Declaration", section_style))
    story.append(Spacer(1, 3*mm))
    
    criminal = submission_data.get('criminal_declaration', {})
    add_field('Has Criminal Convictions', criminal.get('has_criminal_convictions'), story)
    if criminal.get('has_criminal_convictions'):
        add_field('Conviction Details', criminal.get('conviction_details'), story)
    add_field('Has Pending Charges', criminal.get('has_pending_charges'), story)
    if criminal.get('has_pending_charges'):
        add_field('Pending Charges Details', criminal.get('pending_charges_details'), story)
    add_field('Has Cautions/Warnings', criminal.get('has_cautions_warnings'), story)
    if criminal.get('has_cautions_warnings'):
        add_field('Cautions Details', criminal.get('cautions_details'), story)
    add_field('Understands DBS Required', criminal.get('understands_dbs_required'), story)
    add_field('Consents to DBS Check', criminal.get('consents_to_dbs_check'), story)
    
    # RIGHT TO WORK
    story.append(Paragraph("Right to Work", section_style))
    story.append(Spacer(1, 3*mm))
    
    rtw = submission_data.get('right_to_work', {})
    add_field('Has Right to Work in UK', rtw.get('has_right_to_work_uk'), story)
    add_field('Citizenship Status', rtw.get('citizenship_status'), story)
    if rtw.get('visa_type'):
        add_field('Visa Type', rtw.get('visa_type'), story)
    if rtw.get('visa_expiry'):
        add_field('Visa Expiry', rtw.get('visa_expiry'), story)
    if rtw.get('share_code'):
        add_field('Share Code', rtw.get('share_code'), story)
    add_field('Requires Sponsorship', rtw.get('requires_sponsorship'), story)
    
    # ADDITIONAL INFO
    if submission_data.get('how_heard') or submission_data.get('additional_info'):
        story.append(Paragraph("Additional Information", section_style))
        story.append(Spacer(1, 3*mm))
        add_field('How Heard About Us', submission_data.get('how_heard'), story)
        add_field('Additional Information', submission_data.get('additional_info'), story)

    emergency_name = get_value(emergency_contact, 'name', 'emergency_contact_name')
    emergency_phone = get_value(emergency_contact, 'phone', 'emergency_contact_phone')
    emergency_relationship = get_value(emergency_contact, 'relationship', 'emergency_contact_relationship')
    emergency_address = get_value(emergency_contact, 'address', 'emergency_contact_address')
    if any([emergency_name, emergency_phone, emergency_relationship, emergency_address]):
        story.append(Paragraph("Emergency Contact", section_style))
        story.append(Spacer(1, 3*mm))
        add_field('Name', emergency_name, story)
        add_field('Phone', emergency_phone, story)
        add_field('Relationship', emergency_relationship, story)
        add_field('Address', emergency_address, story)
    
    # Footer
    story.append(Spacer(1, 10*mm))
    story.append(HRFlowable(width="100%", thickness=1, color=colors.HexColor('#E0E0E0')))
    story.append(Spacer(1, 3*mm))
    
    # Add verification stamp if verified
    if submission_data.get('_verified'):
        verified_style = ParagraphStyle(
            'VerifiedStamp',
            fontSize=10,
            textColor=colors.HexColor('#059669'),
            alignment=TA_CENTER,
            fontName='Helvetica-Bold'
        )
        story.append(Paragraph("✓ VERIFIED", verified_style))
        story.append(Spacer(1, 2*mm))
    
    submitted_at = submission_data.get('_submitted_at', '')
    if submitted_at:
        try:
            dt = datetime.fromisoformat(submitted_at.replace('Z', '+00:00'))
            submitted_at = dt.strftime('%d/%m/%Y at %H:%M')
        except Exception:
            pass
    
    footer_text = f"Generated from Osabea Compliance Portal | Application submitted: {submitted_at}"
    story.append(Paragraph(footer_text, ParagraphStyle('Footer', fontSize=8, textColor=colors.HexColor('#888888'), alignment=TA_CENTER)))
    
    # Build PDF
    doc.build(story)
    
    buffer.seek(0)
    return buffer.getvalue()



