@api_router.get("/dashboard/stats", response_model=DashboardStats)
async def get_dashboard_stats(user: dict = Depends(require_manager_or_admin)):
    assignment_filter = {}
    if user['role'] == UserRole.BRANCH_MANAGER:
        assignment_filter = {"assignment": user.get('assignment')}
    
    # Get counts
    total_employees = await db.employees.count_documents({**assignment_filter, "status": {"$in": [EmployeeStatus.ACTIVE, EmployeeStatus.ONBOARDING]}})
    total_applicants = await db.employees.count_documents({**assignment_filter, "status": {"$in": [EmployeeStatus.NEW, EmployeeStatus.SCREENING, EmployeeStatus.INTERVIEW, EmployeeStatus.COMPLIANCE_REVIEW]}})
    onboarding = await db.employees.count_documents({**assignment_filter, "status": EmployeeStatus.ONBOARDING})
    
    # Count active employees — UCE promotion guarantees all compliance gates were passed
    fully_verified_count = await db.employees.count_documents(
        {**assignment_filter, "status": EmployeeStatus.ACTIVE}
    )
    
    # Get DBS document type
    dbs_type = await db.document_types.find_one({"name": {"$regex": "DBS", "$options": "i"}}, {"_id": 0})
    rtw_type = await db.document_types.find_one({"name": {"$regex": "Right to Work", "$options": "i"}}, {"_id": 0})
    ref_type = await db.document_types.find_one({"name": {"$regex": "Reference", "$options": "i"}}, {"_id": 0})
    
    # Count missing documents - use correct enum values
    # NOT_STARTED doesn't exist in DocumentStatus enum, use REQUESTED or null status
    missing_urgent = await db.employee_documents.count_documents({
        "status": {"$in": ["not_started", "requested", DocumentStatus.REQUESTED.value]}
    })
    # APPROVED doesn't exist in enum - use VERIFIED instead
    dbs_pending = await db.employee_documents.count_documents({
        "document_type_id": dbs_type['id'] if dbs_type else "", 
        "status": {"$ne": DocumentStatus.VERIFIED.value}
    }) if dbs_type else 0
    rtw_missing = await db.employee_documents.count_documents({
        "document_type_id": rtw_type['id'] if rtw_type else "", 
        "status": {"$ne": DocumentStatus.VERIFIED.value}
    }) if rtw_type else 0
    refs_outstanding = await db.employee_documents.count_documents({
        "document_type_id": ref_type['id'] if ref_type else "", 
        "status": {"$ne": DocumentStatus.VERIFIED.value}
    }) if ref_type else 0
    
    # Unsigned policies
    unsigned_policies = await db.policy_assignments.count_documents({"status": {"$ne": "signed"}})
    
    # Expiring documents
    now = datetime.now(timezone.utc)
    exp_14 = (now + timedelta(days=14)).isoformat()
    exp_30 = (now + timedelta(days=30)).isoformat()
    exp_60 = (now + timedelta(days=60)).isoformat()
    exp_90 = (now + timedelta(days=90)).isoformat()
    
    expiring_30 = await db.employee_documents.count_documents({"expiry_date": {"$lte": exp_30, "$gt": now.isoformat()}})
    expiring_60 = await db.employee_documents.count_documents({"expiry_date": {"$lte": exp_60, "$gt": exp_30}})
    expiring_90 = await db.employee_documents.count_documents({"expiry_date": {"$lte": exp_90, "$gt": exp_60}})
    
    # Training expiry counts
    training_exp_critical = await db.training_records.count_documents({
        "expiry_date": {"$lte": exp_14, "$gt": now.isoformat()},
        "record_status": {"$ne": "superseded"}
    })
    training_exp_warning = await db.training_records.count_documents({
        "expiry_date": {"$lte": exp_30, "$gt": exp_14},
        "record_status": {"$ne": "superseded"}
    })
    training_exp_upcoming = await db.training_records.count_documents({
        "expiry_date": {"$lte": exp_60, "$gt": exp_30},
        "record_status": {"$ne": "superseded"}
    })
    
    # ========== APPLICANT-SPECIFIC METRICS ==========
    # Get all applicants (includes all non-active statuses)
    all_applicants = await db.employees.find({
        **assignment_filter,
        "status": {"$in": [EmployeeStatus.NEW, EmployeeStatus.SCREENING, EmployeeStatus.INTERVIEW,
                         EmployeeStatus.COMPLIANCE_REVIEW, EmployeeStatus.ONBOARDING]}
    }, {"_id": 0, "id": 1, "status": 1, "first_name": 1, "last_name": 1}).to_list(500)
    
    # Pending verifications - documents from applicants waiting for admin review
    pending_verifications = 0
    applicants_stuck = 0  # <50% progress
    applicants_not_ready = 0  # Has blockers
    total_progress = 0
    
    for applicant in all_applicants:
        # Count pending verification documents for this applicant
        pending_docs = await db.employee_documents.count_documents({
            "employee_id": applicant["id"],
            "status": {"$in": ["uploaded", "pending", "active"]},
            "$or": [
                {"verification_stamp": {"$exists": False}},
                {"verification_stamp": None},
                {"verification_stamp": ""},
                {"verification_stamp": "not_verified"}
            ],
            "verified": {"$ne": True}
        })
        pending_verifications += pending_docs
        
        # Calculate progress for this applicant using unified progress
        try:
            progress_data = await compute_unified_progress_internal(applicant["id"], None)
            progress_pct = progress_data.get("overall_percentage", 0)
            blockers = progress_data.get("blockers", [])
            
            total_progress += progress_pct
            
            if progress_pct < 50:
                applicants_stuck += 1
            
            if len(blockers) > 0:
                applicants_not_ready += 1
        except Exception:
            applicants_not_ready += 1  # Assume not ready if can't calculate
    
    # Calculate average progress
    average_progress = (total_progress / len(all_applicants)) if all_applicants else 0
    
    return DashboardStats(
        total_employees=total_employees,
        total_applicants=total_applicants,
        fully_verified_employees=fully_verified_count,
        onboarding_in_progress=onboarding,
        missing_urgent_documents=missing_urgent,
        unsigned_policies=unsigned_policies,
        dbs_pending=dbs_pending,
        rtw_missing=rtw_missing,
        references_outstanding=refs_outstanding,
        expiring_30_days=expiring_30,
        expiring_60_days=expiring_60,
        expiring_90_days=expiring_90,
        training_expiring_critical=training_exp_critical,
        training_expiring_warning=training_exp_warning,
        training_expiring_upcoming=training_exp_upcoming,
        # Applicant-specific metrics
        pending_verifications=pending_verifications,
        applicants_stuck=applicants_stuck,
        applicants_not_ready=applicants_not_ready,
        average_onboarding_progress=round(average_progress, 1)
    )


