@api_router.get("/employees/{employee_id}/unified-progress")
async def get_unified_progress(employee_id: str, user: dict = Depends(get_current_user)):
    """
    Get unified progress for an employee - SINGLE SOURCE OF TRUTH.
    
    P0 FIX: Now uses get_unified_employee_status() from unified_compliance_engine.
    ALL views (Admin, Worker, Audit) use this SAME function.
    
    Standards:
    - CIA Triad: Integrity (same data for all views)
    - 5 E's: Effective, Easy to Learn (clear labels)
    - NHS Level: Complete employment checks
    - CQC Level: Audit-ready with verifier names
    """
    # P0 FIX: SINGLE SOURCE OF TRUTH - unified_compliance_engine
    unified_status = await get_unified_employee_status(employee_id, db, user_role="admin", include_details=True)
    
    if unified_status.get("error"):
        raise HTTPException(status_code=404, detail=unified_status["error"])
    
    # Determine professional registration requirements from role
    role = unified_status.get("role", "").lower()
    requires_prof_reg = False
    prof_reg_type = None
    if "nurse" in role or "midwife" in role:
        requires_prof_reg = True
        prof_reg_type = "NMC"
    elif "doctor" in role or "physician" in role:
        requires_prof_reg = True
        prof_reg_type = "GMC"
    elif "physio" in role or "paramedic" in role:
        requires_prof_reg = True
        prof_reg_type = "HCPC"
    
    return {
        "employee_id": employee_id,
        "overall_percentage": unified_status["progress"]["percentage"],
        "completed_requirements": unified_status["progress"]["completed"],
        "total_requirements": unified_status["progress"]["total"],
        "categories": unified_status["categories"],
        "category_details": unified_status.get("category_details", {}),  # Include full details
        "blockers": [b["reason"] for b in unified_status["blockers"]],  # String list for compatibility
        "blocker_details": unified_status["blockers"],  # Full blocker objects with severity
        "is_work_ready": unified_status["is_work_ready"],
        "can_promote": unified_status["can_promote"],
        "role_requires_professional_registration": requires_prof_reg,
        "professional_registration_type": prof_reg_type,
        "checks": unified_status["checks"],
    }


@api_router.get("/compliance/centre-summary")
async def get_compliance_centre_summary(user: dict = Depends(get_current_user)):
    """
    Enhanced Compliance Centre summary for CQC audit readiness.
    Returns summary counts for policies, certificates, and staff compliance.
    """
    now = datetime.now(timezone.utc)
    thirty_days = timedelta(days=30)
    exp_30 = (now + thirty_days).isoformat()
    
    # === POLICIES SUMMARY ===
    policies = await db.org_policies.find({}, {"_id": 0}).to_list(200)
    policies_total = len(policies)
    policies_active = 0
    policies_missing = 0
    policies_due_soon = 0
    policies_overdue = 0
    policies_required_complete = 0
    policies_required_total = 0
    missing_required_policies = []
    
    for policy in policies:
        is_required = policy.get("required", True)
        if is_required:
            policies_required_total += 1
        
        if policy.get("status") == "missing":
            policies_missing += 1
            if is_required:
                missing_required_policies.append({
                    "id": policy["id"],
                    "name": policy["name"],
                    "category": policy.get("category"),
                    "required": is_required,
                    "conditional": policy.get("conditional", False)
                })
        elif policy.get("status") == "active":
            policies_active += 1
            if is_required:
                policies_required_complete += 1
        
        # Check review date
        if policy.get("review_date"):
            try:
                review_str = policy["review_date"]
                if 'T' in str(review_str):
                    review_date = datetime.fromisoformat(review_str.replace('Z', '+00:00'))
                else:
                    review_date = datetime.fromisoformat(f"{review_str}T00:00:00+00:00")
                
                if review_date < now:
                    policies_overdue += 1
                elif review_date < now + thirty_days:
                    policies_due_soon += 1
            except Exception:
                pass
    
    # === CERTIFICATES SUMMARY ===
    certificates = await db.insurance_docs.find({}, {"_id": 0}).to_list(100)
    certs_total = len(certificates)
    certs_valid = 0
    certs_missing = 0
    certs_expiring = 0
    certs_expired = 0
    certs_required_complete = 0
    certs_required_total = 0
    missing_required_certs = []
    
    for cert in certificates:
        is_required = cert.get("required", True)
        if is_required:
            certs_required_total += 1
        
        status = cert.get("status", "missing")
        
        # Recalculate status based on expiry date
        if cert.get("expiry_date"):
            try:
                exp_str = cert["expiry_date"]
                if 'T' in str(exp_str):
                    exp_date = datetime.fromisoformat(exp_str.replace('Z', '+00:00'))
                else:
                    exp_date = datetime.fromisoformat(f"{exp_str}T00:00:00+00:00")
                
                if exp_date < now:
                    status = "expired"
                elif exp_date < now + thirty_days:
                    status = "expiring_soon"
                elif cert.get("file_url"):
                    status = "valid"
            except Exception:
                pass
        elif cert.get("file_url"):
            status = "valid"  # Has file but no expiry date
        
        if status == "missing":
            certs_missing += 1
            if is_required:
                missing_required_certs.append({
                    "id": cert["id"],
                    "name": cert["name"],
                    "type": cert.get("insurance_type"),
                    "category": cert.get("category", "insurance"),
                    "required": is_required,
                    "conditional": cert.get("conditional", False)
                })
        elif status == "valid":
            certs_valid += 1
            if is_required:
                certs_required_complete += 1
        elif status == "expiring_soon":
            certs_expiring += 1
            if is_required:
                certs_required_complete += 1  # Still counts as complete
        elif status == "expired":
            certs_expired += 1
    
    # === STAFF COMPLIANCE SUMMARY ===
    employees = await db.employees.find(
        {"status": {"$ne": "archived"}},
        {"_id": 0, "id": 1, "first_name": 1, "last_name": 1}
    ).to_list(1000)
    
    staff_total = len(employees)
    staff_compliant = 0
    staff_with_issues = 0
    
    # DBS Register status
    dbs_valid = 0
    dbs_missing = 0
    dbs_expiring = 0
    
    # Training in last 12 months
    twelve_months_ago = (now - timedelta(days=365)).isoformat()
    training_completed_recently = 0
    
    for emp in employees:
        emp_id = emp["id"]
        
        # Check DBS status
        dbs_doc = await db.employee_documents.find_one({
            "employee_id": emp_id,
            "requirement_id": {"$in": ["dbs_certificate", "dbs_check"]}
        }, {"_id": 0, "expiry_date": 1})
        
        if dbs_doc:
            if dbs_doc.get("expiry_date"):
                try:
                    exp_str = dbs_doc["expiry_date"]
                    if 'T' in str(exp_str):
                        exp_date = datetime.fromisoformat(exp_str.replace('Z', '+00:00'))
                    else:
                        exp_date = datetime.fromisoformat(f"{exp_str}T00:00:00+00:00")
                    
                    if exp_date < now:
                        dbs_missing += 1  # Expired counts as missing
                    elif exp_date < now + thirty_days:
                        dbs_expiring += 1
                    else:
                        dbs_valid += 1
                except Exception:
                    dbs_valid += 1
            else:
                dbs_valid += 1
        else:
            dbs_missing += 1
        
        # Check recent training
        recent_training = await db.training_records.count_documents({
            "employee_id": emp_id,
            "completion_date": {"$gte": twelve_months_ago}
        })
        if recent_training > 0:
            training_completed_recently += 1
    
    # Calculate overall status
    policies_ok = policies_missing == 0 and policies_overdue == 0
    certs_ok = certs_missing == 0 and certs_expired == 0
    staff_ok = dbs_missing == 0
    
    if policies_ok and certs_ok and staff_ok:
        overall_status = "OK"
    elif (policies_missing > 5 or certs_missing > 3 or dbs_missing > (staff_total * 0.2)):
        overall_status = "Critical"
    else:
        overall_status = "Needs Attention"
    
    return {
        "overall_status": overall_status,
        "policies": {
            "complete": policies_active,
            "total": policies_total,
            "missing": policies_missing,
            "due_soon": policies_due_soon,
            "overdue": policies_overdue,
            "required_complete": policies_required_complete,
            "required_total": policies_required_total
        },
        "certificates": {
            "valid": certs_valid,
            "total": certs_total,
            "missing": certs_missing,
            "expiring": certs_expiring,
            "expired": certs_expired,
            "required_complete": certs_required_complete,
            "required_total": certs_required_total
        },
        "staff_compliance": {
            "total": staff_total,
            "dbs_valid": dbs_valid,
            "dbs_missing": dbs_missing,
            "dbs_expiring": dbs_expiring,
            "training_last_12_months": training_completed_recently
        },
        "missing_items": {
            "required_policies": missing_required_policies[:10],
            "required_certificates": missing_required_certs[:10],
            "has_more_policies": len(missing_required_policies) > 10,
            "has_more_certificates": len(missing_required_certs) > 10
        }
    }





# ==================== CQC INSPECTION DASHBOARD ====================

@api_router.get("/cqc/inspection-dashboard")
async def get_cqc_inspection_dashboard(user: dict = Depends(require_manager_or_admin)):
    """
    CQC Inspection Dashboard - Audit-ready compliance overview.
    
    Returns:
    - Overall summary stats
    - CQC 5 Key Questions assessment (Safe, Effective, Caring, Responsive, Well-led)
    - Staff breakdown by role and compliance status
    - Expiring documents in next 30 days
    - Training compliance gaps
    - Priority risk areas
    """
    now = datetime.now(timezone.utc)
    thirty_days = timedelta(days=30)
    
    # ========== SUMMARY STATS ==========
    total_staff = await db.employees.count_documents({
        "status": {"$in": [EmployeeStatus.ACTIVE, EmployeeStatus.ONBOARDING]}
    })
    
    # Count work-ready staff (those with start_status complete)
    work_ready_count = 0
    onboarding_count = 0
    critical_issues = 0
    
    all_employees = await db.employees.find(
        {"status": {"$in": [EmployeeStatus.ACTIVE, EmployeeStatus.ONBOARDING]}},
        {"_id": 0, "id": 1, "role": 1, "first_name": 1, "last_name": 1, "status": 1}
    ).to_list(1000)
    
    for emp in all_employees:
        try:
            compliance = await calculate_employee_compliance(emp["id"], emp.get("role", ""))
            work_readiness = compliance.get("work_readiness_3tier", {})
            
            if work_readiness.get("status") == "READY_TO_WORK":
                work_ready_count += 1
            elif work_readiness.get("status") == "SUPERVISED_START":
                onboarding_count += 1
            else:
                onboarding_count += 1
            
            # Count critical blockers
            blockers = work_readiness.get("blockers_for_next_tier", [])
            critical_blockers = [b for b in blockers if b.get("priority") == "start_required"]
            if critical_blockers:
                critical_issues += len(critical_blockers)
        except Exception:
            onboarding_count += 1
    
    summary = {
        "total_staff": total_staff,
        "work_ready": work_ready_count,
        "work_ready_percentage": round((work_ready_count / total_staff * 100) if total_staff > 0 else 0, 1),
        "onboarding": onboarding_count,
        "critical_issues": critical_issues
    }
    
    # ========== CQC 5 KEY QUESTIONS ==========
    # Calculate scores for each domain based on compliance data
    
    # SAFE: DBS, RTW, Safeguarding, Identity verification
    safe_items = ["dbs_certificate", "right_to_work", "safeguarding", "identity_verification", "proof_of_address"]
    safe_complete = 0
    safe_total = 0
    
    # EFFECTIVE: Training, References, Competency
    effective_items = ["manual_handling", "infection_control", "basic_life_support", "reference_1", "reference_2", "cv"]
    effective_complete = 0
    effective_total = 0
    
    # CARING: Health questionnaire, Induction
    caring_items = ["staff_health_questionnaire", "induction"]
    caring_complete = 0
    caring_total = 0
    
    # RESPONSIVE: Employment history, Interview, References
    responsive_items = ["employment_history", "interview", "reference_1"]
    responsive_complete = 0
    responsive_total = 0
    
    # WELL-LED: Policies, Agreements, Contract
    wellled_items = ["contract_acknowledgement", "whistleblowing_policy", "conflict_of_interest"]
    wellled_complete = 0
    wellled_total = 0
    
    # Sample 50 employees for domain scoring (performance optimization)
    sample_employees = all_employees[:50]
    
    for emp in sample_employees:
        try:
            compliance = await calculate_employee_compliance(emp["id"], emp.get("role", ""))
            requirements = compliance.get("requirements", [])
            req_map = {r["id"]: r for r in requirements}
            
            for item in safe_items:
                if item in req_map:
                    safe_total += 1
                    if req_map[item].get("has_evidence"):
                        safe_complete += 1
            
            for item in effective_items:
                if item in req_map:
                    effective_total += 1
                    if req_map[item].get("has_evidence"):
                        effective_complete += 1
            
            for item in caring_items:
                if item in req_map:
                    caring_total += 1
                    if req_map[item].get("has_evidence"):
                        caring_complete += 1
            
            for item in responsive_items:
                if item in req_map:
                    responsive_total += 1
                    if req_map[item].get("has_evidence"):
                        responsive_complete += 1
            
            for item in wellled_items:
                if item in req_map:
                    wellled_total += 1
                    if req_map[item].get("has_evidence"):
                        wellled_complete += 1
        except Exception:
            pass
    
    def calc_score(complete, total):
        return round((complete / total * 100) if total > 0 else 0, 1)
    
    def get_risk_level(score):
        if score >= 80:
            return "low"
        elif score >= 60:
            return "medium"
        else:
            return "high"
    
    cqc_domains = [
        {
            "name": "Safe",
            "score": calc_score(safe_complete, safe_total),
            "risk_level": get_risk_level(calc_score(safe_complete, safe_total)),
            "summary": f"DBS, RTW, Identity & Safeguarding checks"
        },
        {
            "name": "Effective",
            "score": calc_score(effective_complete, effective_total),
            "risk_level": get_risk_level(calc_score(effective_complete, effective_total)),
            "summary": f"Training, References & Competency evidence"
        },
        {
            "name": "Caring",
            "score": calc_score(caring_complete, caring_total),
            "risk_level": get_risk_level(calc_score(caring_complete, caring_total)),
            "summary": f"Health declarations & Induction records"
        },
        {
            "name": "Responsive",
            "score": calc_score(responsive_complete, responsive_total),
            "risk_level": get_risk_level(calc_score(responsive_complete, responsive_total)),
            "summary": f"Employment history & Interview records"
        },
        {
            "name": "Well-led",
            "score": calc_score(wellled_complete, wellled_total),
            "risk_level": get_risk_level(calc_score(wellled_complete, wellled_total)),
            "summary": f"Contracts, Policies & Declarations"
        }
    ]
    
    # ========== STAFF BREAKDOWN BY ROLE ==========
    role_counts = {}
    role_compliant = {}
    
    for emp in all_employees:
        role = emp.get("role", "Unknown")
        role_counts[role] = role_counts.get(role, 0) + 1
        
        try:
            compliance = await calculate_employee_compliance(emp["id"], role)
            work_readiness = compliance.get("work_readiness_3tier", {})
            if work_readiness.get("status") == "READY_TO_WORK":
                role_compliant[role] = role_compliant.get(role, 0) + 1
        except Exception:
            pass
    
    staff_breakdown = [
        {
            "role": role,
            "total": count,
            "compliant": role_compliant.get(role, 0)
        }
        for role, count in sorted(role_counts.items(), key=lambda x: x[1], reverse=True)[:10]
    ]
    
    # ========== EXPIRING DOCUMENTS ==========
    exp_30 = (now + thirty_days).isoformat()
    expiring_docs = await db.employee_documents.find(
        {
            "expiry_date": {"$lte": exp_30, "$gt": now.isoformat()},
            "status": {"$ne": DocumentStatus.SUPERSEDED.value}
        },
        {"_id": 0, "employee_id": 1, "requirement_id": 1, "expiry_date": 1}
    ).to_list(50)
    
    expiring_documents = []
    for doc in expiring_docs:
        emp = await db.employees.find_one({"id": doc["employee_id"]}, {"_id": 0, "first_name": 1, "last_name": 1})
        if emp:
            try:
                exp_date = datetime.fromisoformat(doc["expiry_date"].replace('Z', '+00:00'))
                days_until = (exp_date - now).days
            except Exception:
                days_until = 30
            
            expiring_documents.append({
                "employee_name": f"{emp.get('first_name', '')} {emp.get('last_name', '')}".strip(),
                "document_type": doc.get("requirement_id", "Document"),
                "days_until_expiry": max(0, days_until)
            })
    
    expiring_documents.sort(key=lambda x: x["days_until_expiry"])
    
    # ========== TRAINING GAPS ==========
    training_names = ["Safeguarding", "Manual Handling", "Infection Control", "Basic Life Support", "Fire Safety", "PREVENT"]
    training_gaps = []
    
    for training_name in training_names:
        # Count how many staff have this training
        records = await db.training_records.find(
            {"training_name": {"$regex": training_name, "$options": "i"}, "status": "completed"},
            {"_id": 0, "employee_id": 1}
        ).to_list(1000)
        
        trained_employee_ids = set(r["employee_id"] for r in records)
        missing_count = total_staff - len(trained_employee_ids)
        compliance_rate = round((len(trained_employee_ids) / total_staff * 100) if total_staff > 0 else 0, 1)
        
        if missing_count > 0:
            training_gaps.append({
                "training_name": training_name,
                "missing_count": missing_count,
                "compliance_rate": compliance_rate
            })
    
    training_gaps.sort(key=lambda x: x["compliance_rate"])
    
    # ========== PRIORITY RISK AREAS ==========
    risk_areas = []
    
    # Check for expired DBS
    expired_dbs = await db.employee_documents.count_documents({
        "requirement_id": "dbs_certificate",
        "expiry_date": {"$lt": now.isoformat()},
        "status": {"$ne": DocumentStatus.SUPERSEDED.value}
    })
    if expired_dbs > 0:
        risk_areas.append({
            "title": "Expired DBS Certificates",
            "description": "Staff with expired DBS checks require immediate renewal",
            "severity": "high",
            "affected_count": expired_dbs
        })
    
    # Check for missing Right to Work
    missing_rtw = await db.employee_documents.count_documents({
        "requirement_id": "right_to_work",
        "status": {"$in": [DocumentStatus.REQUESTED.value, "pending"]}
    })
    if missing_rtw > 0:
        risk_areas.append({
            "title": "Missing Right to Work",
            "description": "Staff without verified Right to Work documentation",
            "severity": "high",
            "affected_count": missing_rtw
        })
    
    # Check for training gaps > 20%
    for gap in training_gaps:
        if gap["compliance_rate"] < 80:
            risk_areas.append({
                "title": f"Low {gap['training_name']} Compliance",
                "description": f"Only {gap['compliance_rate']}% of staff have completed this mandatory training",
                "severity": "medium" if gap["compliance_rate"] >= 60 else "high",
                "affected_count": gap["missing_count"]
            })
    
    risk_areas.sort(key=lambda x: 0 if x["severity"] == "high" else 1)
    
    return {
        "summary": summary,
        "cqc_domains": cqc_domains,
        "staff_breakdown": staff_breakdown,
        "expiring_documents": expiring_documents[:20],
        "training_gaps": training_gaps[:6],
        "risk_areas": risk_areas[:6],
        "generated_at": now.isoformat()
    }


@api_router.get("/cqc/inspection-report/pdf")
async def export_cqc_inspection_report_pdf(user: dict = Depends(require_manager_or_admin)):
    """
    Export CQC Inspection Dashboard as PDF report.
    """
    # Get dashboard data
    dashboard = await get_cqc_inspection_dashboard(user)
    
    # Create PDF
    buffer = io.BytesIO()
    doc = SimpleDocTemplate(buffer, pagesize=A4, topMargin=30, bottomMargin=30)
    styles = getSampleStyleSheet()
    story = []
    
    # Title
    title_style = ParagraphStyle('Title', parent=styles['Title'], fontSize=24, spaceAfter=20)
    story.append(Paragraph("CQC Inspection Readiness Report", title_style))
    story.append(Paragraph(f"Generated: {datetime.now().strftime('%d %B %Y at %H:%M')}", styles['Normal']))
    story.append(Spacer(1, 20))
    
    # Summary Section
    story.append(Paragraph("Executive Summary", styles['Heading2']))
    summary = dashboard["summary"]
    summary_data = [
        ["Total Staff", str(summary["total_staff"])],
        ["Work Ready", f"{summary['work_ready']} ({summary['work_ready_percentage']}%)"],
        ["In Onboarding", str(summary["onboarding"])],
        ["Critical Issues", str(summary["critical_issues"])]
    ]
    summary_table = Table(summary_data, colWidths=[200, 200])
    summary_table.setStyle(TableStyle([
        ('BACKGROUND', (0, 0), (0, -1), colors.lightgrey),
        ('GRID', (0, 0), (-1, -1), 1, colors.grey),
        ('PADDING', (0, 0), (-1, -1), 8),
    ]))
    story.append(summary_table)
    story.append(Spacer(1, 20))
    
    # CQC 5 Key Questions
    story.append(Paragraph("CQC 5 Key Questions Assessment", styles['Heading2']))
    cqc_data = [["Domain", "Score", "Risk Level", "Summary"]]
    for domain in dashboard["cqc_domains"]:
        cqc_data.append([
            domain["name"],
            f"{domain['score']}%",
            domain["risk_level"].upper(),
            domain["summary"]
        ])
    cqc_table = Table(cqc_data, colWidths=[80, 60, 80, 260])
    cqc_table.setStyle(TableStyle([
        ('BACKGROUND', (0, 0), (-1, 0), colors.HexColor('#1e40af')),
        ('TEXTCOLOR', (0, 0), (-1, 0), colors.white),
        ('GRID', (0, 0), (-1, -1), 1, colors.grey),
        ('PADDING', (0, 0), (-1, -1), 6),
        ('FONTSIZE', (0, 0), (-1, -1), 9),
    ]))
    story.append(cqc_table)
    story.append(Spacer(1, 20))
    
    # Risk Areas
    if dashboard["risk_areas"]:
        story.append(Paragraph("Priority Risk Areas", styles['Heading2']))
        for area in dashboard["risk_areas"]:
            risk_text = f"<b>{area['title']}</b> ({area['severity'].upper()}) - {area['affected_count']} affected"
            story.append(Paragraph(risk_text, styles['Normal']))
            story.append(Paragraph(area['description'], styles['Normal']))
            story.append(Spacer(1, 10))
    
    # Build PDF
    doc.build(story)
    buffer.seek(0)
    
    return StreamingResponse(
        buffer,
        media_type="application/pdf",
        headers={"Content-Disposition": f"attachment; filename=CQC_Inspection_Report_{datetime.now().strftime('%Y%m%d')}.pdf"}
    )


@api_router.get("/compliance/cqc-evidence-map")
async def get_cqc_evidence_map(user: dict = Depends(get_current_user)):
    """
    CQC Evidence Mapping - Read-only view of existing evidence mapped to CQC 5 Key Questions.
    
    This is a VISIBILITY LAYER ONLY:
    - Does NOT change employee compliance calculations
    - Does NOT change progress %
    - Does NOT change Ready to Work status
    - Does NOT create a second compliance engine
    
    Maps existing system data (policies, certificates, forms, registers, reports) to:
    - Safe
    - Effective
    - Caring
    - Responsive
    - Well-led
    """
    now = datetime.now(timezone.utc)
    thirty_days = timedelta(days=30)
    
    # Fetch all source data
    policies = await db.org_policies.find({}, {"_id": 0}).to_list(200)
    policies_map = {p["name"]: p for p in policies}
    
    certificates = await db.insurance_docs.find({}, {"_id": 0}).to_list(100)
    certs_map = {c["insurance_type"]: c for c in certificates}
    
    # Get form submission counts
    form_counts = {}
    for form_type in ["health_screening", "induction", "recruitment_checklist", "interview_record", "equal_opportunities"]:
        count = await db.form_submissions.count_documents({"requirement_id": form_type})
        form_counts[form_type] = count
    
    # Get incident counts
    incident_count = await db.incident_logs.count_documents({})
    open_incidents = await db.incident_logs.count_documents({"status": {"$in": ["open", "under_investigation"]}})
    
    # Get staff counts
    total_staff = await db.employees.count_documents({"status": {"$ne": "archived"}})
    
    # Get DBS summary
    dbs_valid = 0
    dbs_missing = 0
    employees = await db.employees.find({"status": {"$ne": "archived"}}, {"_id": 0, "id": 1}).to_list(1000)
    for emp in employees:
        dbs_doc = await db.employee_documents.find_one({
            "employee_id": emp["id"],
            "requirement_id": {"$in": ["dbs_certificate", "dbs_check"]}
        })
        if dbs_doc:
            dbs_valid += 1
        else:
            dbs_missing += 1
    
    # Get RTW summary
    rtw_approved = 0
    for emp in employees:
        rtw_docs = await db.employee_documents.count_documents({
            "employee_id": emp["id"],
            "requirement_id": {"$in": ["right_to_work_documents", "right_to_work_check"]}
        })
        if rtw_docs > 0:
            rtw_approved += 1
    
    # Get training summary
    training_count = await db.training_records.count_documents({})
    twelve_months_ago = (now - timedelta(days=365)).isoformat()
    recent_training = await db.training_records.count_documents({"completion_date": {"$gte": twelve_months_ago}})
    
    # Get policy review stats
    policies_due_review = 0
    policies_overdue = 0
    for p in policies:
        if p.get("review_date"):
            try:
                review_str = p["review_date"]
                if 'T' in str(review_str):
                    review_date = datetime.fromisoformat(review_str.replace('Z', '+00:00'))
                else:
                    review_date = datetime.fromisoformat(f"{review_str}T00:00:00+00:00")
                
                if review_date < now:
                    policies_overdue += 1
                elif review_date < now + thirty_days:
                    policies_due_review += 1
            except Exception:
                pass
    
    # Get audit trail count
    audit_count = await db.audit_log.count_documents({})
    
    # Helper to determine item status
    def get_item_status(item):
        source_type = item["source_type"]
        source_id = item["source_id"]
        status = "missing"
        details = None
        link = None
        review_date = None
        expiry_date = None
        
        if source_type == "policy":
            policy = policies_map.get(source_id)
            if policy:
                if policy.get("status") == "active":
                    status = "present"
                    if policy.get("review_date"):
                        try:
                            review_str = policy["review_date"]
                            if 'T' in str(review_str):
                                rev_date = datetime.fromisoformat(review_str.replace('Z', '+00:00'))
                            else:
                                rev_date = datetime.fromisoformat(f"{review_str}T00:00:00+00:00")
                            review_date = policy["review_date"]
                            if rev_date < now:
                                status = "overdue"
                            elif rev_date < now + thirty_days:
                                status = "due_review"
                        except Exception:
                            pass
                elif policy.get("status") == "expired":
                    status = "expired"
                link = f"/portal/compliance-centre?tab=policies&policy={policy.get('id')}"
                details = f"Version {policy.get('version', 'N/A')}"
            else:
                status = "missing"
        
        elif source_type == "certificate":
            cert = certs_map.get(source_id)
            if cert:
                if cert.get("file_url"):
                    if cert.get("expiry_date"):
                        try:
                            exp_str = cert["expiry_date"]
                            if 'T' in str(exp_str):
                                exp_date = datetime.fromisoformat(exp_str.replace('Z', '+00:00'))
                            else:
                                exp_date = datetime.fromisoformat(f"{exp_str}T00:00:00+00:00")
                            expiry_date = cert["expiry_date"]
                            if exp_date < now:
                                status = "expired"
                            elif exp_date < now + thirty_days:
                                status = "expiring"
                            else:
                                status = "present"
                        except Exception:
                            status = "present"
                    else:
                        status = "present"
                    details = cert.get("provider")
                else:
                    status = "missing"
                link = f"/portal/compliance-centre?tab=certificates&cert={cert.get('id')}"
            elif item.get("conditional"):
                status = "n/a"
                details = "Conditional - may not apply"
            else:
                status = "missing"
        
        elif source_type == "form":
            count = form_counts.get(source_id, 0)
            if count > 0:
                status = "present"
                details = f"{count} submissions"
            else:
                status = "missing"
            link = "/portal/employees"
        
        elif source_type == "register":
            if source_id == "dbs_register":
                if dbs_valid > 0:
                    status = "present"
                    details = f"{dbs_valid}/{total_staff} staff with valid DBS"
                    if dbs_missing > 0:
                        status = "partial"
                else:
                    status = "missing"
                link = "/portal/compliance-centre?tab=staff"
            elif source_id == "rtw_register":
                if rtw_approved > 0:
                    status = "present"
                    details = f"{rtw_approved}/{total_staff} staff with RTW verified"
                else:
                    status = "missing"
                link = "/portal/employees"
            elif source_id == "training_matrix":
                if training_count > 0:
                    status = "present"
                    details = f"{training_count} training records"
                else:
                    status = "missing"
                link = "/portal/compliance-centre?tab=reports"
            elif source_id == "training_records":
                if recent_training > 0:
                    status = "present"
                    details = f"{recent_training} in last 12 months"
                else:
                    status = "missing"
                link = "/portal/compliance-centre?tab=reports"
        
        elif source_type == "report":
            if source_id == "incidents":
                if incident_count > 0:
                    status = "present"
                    details = f"{incident_count} logged, {open_incidents} open"
                else:
                    status = "n/a"
                    details = "No incidents logged"
                link = "/portal/compliance-centre?tab=incidents"
            elif source_id == "complaints":
                # Complaints tracked via incidents with type
                complaint_count = 0  # Would need specific query
                status = "n/a"
                details = "Track via Incident Logs"
                link = "/portal/compliance-centre?tab=incidents"
            elif source_id == "audit_trail":
                if audit_count > 0:
                    status = "present"
                    details = f"{audit_count} audit entries"
                else:
                    status = "present"
                    details = "Audit trail active"
                link = "/portal/compliance-centre"
            elif source_id == "policy_reviews":
                status = "present"
                details = f"{policies_due_review} due soon, {policies_overdue} overdue"
                link = "/portal/compliance-centre?tab=policies"
        
        elif source_type == "training":
            # Training types - check if any staff have this training
            status = "n/a"
            details = "Check training records"
            link = "/portal/compliance-centre?tab=reports"
        
        return {
            "name": item["name"],
            "source_type": source_type,
            "status": status,
            "details": details,
            "link": link,
            "review_date": review_date,
            "expiry_date": expiry_date,
            "conditional": item.get("conditional", False)
        }
    
    # Build response
    result = {}
    summary = {
        "total_items": 0,
        "present": 0,
        "missing": 0,
        "due_review": 0,
        "expired": 0,
        "partial": 0,
        "n_a": 0
    }
    
    for key, category in CQC_EVIDENCE_MAPPING.items():
        items = []
        category_summary = {"present": 0, "missing": 0, "due_review": 0, "expired": 0, "partial": 0, "n_a": 0}
        
        for item in category["items"]:
            item_status = get_item_status(item)
            items.append(item_status)
            
            # Update counts
            status = item_status["status"]
            if status in category_summary:
                category_summary[status] += 1
            elif status == "expiring":
                category_summary["due_review"] += 1
            elif status == "overdue":
                category_summary["expired"] += 1
            
            summary["total_items"] += 1
            if status == "present":
                summary["present"] += 1
            elif status == "missing":
                summary["missing"] += 1
            elif status in ["due_review", "expiring"]:
                summary["due_review"] += 1
            elif status in ["expired", "overdue"]:
                summary["expired"] += 1
            elif status == "partial":
                summary["partial"] += 1
            elif status == "n/a":
                summary["n_a"] += 1
        
        result[key] = {
            "title": category["title"],
            "description": category["description"],
            "items": items,
            "summary": category_summary
        }
    
    return {
        "cqc_mapping": result,
        "summary": summary,
        "generated_at": now.isoformat(),
        "note": "This is a read-only evidence mapping view. It does NOT affect employee compliance calculations, progress %, or Ready to Work status."
    }




@api_router.get("/dashboard/expiry-alerts")
async def get_expiry_alerts_dashboard(user: dict = Depends(get_current_user)):
    """
    Get dashboard view of all expiring and expired compliance items across all employees.
    Returns employees grouped by alert severity.
    """
    now = datetime.now(timezone.utc)
    warning_threshold = now + timedelta(days=EXPIRY_WARNING_DAYS)
    
    # Get all non-archived employees
    employees = await db.employees.find(
        {"status": {"$ne": "archived"}},
        {"_id": 0, "id": 1, "first_name": 1, "last_name": 1, "role": 1}
    ).to_list(1000)
    
    employees_with_expired = []
    employees_expiring_soon = []
    
    for emp in employees:
        emp_id = emp['id']
        emp_name = f"{emp['first_name']} {emp['last_name']}"
        role = emp.get('role', '')
        
        expired_items = []
        expiring_items = []
        
        # Check documents
        docs = await db.employee_documents.find({
            "employee_id": emp_id,
            "expiry_date": {"$exists": True, "$ne": None}
        }, {"_id": 0, "requirement_id": 1, "document_label": 1, "expiry_date": 1}).to_list(100)
        
        for doc in docs:
            expiry_status = calculate_expiry_status(doc.get('expiry_date'))
            if expiry_status:
                item_info = {
                    "requirement_id": doc.get('requirement_id'),
                    "name": doc.get('document_label', 'Document'),
                    "expiry_date": expiry_status.get('expiry_date'),
                    "days": expiry_status.get('days_until_expiry')
                }
                if expiry_status['status'] == 'expired':
                    expired_items.append(item_info)
                elif expiry_status['status'] == 'expiring_soon':
                    expiring_items.append(item_info)
        
        # Check training records
        training = await db.training_records.find({
            "employee_id": emp_id,
            "expiry_date": {"$exists": True, "$ne": None}
        }, {"_id": 0, "requirement_id": 1, "training_name": 1, "expiry_date": 1}).to_list(100)
        
        for t in training:
            expiry_status = calculate_expiry_status(t.get('expiry_date'))
            if expiry_status:
                item_info = {
                    "requirement_id": t.get('requirement_id'),
                    "name": t.get('training_name', 'Training'),
                    "expiry_date": expiry_status.get('expiry_date'),
                    "days": expiry_status.get('days_until_expiry')
                }
                if expiry_status['status'] == 'expired':
                    expired_items.append(item_info)
                elif expiry_status['status'] == 'expiring_soon':
                    expiring_items.append(item_info)
        
        if expired_items:
            employees_with_expired.append({
                "employee_id": emp_id,
                "employee_name": emp_name,
                "role": role,
                "expired_items": expired_items,
                "expired_count": len(expired_items)
            })
        
        if expiring_items:
            employees_expiring_soon.append({
                "employee_id": emp_id,
                "employee_name": emp_name,
                "role": role,
                "expiring_items": expiring_items,
                "expiring_count": len(expiring_items)
            })
    
    # Sort by count (most urgent first)
    employees_with_expired.sort(key=lambda x: x['expired_count'], reverse=True)
    employees_expiring_soon.sort(key=lambda x: x['expiring_count'], reverse=True)
    
    return {
        "expired": {
            "employees": employees_with_expired,
            "total_employees": len(employees_with_expired),
            "total_items": sum(e['expired_count'] for e in employees_with_expired)
        },
        "expiring_soon": {
            "employees": employees_expiring_soon,
            "total_employees": len(employees_expiring_soon),
            "total_items": sum(e['expiring_count'] for e in employees_expiring_soon)
        },
        "has_alerts": len(employees_with_expired) > 0 or len(employees_expiring_soon) > 0
    }

# ==================== AUDIT LOG ROUTES ====================

async def log_audit_action(user_id: str, action: str, entity_type: str, entity_id: str, metadata: dict):
    """
    Log an audit action with optional employee_id extraction from metadata.
    CQC Regulation 17: All actions must be logged with timestamp and user.
    """
    # Get user info for better audit trail
    user_info = await db.users.find_one(
        {"$or": [{"user_id": user_id}, {"id": user_id}]},
        {"_id": 0, "name": 1, "email": 1}
    )
    user_name = user_info.get("name", user_info.get("email", "Unknown")) if user_info else "System"
    
    audit_doc = {
        "id": str(uuid.uuid4()),
        "user_id": user_id,
        "user_name": user_name,
        "action": action,
        "entity_type": entity_type,
        "entity_id": entity_id,
        "metadata": metadata,
        # Extract employee_id from metadata if present for easier querying
        "employee_id": metadata.get("employee_id") if metadata else None,
        "timestamp": datetime.now(timezone.utc).isoformat(),
        "created_at": datetime.now(timezone.utc).isoformat()
    }
    await db.audit_logs.insert_one(audit_doc)


async def log_audit_change(
    user_id: str, 
    action: str, 
    entity_type: str, 
    entity_id: str, 
    field_name: str,
    old_value: any,
    new_value: any,
    reason: str,
    metadata: dict = None
):
    """
    Enhanced audit logging for CQC compliance.
    Captures before/after values and mandatory reason for change.
    """
    # Get user info for better audit trail
    user_info = await db.users.find_one(
        {"$or": [{"user_id": user_id}, {"id": user_id}]},
        {"_id": 0, "name": 1, "email": 1}
    )
    user_name = user_info.get("name", user_info.get("email", "Unknown")) if user_info else "System"
    
    audit_doc = {
        "id": str(uuid.uuid4()),
        "user_id": user_id,
        "user_name": user_name,
        "action": action,
        "entity_type": entity_type,
        "entity_id": entity_id,
        "field_name": field_name,
        "details": {
            "before": str(old_value) if old_value is not None else None,
            "after": str(new_value) if new_value is not None else None,
            "reason": reason
        },
        "metadata": metadata or {},
        # Extract employee_id from metadata if present
        "employee_id": metadata.get("employee_id") if metadata else None,
        "timestamp": datetime.now(timezone.utc).isoformat(),
        "created_at": datetime.now(timezone.utc).isoformat()
    }
    await db.audit_logs.insert_one(audit_doc)
    return audit_doc



