# ============================================================================
# TRAINING MATRIX EXPORT
# Reuses: training_records, MANDATORY_ITEMS["training"], compute_training_record_status()
# New: Export endpoint returning CSV or PDF
# ============================================================================

@api_router.get("/training-matrix/export")
async def export_training_matrix(
    format: str = "csv",  # csv or pdf
    user: dict = Depends(get_current_user)
):
    """
    Export Training Matrix as CSV or PDF in CQC-compliant format.
    
    Format matches standard UK Care Home Training Matrix with:
    - Staff Name, Employee Start Date, Probation Review, Appraisal
    - Training columns showing completion dates
    - Color coding: Blue (in date), Yellow (expiring), Red (expired/missing)
    - Summary rows: Out of date count, % In Date per column, Average
    """
    import csv
    import io
    
    now = datetime.now(timezone.utc)
    
    # CQC Standard Training Types in order (matching Excel format)
    # Each training has an initial and optional refresher tracking
    cqc_training_order = [
        {"id": "induction", "name": "Induction", "has_refresher": False},
        {"id": "manual_handling", "name": "Moving & Handling", "has_refresher": True},
        {"id": "medication", "name": "Medication", "has_refresher": True},
        {"id": "health_safety", "name": "Health and Safety", "has_refresher": True},
        {"id": "food_hygiene", "name": "Food Hygiene", "has_refresher": True},
        {"id": "bls", "name": "First Aid", "has_refresher": True},  # BLS maps to First Aid
        {"id": "safeguarding", "name": "Safeguarding Adults & Child", "has_refresher": True},
        {"id": "mca_dols", "name": "MCA and DoLs", "has_refresher": True},
        {"id": "dementia", "name": "Dementia", "has_refresher": True},
        {"id": "fire_safety", "name": "Fire", "has_refresher": True},
        {"id": "autism", "name": "Autism Awareness", "has_refresher": True},
        # Additional trainings not in standard matrix but required
        {"id": "infection_control", "name": "Infection Control", "has_refresher": True},
        {"id": "information_governance", "name": "Info Governance", "has_refresher": True},
        {"id": "prevent", "name": "Prevent", "has_refresher": True},
    ]
    
    # Get all active employees with additional fields
    employees = await db.employees.find(
        {"status": {"$in": ["active", "onboarding"]}},
        {"_id": 0, "id": 1, "first_name": 1, "last_name": 1, "employee_code": 1, 
         "role": 1, "start_date": 1, "probation_end_date": 1, "next_appraisal_date": 1}
    ).to_list(500)
    
    # Build matrix data
    matrix_data = []
    column_stats = {t["id"]: {"in_date": 0, "out_of_date": 0, "total": 0} for t in cqc_training_order}
    
    for emp in employees:
        # Get employee's training records
        training_records = await db.training_records.find(
            {"employee_id": emp["id"], "record_status": {"$nin": ["deleted", "superseded"]}},
            {"_id": 0}
        ).to_list(100)
        
        # Create lookup by training name/id
        training_lookup = {}
        for record in training_records:
            key = record.get("requirement_id") or record.get("training_name", "").lower().replace(" ", "_")
            # Keep the most recent completed record
            if key not in training_lookup or (record.get("completion_date") and 
                (not training_lookup[key].get("completion_date") or 
                 record.get("completion_date") > training_lookup[key].get("completion_date"))):
                training_lookup[key] = record
        
        # Format dates helper
        def format_date(date_val):
            if not date_val:
                return ""
            try:
                if isinstance(date_val, str):
                    if 'T' in date_val:
                        dt = datetime.fromisoformat(date_val.replace('Z', '+00:00'))
                    else:
                        dt = datetime.fromisoformat(f"{date_val}T00:00:00+00:00")
                else:
                    dt = date_val
                return dt.strftime("%d/%m/%Y")
            except:
                return ""
        
        # Build row
        row = {
            "name": f"{emp['first_name']} {emp['last_name']}",
            "employee_code": emp.get("employee_code", ""),
            "start_date": format_date(emp.get("start_date")),
            "probation_review": format_date(emp.get("probation_end_date")),
            "appraisal": format_date(emp.get("next_appraisal_date")),
            "training": {}
        }
        
        for training_type in cqc_training_order:
            training_id = training_type["id"]
            
            # Try to find matching record
            record = training_lookup.get(training_id)
            if not record:
                # Try alternative keys
                alt_keys = {
                    "manual_handling": ["moving_handling", "moving_and_handling"],
                    "bls": ["first_aid", "basic_life_support"],
                    "safeguarding": ["safeguarding_adults", "safeguarding_children"],
                    "mca_dols": ["mca", "dols", "mental_capacity"],
                    "dementia": ["dementia_awareness"],
                    "autism": ["autism_awareness"],
                    "food_hygiene": ["food_safety"],
                }
                for alt_key in alt_keys.get(training_id, []):
                    record = training_lookup.get(alt_key)
                    if record:
                        break
            
            column_stats[training_id]["total"] += 1
            
            if record and record.get("status") == "completed":
                completion_date = record.get("completion_date")
                expiry_date = record.get("expiry_date")
                
                # Determine status
                status = "in_date"  # Blue
                completion_display = format_date(completion_date)
                expiry_display = format_date(expiry_date)
                
                if expiry_date:
                    try:
                        if isinstance(expiry_date, str):
                            if 'T' in expiry_date:
                                exp = datetime.fromisoformat(expiry_date.replace('Z', '+00:00'))
                            else:
                                exp = datetime.fromisoformat(f"{expiry_date}T00:00:00+00:00")
                        else:
                            exp = expiry_date if expiry_date.tzinfo else expiry_date.replace(tzinfo=timezone.utc)
                        
                        days_until = (exp - now).days
                        
                        if days_until < 0:
                            status = "expired"  # Red
                            column_stats[training_id]["out_of_date"] += 1
                        elif days_until <= 30:
                            status = "expiring"  # Yellow/Orange
                            column_stats[training_id]["in_date"] += 1
                        else:
                            column_stats[training_id]["in_date"] += 1
                    except:
                        column_stats[training_id]["in_date"] += 1
                else:
                    # No expiry = always in date
                    column_stats[training_id]["in_date"] += 1
                
                row["training"][training_id] = {
                    "status": status,
                    "completion_date": completion_display,
                    "expiry_date": expiry_display,
                    "verified": record.get("verified", False)
                }
            else:
                # Missing training
                row["training"][training_id] = {
                    "status": "missing",
                    "completion_date": "",
                    "expiry_date": "",
                    "verified": False
                }
                column_stats[training_id]["out_of_date"] += 1
        
        matrix_data.append(row)
    
    # Calculate percentages
    column_percentages = {}
    for training_id, stats in column_stats.items():
        if stats["total"] > 0:
            column_percentages[training_id] = round((stats["in_date"] / stats["total"]) * 100)
        else:
            column_percentages[training_id] = 100
    
    average_percentage = round(sum(column_percentages.values()) / len(column_percentages)) if column_percentages else 100
    
    # Generate export based on format
    if format.lower() == "csv":
        # CSV Export - Excel compatible
        output = io.StringIO()
        
        # Build headers
        headers = ["Staff Name", "Employee Start Date", "Probation Review", "Appraisal", "Add 1 for Current Employee"]
        for t in cqc_training_order:
            headers.append(t["name"])
            if t["has_refresher"]:
                headers.append(f"{t['name']} Refresher")
        
        writer = csv.writer(output)
        writer.writerow(headers)
        
        # Data rows
        for idx, row in enumerate(matrix_data, start=1):
            csv_row = [
                row["name"],
                row["start_date"],
                row["probation_review"],
                row["appraisal"],
                "1"  # Current employee count
            ]
            
            for t in cqc_training_order:
                training_data = row["training"].get(t["id"], {})
                # Show completion date in main column
                csv_row.append(training_data.get("completion_date", ""))
                # Show expiry/refresher due date in refresher column
                if t["has_refresher"]:
                    csv_row.append(training_data.get("expiry_date", ""))
            
            writer.writerow(csv_row)
        
        # Empty row
        writer.writerow([])
        
        # Out of date row
        out_of_date_row = ["", "", "", "", "Out of date"]
        for t in cqc_training_order:
            out_of_date_row.append(column_stats[t["id"]]["out_of_date"])
            if t["has_refresher"]:
                out_of_date_row.append("")
        writer.writerow(out_of_date_row)
        
        # Empty row
        writer.writerow([])
        
        # Training % In Date row
        percentage_row = ["", "", "", "Training % In Date"]
        for t in cqc_training_order:
            percentage_row.append(f"{column_percentages[t['id']]}%")
            if t["has_refresher"]:
                percentage_row.append("")
        writer.writerow(percentage_row)
        
        # Empty row
        writer.writerow([])
        
        # Average row
        writer.writerow(["", "", "Average", f"{average_percentage}%"])
        
        csv_content = output.getvalue()
        filename = f"training_matrix_{now.strftime('%Y%m%d_%H%M%S')}.csv"
        
        return Response(
            content=csv_content,
            media_type="text/csv",
            headers={"Content-Disposition": f"attachment; filename={filename}"}
        )
    
    elif format.lower() == "pdf":
        # PDF Export - CQC compliant format
        buffer = io.BytesIO()
        
        # Create PDF with landscape A3 for more columns
        from reportlab.lib.pagesizes import A3, landscape
        doc = SimpleDocTemplate(buffer, pagesize=landscape(A3), 
                               leftMargin=10*mm, rightMargin=10*mm, 
                               topMargin=15*mm, bottomMargin=15*mm)
        
        elements = []
        styles = getSampleStyleSheet()
        
        # Title
        title_style = ParagraphStyle(
            'CustomTitle',
            parent=styles['Heading1'],
            fontSize=18,
            spaceAfter=8,
            alignment=TA_CENTER,
            textColor=colors.Color(0, 0.3, 0.5)
        )
        elements.append(Paragraph("Training Matrix", title_style))
        elements.append(Paragraph(f"Generated: {now.strftime('%d/%m/%Y %H:%M')}", 
                                 ParagraphStyle('Date', fontSize=9, alignment=TA_CENTER, spaceAfter=15)))
        
        # Define colors matching Excel format
        color_blue = colors.Color(0.2, 0.6, 0.85)  # In date (blue)
        color_yellow = colors.Color(1, 0.85, 0.4)  # Expiring (yellow/orange)
        color_red = colors.Color(0.9, 0.3, 0.3)    # Expired/missing (red)
        color_header = colors.Color(0, 0.55, 0.75) # Header (teal blue like Excel)
        color_white = colors.white
        
        # Build headers
        pdf_headers = [
            Paragraph("<b>STAFF NAME</b>", ParagraphStyle('H', fontSize=6, alignment=TA_CENTER, textColor=colors.white)),
            Paragraph("<b>START<br/>DATE</b>", ParagraphStyle('H', fontSize=5, alignment=TA_CENTER, textColor=colors.white)),
            Paragraph("<b>PROBATION<br/>REVIEW</b>", ParagraphStyle('H', fontSize=5, alignment=TA_CENTER, textColor=colors.white)),
            Paragraph("<b>APPRAISAL</b>", ParagraphStyle('H', fontSize=5, alignment=TA_CENTER, textColor=colors.white)),
        ]
        
        for t in cqc_training_order:
            name = t["name"]
            # Shorten long names for PDF
            if len(name) > 12:
                name = name[:11] + "..."
            pdf_headers.append(Paragraph(f"<b>{name}</b>", ParagraphStyle('H', fontSize=5, alignment=TA_CENTER, textColor=colors.white)))
            if t["has_refresher"]:
                pdf_headers.append(Paragraph(f"<b>{name[:8]}...<br/>Refresher</b>", ParagraphStyle('H', fontSize=4, alignment=TA_CENTER, textColor=colors.white)))
        
        table_data = [pdf_headers]
        row_training_status = []  # Track status for conditional formatting
        
        # Data rows
        for row in matrix_data:
            pdf_row = [
                Paragraph(row["name"], ParagraphStyle('Cell', fontSize=6)),
                Paragraph(row["start_date"], ParagraphStyle('Cell', fontSize=5, alignment=TA_CENTER)),
                Paragraph(row["probation_review"], ParagraphStyle('Cell', fontSize=5, alignment=TA_CENTER)),
                Paragraph(row["appraisal"], ParagraphStyle('Cell', fontSize=5, alignment=TA_CENTER)),
            ]
            row_status = []
            
            for t in cqc_training_order:
                training_data = row["training"].get(t["id"], {})
                status = training_data.get("status", "missing")
                completion = training_data.get("completion_date", "")
                expiry = training_data.get("expiry_date", "")
                
                pdf_row.append(Paragraph(completion, ParagraphStyle('Cell', fontSize=5, alignment=TA_CENTER)))
                row_status.append(status)
                
                if t["has_refresher"]:
                    pdf_row.append(Paragraph(expiry, ParagraphStyle('Cell', fontSize=5, alignment=TA_CENTER)))
                    row_status.append(status)  # Same status for refresher column
            
            table_data.append(pdf_row)
            row_training_status.append(row_status)
        
        # Add empty row
        empty_row = [""] * len(pdf_headers)
        table_data.append(empty_row)
        row_training_status.append(["empty"] * (len(pdf_headers) - 4))
        
        # Out of date summary row
        out_of_date_row = [
            Paragraph("<b>Out of date</b>", ParagraphStyle('Sum', fontSize=6)),
            "", "", ""
        ]
        for t in cqc_training_order:
            out_of_date_row.append(Paragraph(str(column_stats[t["id"]]["out_of_date"]), 
                                            ParagraphStyle('Sum', fontSize=6, alignment=TA_CENTER, textColor=colors.red)))
            if t["has_refresher"]:
                out_of_date_row.append("")
        table_data.append(out_of_date_row)
        row_training_status.append(["summary"] * (len(pdf_headers) - 4))
        
        # Empty row
        table_data.append(empty_row)
        row_training_status.append(["empty"] * (len(pdf_headers) - 4))
        
        # Training % In Date row
        pct_row = [
            "", "", "",
            Paragraph("<b>Training % In Date</b>", ParagraphStyle('Sum', fontSize=6))
        ]
        for t in cqc_training_order:
            pct_row.append(Paragraph(f"<b>{column_percentages[t['id']]}%</b>", 
                                    ParagraphStyle('Sum', fontSize=6, alignment=TA_CENTER)))
            if t["has_refresher"]:
                pct_row.append("")
        table_data.append(pct_row)
        row_training_status.append(["summary"] * (len(pdf_headers) - 4))
        
        # Empty row
        table_data.append(empty_row)
        row_training_status.append(["empty"] * (len(pdf_headers) - 4))
        
        # Average row
        avg_row = [
            "", "",
            Paragraph("<b>Average</b>", ParagraphStyle('Sum', fontSize=8)),
            Paragraph(f"<b>{average_percentage}%</b>", ParagraphStyle('Sum', fontSize=8, textColor=colors.Color(0, 0.5, 0)))
        ] + [""] * (len(pdf_headers) - 4)
        table_data.append(avg_row)
        row_training_status.append(["summary"] * (len(pdf_headers) - 4))
        
        # Calculate column widths
        available_width = landscape(A3)[0] - 20*mm
        name_width = 45*mm
        date_col_width = 18*mm
        fixed_cols_width = name_width + (date_col_width * 3)
        remaining = available_width - fixed_cols_width
        
        # Count training columns (including refreshers)
        num_training_cols = sum(2 if t["has_refresher"] else 1 for t in cqc_training_order)
        training_col_width = remaining / num_training_cols if num_training_cols > 0 else 15*mm
        
        col_widths = [name_width, date_col_width, date_col_width, date_col_width]
        for t in cqc_training_order:
            col_widths.append(training_col_width)
            if t["has_refresher"]:
                col_widths.append(training_col_width)
        
        # Create table
        table = Table(table_data, colWidths=col_widths, repeatRows=1)
        
        # Base table style
        table_style = TableStyle([
            # Header row
            ('BACKGROUND', (0, 0), (-1, 0), color_header),
            ('TEXTCOLOR', (0, 0), (-1, 0), colors.white),
            ('ALIGN', (0, 0), (-1, -1), 'CENTER'),
            ('VALIGN', (0, 0), (-1, -1), 'MIDDLE'),
            ('FONTNAME', (0, 0), (-1, 0), 'Helvetica-Bold'),
            ('FONTSIZE', (0, 0), (-1, 0), 6),
            ('FONTSIZE', (0, 1), (-1, -1), 5),
            ('TOPPADDING', (0, 0), (-1, -1), 3),
            ('BOTTOMPADDING', (0, 0), (-1, -1), 3),
            ('GRID', (0, 0), (-1, -1), 0.5, colors.Color(0.7, 0.7, 0.7)),
            # Left align staff names
            ('ALIGN', (0, 1), (0, -1), 'LEFT'),
        ])
        
        # Apply conditional formatting for training status
        for row_idx, statuses in enumerate(row_training_status, start=1):
            for col_idx, status in enumerate(statuses, start=4):  # Start after fixed columns
                if status == "in_date":
                    table_style.add('BACKGROUND', (col_idx, row_idx), (col_idx, row_idx), color_blue)
                    table_style.add('TEXTCOLOR', (col_idx, row_idx), (col_idx, row_idx), colors.white)
                elif status == "expiring":
                    table_style.add('BACKGROUND', (col_idx, row_idx), (col_idx, row_idx), color_yellow)
                elif status == "expired" or status == "missing":
                    table_style.add('BACKGROUND', (col_idx, row_idx), (col_idx, row_idx), color_red)
                    table_style.add('TEXTCOLOR', (col_idx, row_idx), (col_idx, row_idx), colors.white)
        
        table.setStyle(table_style)
        elements.append(table)
        
        # Legend
        elements.append(Spacer(1, 8*mm))
        legend_style = ParagraphStyle('Legend', fontSize=8, spaceAfter=4)
        elements.append(Paragraph(
            "<b>Legend:</b> "
            "<font color='#3399DD'>■</font> In Date | "
            "<font color='#FFD966'>■</font> Expiring Soon (30 days) | "
            "<font color='#E64D4D'>■</font> Expired/Missing",
            legend_style
        ))
        elements.append(Paragraph(f"<i>Total Staff: {len(matrix_data)}</i>", legend_style))
        
        # Add verification stamp
        verification_stamp = generate_verification_stamp(
            verified_by=user.get('name', user.get('email', 'System')),
            verified_at=now.isoformat(),
            document_type="Training Matrix",
            include_hash=True,
            content_bytes=f"training_matrix_{len(matrix_data)}_{now.isoformat()}".encode()
        )
        stamp_elements = create_verification_footer_elements(verification_stamp)
        elements.extend(stamp_elements)
        
        # Build PDF
        doc.build(elements)
        
        pdf_content = buffer.getvalue()
        filename = f"training_matrix_{now.strftime('%Y%m%d_%H%M%S')}.pdf"
        
        return Response(
            content=pdf_content,
            media_type="application/pdf",
            headers={"Content-Disposition": f"attachment; filename={filename}"}
        )
    
    else:
        raise HTTPException(status_code=400, detail="Invalid format. Use 'csv' or 'pdf'")



@api_router.get("/compliance/dashboard")
async def get_compliance_dashboard(user: dict = Depends(get_current_user)):
    """Get compliance centre dashboard summary"""
    
    # Policies summary
    policies = await db.org_policies.find({}, {"_id": 0}).to_list(50)
    policies_active = len([p for p in policies if p.get("status") == "active"])
    policies_missing = len([p for p in policies if p.get("status") == "missing"])
    policies_expired = len([p for p in policies if p.get("status") == "expired"])
    
    # Insurance summary
    insurance = await db.insurance_docs.find({}, {"_id": 0}).to_list(10)
    now = datetime.now(timezone.utc)
    insurance_valid = 0
    insurance_expiring = 0
    insurance_expired = 0
    insurance_missing = 0
    
    for ins in insurance:
        if not ins.get("file_url"):
            insurance_missing += 1
        elif ins.get("expiry_date"):
            try:
                expiry_str = ins["expiry_date"]
                # Handle various date formats
                if isinstance(expiry_str, datetime):
                    exp = expiry_str if expiry_str.tzinfo else expiry_str.replace(tzinfo=timezone.utc)
                elif 'T' in str(expiry_str):
                    exp = datetime.fromisoformat(expiry_str.replace('Z', '+00:00'))
                else:
                    # Simple date format YYYY-MM-DD
                    exp = datetime.fromisoformat(f"{expiry_str}T00:00:00+00:00")
                
                if exp < now:
                    insurance_expired += 1
                elif exp < now + timedelta(days=30):
                    insurance_expiring += 1
                else:
                    insurance_valid += 1
            except Exception:
                insurance_valid += 1
        else:
            insurance_valid += 1
    
    # Incidents summary
    incidents_open = await db.incident_logs.count_documents({"status": {"$in": ["open", "investigating"]}})
    incidents_total = await db.incident_logs.count_documents({})
    
    # Staff compliance
    active_staff = await db.employees.count_documents({"status": {"$in": ["active", "onboarding"]}})
    
    return {
        "policies": {
            "total": len(policies),
            "active": policies_active,
            "missing": policies_missing,
            "expired": policies_expired
        },
        "insurance": {
            "total": len(insurance),
            "valid": insurance_valid,
            "expiring_soon": insurance_expiring,
            "expired": insurance_expired,
            "missing": insurance_missing
        },
        "incidents": {
            "open": incidents_open,
            "total": incidents_total
        },
        "staff": {
            "active": active_staff
        }
    }

@api_router.post("/contact")
async def submit_contact_form(form: ContactForm):
    contact_id = str(uuid.uuid4())
    now = datetime.now(timezone.utc).isoformat()
    
    contact_doc = {
        "id": contact_id,
        **form.model_dump(),
        "status": "new",
        "created_at": now
    }
    await db.contact_submissions.insert_one(contact_doc)
    
    # Send notification email if configured
    if resend.api_key:
        try:
            await asyncio.to_thread(resend.Emails.send, {
                "from": SENDER_EMAIL,
                "to": [os.environ.get('ADMIN_EMAIL', 'admin@osabeacares.co.uk')],
                "subject": f"New Contact Form: {form.subject}",
                "html": f"""
                <h2>New Contact Form Submission</h2>
                <p><strong>Name:</strong> {form.full_name}</p>
                <p><strong>Email:</strong> {form.email}</p>
                <p><strong>Phone:</strong> {form.phone or 'N/A'}</p>
                <p><strong>Organisation:</strong> {form.organisation or 'N/A'}</p>
                <p><strong>Subject:</strong> {form.subject}</p>
                <p><strong>Message:</strong></p>
                <p>{form.message}</p>
                """
            })
        except Exception as e:
            logger.error(f"Failed to send contact notification: {e}")
    
    return {"message": "Thank you for your enquiry. We will be in touch soon.", "id": contact_id}

@api_router.post("/apply")
async def submit_application(form: ApplicationForm):
    """
    Legacy simple application submission endpoint.
    
    Creates applicant record with applicant_reference (NOT employee_code).
    Employee_code is only assigned on recruitment approval.
    
    CONSTRAINT: NO user account created at application stage.
    """
    # Check for existing application with same email
    existing = await db.employees.find_one({"email": form.email}, {"_id": 0})
    if existing:
        raise HTTPException(
            status_code=400,
            detail=f"An application with this email already exists. Reference: {existing.get('applicant_reference', 'Unknown')}"
        )
    
    app_id = str(uuid.uuid4())
    applicant_ref = f"APP-{uuid.uuid4().hex[:8].upper()}"  # Applicant reference, not employee code
    now = datetime.now(timezone.utc).isoformat()
    
    # Create employee record (applicant stage)
    employee_doc = {
        "id": app_id,
        "applicant_reference": applicant_ref,  # Use applicant reference
        "employee_code": None,  # NOT assigned until recruitment approval
        "first_name": form.first_name,
        "last_name": form.last_name,
        "email": form.email,
        "phone": form.phone,
        "role": form.role_applied,
        "assignment": "Unassigned",
        "status": EmployeeStatus.NEW,  # Applicant stage
        "onboarding_status": OnboardingStatus.NEW,
        "start_date": None,
        "manager_name": None,
        "driver_status": False,
        "notes": f"Application received (legacy form). Availability: {form.availability or 'Not specified'}. Experience: {form.experience_summary or 'Not provided'}. How heard: {form.how_heard or 'Not specified'}",
        "completion_percentage": 0,
        "right_to_work_declared": form.right_to_work,
        "has_dbs_declared": form.has_dbs,
        "address": form.address,
        "postcode": form.postcode,
        "recruitment_approved": False,  # Explicitly false - NOT approved
        "application_source": "online_legacy",
        "application_submitted_at": now,
        "created_at": now,
        "updated_at": now
    }
    await db.employees.insert_one(employee_doc)
    
    # NO user account created - per constraint "Do NOT create employee user accounts at application stage"
    # User account will be created only when needed for portal access after recruitment approval
    
    # Log audit trail
    await db.audit_log.insert_one({
        "id": str(uuid.uuid4()),
        "user_id": "system",
        "action": "application_submitted",
        "entity_type": "applicant",
        "entity_id": app_id,
        "details": {
            "applicant_reference": applicant_ref,
            "email": form.email,
            "role_applied": form.role_applied,
            "application_source": "online_legacy",
            "clearance_granted": False,
            "approval_granted": False,
            "user_account_created": False
        },
        "timestamp": now
    })
    
    return {"message": "Your application has been submitted successfully. We will review it and be in touch.", "reference": applicant_ref}


# ==================== NHS-LEVEL STRUCTURED APPLICATION ENDPOINT ====================

@api_router.post("/applications/structured")
async def submit_structured_application(form: StructuredApplicationForm):
    """
    NHS-Level Structured Application Submission
    
    This endpoint receives comprehensive online applications and maps them
    into the existing recruitment model. 
    
    CRITICAL CONSTRAINTS:
    - NO employee_code assigned (assigned only on recruitment approval)
    - NO user account created (created only when needed for portal access)
    - NO clearance, approval, or work-ready status implied
    - Status is explicitly 'new' (applicant-stage)
    - recruitment_approved is explicitly False
    - All verification and approval remains manual
    
    This creates:
    1. Applicant record in employees collection
    2. Structured form_submission with all application data
    3. CV document in employee_documents (if uploaded)
    4. Follow-up requirement slots for missing items
    
    Returns applicant reference and list of follow-up items.
    """
    # Validation: Required declarations must be True
    if not form.declarations.information_accurate:
        raise HTTPException(status_code=400, detail="You must confirm the information is accurate")
    if not form.declarations.consents_to_reference_checks:
        raise HTTPException(status_code=400, detail="Consent to reference checks is required")
    if not form.declarations.consents_to_background_checks:
        raise HTTPException(status_code=400, detail="Consent to background checks is required")
    if not form.declarations.consents_to_data_processing:
        raise HTTPException(status_code=400, detail="Consent to data processing is required (GDPR)")
    if not form.health_declaration.health_declaration_accurate:
        raise HTTPException(status_code=400, detail="Health declaration must be confirmed accurate")
    if not form.criminal_declaration.understands_dbs_required:
        raise HTTPException(status_code=400, detail="You must acknowledge DBS check requirement")
    if not form.criminal_declaration.consents_to_dbs_check:
        raise HTTPException(status_code=400, detail="Consent to DBS check is required")
    
    # Validation: Minimum 2 references required for NHS-level compliance
    if len(form.references) < 2:
        raise HTTPException(status_code=400, detail="Minimum 2 references required")
    
    # Check for existing application with same email
    existing = await db.employees.find_one({"email": form.email}, {"_id": 0})
    if existing:
        raise HTTPException(
            status_code=400, 
            detail=f"An application with this email already exists. Reference: {existing.get('applicant_reference', 'Unknown')}"
        )
    
    app_id = str(uuid.uuid4())
    applicant_ref = f"APP-{uuid.uuid4().hex[:8].upper()}"
    now = datetime.now(timezone.utc).isoformat()
    
    # ==================== 1. CREATE APPLICANT RECORD ====================
    # Maps into existing employees collection with applicant-stage status
    
    # Build full address
    full_address = form.address_line_1
    if form.address_line_2:
        full_address += f", {form.address_line_2}"
    full_address += f", {form.city}"
    if form.county:
        full_address += f", {form.county}"
    
    employee_doc = {
        "id": app_id,
        "applicant_reference": applicant_ref,
        "employee_code": None,  # Not assigned until recruitment approval (EMP-XXXX)
        
        # Personal details
        "title": form.title,
        "first_name": form.first_name,
        "middle_name": form.middle_name,
        "last_name": form.last_name,
        "preferred_name": form.preferred_name,
        "date_of_birth": form.date_of_birth,
        "national_insurance": form.national_insurance,
        
        # Contact
        "email": form.email,
        "phone": form.phone,
        "phone_secondary": form.phone_secondary,
        
        # Address - store both individual fields AND concatenated
        "address": full_address,
        "address_line_1": form.address_line_1,
        "address_line_2": form.address_line_2,
        "city": form.city,
        "county": form.county,
        "postcode": form.postcode,
        
        # NI Number - store in both fields for compatibility
        "ni_number": form.national_insurance,
        
        # Role & availability
        "role_applied_raw": form.role_applied,  # Original input
        "role": normalize_role(form.role_applied),  # Normalized canonical role
        "system_role": normalize_to_system_role(form.role_applied),  # Compliance system role (HCA/NURSE)
        "assignment": "Unassigned",
        "availability": form.availability,
        "earliest_start_date": form.earliest_start_date,
        "preferred_locations": form.preferred_locations,
        "driver_status": form.has_driving_licence,
        "has_own_transport": form.has_own_transport,
        
        # Status - ALWAYS applicant stage, NEVER approved/cleared
        "status": EmployeeStatus.NEW,
        "onboarding_status": OnboardingStatus.NEW,
        "recruitment_approved": False,  # EXPLICIT: Not approved
        "recruitment_approved_by": None,
        "recruitment_approved_at": None,
        
        # Flags from declarations (for quick filtering - NOT verification)
        "right_to_work_declared": form.right_to_work.has_right_to_work_uk,
        "citizenship_status_declared": form.right_to_work.citizenship_status,
        "has_dbs_declared": form.criminal_declaration.consents_to_dbs_check,
        "has_criminal_convictions_declared": form.criminal_declaration.has_criminal_convictions,
        "has_professional_registration_declared": getattr(form.declarations, 'has_professional_registration', False),
        "professional_registration_body": getattr(form.declarations, 'registration_body', None),
        "professional_registration_number": getattr(form.declarations, 'registration_number', None),
        
        # Application metadata
        "application_source": "online_structured",
        "application_submitted_at": now,
        "how_heard": form.how_heard,
        
        # System fields
        "notes": f"Online application submitted. Role: {form.role_applied}. Availability: {form.availability}.",
        "completion_percentage": 0,
        "created_at": now,
        "updated_at": now,
        
        # Reference fields - ReferenceIntegrityService reads these from employee doc
        # Reference 1
        "reference_1_name": form.references[0].referee_name if len(form.references) > 0 else None,
        "reference_1_email": form.references[0].referee_email if len(form.references) > 0 else None,
        "reference_1_phone": form.references[0].referee_phone if len(form.references) > 0 else None,
        "reference_1_company": form.references[0].referee_organisation if len(form.references) > 0 else None,
        "reference_1_job_title": form.references[0].referee_job_title if len(form.references) > 0 else None,
        "reference_1_relationship": form.references[0].relationship if len(form.references) > 0 else None,
        "reference_1_years_known": form.references[0].years_known if len(form.references) > 0 else None,
        "reference_1_is_professional": form.references[0].is_professional if len(form.references) > 0 else None,
        "reference_1_can_contact_before_offer": form.references[0].can_contact_before_offer if len(form.references) > 0 else None,
        # Reference 2
        "reference_2_name": form.references[1].referee_name if len(form.references) > 1 else None,
        "reference_2_email": form.references[1].referee_email if len(form.references) > 1 else None,
        "reference_2_phone": form.references[1].referee_phone if len(form.references) > 1 else None,
        "reference_2_company": form.references[1].referee_organisation if len(form.references) > 1 else None,
        "reference_2_job_title": form.references[1].referee_job_title if len(form.references) > 1 else None,
        "reference_2_relationship": form.references[1].relationship if len(form.references) > 1 else None,
        "reference_2_years_known": form.references[1].years_known if len(form.references) > 1 else None,
        "reference_2_is_professional": form.references[1].is_professional if len(form.references) > 1 else None,
        "reference_2_can_contact_before_offer": form.references[1].can_contact_before_offer if len(form.references) > 1 else None,
        
        # Employment history - stored on employee for direct access
        "employment_history": [eh.model_dump() for eh in form.employment_history],
        "has_employment_gaps": form.has_employment_gaps,
        "employment_gap_explanation": form.employment_gap_explanation,
        
        # Declarations - stored on employee for direct access
        "declarations": {
            "has_criminal_convictions": form.criminal_declaration.has_criminal_convictions,
            "criminal_convictions_details": form.criminal_declaration.conviction_details,
            "dbs_consent_given": form.criminal_declaration.consents_to_dbs_check,
            "understands_dbs_required": form.criminal_declaration.understands_dbs_required,
            "has_health_conditions": form.health_declaration.has_health_conditions,
            "health_conditions_details": form.health_declaration.health_condition_details,
            "has_rtw_restrictions": not form.right_to_work.has_unlimited_right_to_work,
            "rtw_restrictions_details": form.right_to_work.visa_type if not form.right_to_work.has_unlimited_right_to_work else None,
            "rtw_expiry_date": form.right_to_work.visa_expiry if not form.right_to_work.has_unlimited_right_to_work else None,
            "information_accurate_declared": form.declarations.information_accurate,
            "consents_to_reference_checks": form.declarations.consents_to_reference_checks,
            "consents_to_background_checks": form.declarations.consents_to_background_checks,
            "consents_to_data_processing": form.declarations.consents_to_data_processing,
        },
        
        # Emergency Contact / Next of Kin
        "next_of_kin_name": form.emergency_contact_name,
        "next_of_kin_phone": form.emergency_contact_phone,
        "next_of_kin_relationship": form.emergency_contact_relationship,
        "next_of_kin_address": form.emergency_contact_address,
        "emergency_contact_name": form.emergency_contact_name,
        "emergency_contact_phone": form.emergency_contact_phone,
        "emergency_contact_relationship": form.emergency_contact_relationship,
        
        # Qualifications
        "highest_qualification": form.highest_qualification,
        "relevant_qualifications": form.relevant_qualifications,
        "care_certificate_completed": form.care_certificate_completed,
        "mandatory_training_completed": form.mandatory_training_completed,
    }
    
    await db.employees.insert_one(employee_doc)
    
    # ==================== 2. CREATE STRUCTURED FORM SUBMISSION ====================
    # Stores complete application data for review in existing form_submissions
    
    form_submission_id = str(uuid.uuid4())
    
    form_submission = {
        "id": form_submission_id,
        "employee_id": app_id,
        "requirement_id": "application_form",  # Required for compliance-file query
        "template_id": "structured_application_form",  # Virtual template ID
        "template_name": "Structured Application Form",
        "form_data": {
            # All structured data preserved for review
            "personal_details": {
                "title": form.title,
                "first_name": form.first_name,
                "middle_name": form.middle_name,
                "last_name": form.last_name,
                "preferred_name": form.preferred_name,
                "date_of_birth": form.date_of_birth,
                "national_insurance": form.national_insurance,
            },
            "contact_details": {
                "email": form.email,
                "phone": form.phone,
                "phone_secondary": form.phone_secondary,
            },
            "address": {
                "address_line_1": form.address_line_1,
                "address_line_2": form.address_line_2,
                "city": form.city,
                "county": form.county,
                "postcode": form.postcode,
                "years_at_current_address": form.years_at_current_address,
                "previous_addresses": form.previous_addresses,
            },
            "role_availability": {
                "role_applied": form.role_applied,
                "availability": form.availability,
                "earliest_start_date": form.earliest_start_date,
                "preferred_locations": form.preferred_locations,
                "has_driving_licence": form.has_driving_licence,
                "has_own_transport": form.has_own_transport,
            },
            "employment_history": [eh.model_dump() for eh in form.employment_history],
            "has_employment_gaps": form.has_employment_gaps,
            "employment_gap_explanation": form.employment_gap_explanation,
            "references": [ref.model_dump() for ref in form.references],
            "qualifications": {
                "highest_qualification": form.highest_qualification,
                "relevant_qualifications": form.relevant_qualifications,
                "care_certificate_completed": form.care_certificate_completed,
                "mandatory_training_completed": form.mandatory_training_completed,
            },
            "health_declaration": form.health_declaration.model_dump(),
            "criminal_declaration": form.criminal_declaration.model_dump(),
            "right_to_work": form.right_to_work.model_dump(),
            "declarations": form.declarations.model_dump(),
            "emergency_contact": {
                "name": form.emergency_contact_name,
                "phone": form.emergency_contact_phone,
                "relationship": form.emergency_contact_relationship,
                "address": form.emergency_contact_address,
            },
            "emergency_contact_name": form.emergency_contact_name,
            "emergency_contact_phone": form.emergency_contact_phone,
            "emergency_contact_relationship": form.emergency_contact_relationship,
            "emergency_contact_address": form.emergency_contact_address,
            "additional_info": form.additional_info,
            "how_heard": form.how_heard,
        },
        "status": FormStatus.COMPLETED,  # Completed by applicant, awaiting review
        "submitted_by_applicant": True,
        "submitted_at": now,
        "verified": False,  # NOT verified - requires manual review
        "verified_by": None,
        "verified_at": None,
        "requires_reverification": False,
        "created_at": now,
        "updated_at": now
    }
    
    await db.form_submissions.insert_one(form_submission)
    
    # ==================== 2b. INSERT REFERENCES INTO db.references ====================
    # This ensures references appear in the Recruitment Record's References section
    # Uses defensive error handling to never fail the application submission
    try:
        reference_doc = {
            "employee_id": app_id,
            "created_at": now,
            "updated_at": now,
        }
        
        # Process each reference (minimum 2 required, already validated above)
        for idx, ref in enumerate(form.references[:2], start=1):
            ref_key = f"ref{idx}"
            reference_doc[ref_key] = {
                "declared": {
                    "name": ref.referee_name,
                    "job_title": ref.referee_job_title,
                    "organisation": ref.referee_organisation,
                    "email": ref.referee_email,
                    "phone": ref.referee_phone,
                    "relationship": ref.relationship,
                    "years_known": ref.years_known,
                    "is_professional": ref.is_professional,
                    "can_contact_before_offer": ref.can_contact_before_offer,
                    "declared_at": now
                },
                "verification_status": "pending",  # Awaiting admin verification
                "response": None,  # No response yet
                "request": {
                    "sent_at": None,  # No request sent yet
                    "method": None
                },
                "verified_by": None,
                "verified_at": None,
                "notes": None
            }
        
        await db.references.insert_one(reference_doc)
        logger.info(f"Created references record for applicant {app_id}")
    except Exception as ref_err:
        # Log the error but DO NOT fail the application submission
        logger.warning(f"Non-blocking: Failed to insert references for {app_id}: {str(ref_err)}")
    
    # ==================== 3. LINK CV IF UPLOADED ====================
    
    if form.cv_file_id:
        # Get the CV document with extraction data
        cv_doc = await db.employee_documents.find_one({"id": form.cv_file_id}, {"_id": 0})
        
        # Update the CV document to link to this applicant
        await db.employee_documents.update_one(
            {"id": form.cv_file_id},
            {"$set": {
                "employee_id": app_id,
                "requirement_id": "cv",
                "requirement_name": "CV / Resume",
                "document_subtype": "cv",
                "is_active": True,
                "status": DocumentStatus.UPLOADED,
                "verified": False,
                "updated_at": now
            }}
        )
        await db.employees.update_one(
            {"id": app_id},
            {"$set": {
                "cv_document_id": form.cv_file_id,
                "updated_at": now
            }}
        )
        
        # If CV had extraction data, copy to employee record for 10-Year Employment History form
        if cv_doc and cv_doc.get("cv_extraction"):
            cv_extraction = cv_doc["cv_extraction"]
            await db.employees.update_one(
                {"id": app_id},
                {"$set": {
                    "cv_document_id": form.cv_file_id,
                    "cv_extracted_employment_history": cv_extraction.get("employment_history", []),
                    "cv_extracted_education": cv_extraction.get("education", []),
                    "cv_extracted_skills": cv_extraction.get("skills", []),
                    "cv_gaps_detected": [
                        {
                            "gap_id": f"gap_{i}",
                            "start_date": g.get("start_date"),
                            "end_date": g.get("end_date"),
                            "duration_days": g.get("duration_days"),
                            "message": g.get("message"),
                            "explanation": None,
                            "verified": False
                        }
                        for i, g in enumerate(cv_extraction.get("gaps_detected", [])) if g.get("needs_explanation")
                    ],
                    "cv_gaps_all_explained": len([g for g in cv_extraction.get("gaps_detected", []) if g.get("needs_explanation")]) == 0,
                    "cv_extracted_at": cv_extraction.get("extracted_at", now)
                }}
            )
            logger.info(f"CV extraction data linked to applicant {app_id}")
    
    # ==================== 4. CREATE FOLLOW-UP REQUIREMENT SLOTS ====================
    # Uses StageGateService to generate role-based requirement slots
    
    # Normalize the role
    normalized_role = normalize_role(form.role_applied)
    
    # Extract reference metadata from form
    ref1 = form.references[0]
    ref2 = form.references[1]
    reference_metadata = {
        "ref1": {
            "referee_name": ref1.referee_name,
            "referee_email": ref1.referee_email,
            "referee_phone": ref1.referee_phone,
            "referee_organisation": ref1.referee_organisation,
            "referee_job_title": ref1.referee_job_title,
            "relationship": ref1.relationship,
            "years_known": ref1.years_known,
            "is_professional": ref1.is_professional,
            "can_contact_before_offer": ref1.can_contact_before_offer
        },
        "ref2": {
            "referee_name": ref2.referee_name,
            "referee_email": ref2.referee_email,
            "referee_phone": ref2.referee_phone,
            "referee_organisation": ref2.referee_organisation,
            "referee_job_title": ref2.referee_job_title,
            "relationship": ref2.relationship,
            "years_known": ref2.years_known,
            "is_professional": ref2.is_professional,
            "can_contact_before_offer": ref2.can_contact_before_offer
        }
    }
    
    # Generate requirement slots based on role pack
    stage_service = StageGateService(db)
    created_slots = await stage_service.generate_requirements_for_employee(
        employee_id=app_id,
        role=normalized_role,
        reference_metadata=reference_metadata
    )
    
    # Seed application completion (cv, application_form, equal_opportunities)
    await stage_service.seed_application_completion(
        employee_id=app_id,
        cv_file_id=form.cv_file_id,
        form_submission_id=form_submission_id
    )
    
    # Build follow-up items from created slots
    follow_up_items = stage_service.build_follow_up_items(normalized_role, created_slots)
    
    # Add conditional follow-up items based on declarations
    
    # Health Declaration Review
    if form.health_declaration.has_condition_affecting_work or form.health_declaration.requires_reasonable_adjustments:
        follow_up_items.append({
            "type": "health_review",
            "requirement_key": "health_review",
            "description": "Health declaration requires Occupational Health review",
            "status": "review_required"
        })
    
    # Professional Registration (if declared and not already in role pack)
    has_prof_reg = getattr(form.declarations, 'has_professional_registration', False)
    if has_prof_reg and normalized_role != "nurse":
        reg_body = getattr(form.declarations, 'registration_body', 'Unknown')
        reg_number = getattr(form.declarations, 'registration_number', 'Unknown')
        follow_up_items.append({
            "type": "professional_registration",
            "requirement_key": "professional_registration",
            "description": f"Verify {reg_body} registration: {reg_number}",
            "status": "verification_required"
        })
    
    # Address History (if at current address < 5 years)
    if form.years_at_current_address < 5:
        follow_up_items.append({
            "type": "address_history",
            "requirement_key": "address_history",
            "description": "5-year address history verification required for DBS",
            "status": "required"
        })
    
    # ==================== AUTO-DETECT EMPLOYMENT GAPS ====================
    # Detect gaps automatically from employment history dates
    employment_history_list = [eh.model_dump() for eh in form.employment_history]
    detected_gaps = detect_employment_gaps(employment_history_list)
    
    # Store detected gaps in employee record and create gap records
    if detected_gaps:
        # Update employee with gaps
        await db.employees.update_one(
            {"id": app_id},
            {"$set": {
                "employment_gaps": detected_gaps,
                "employment_gaps_detected_at": now,
                "has_employment_gaps": True
            }}
        )
        
        # Create individual gap records in gaps collection
        for gap in detected_gaps:
            gap_record = create_gap_record(app_id, gap, created_by="system")
            await db.employment_gaps.update_one(
                {"id": gap_record["id"]},
                {"$set": gap_record},
                upsert=True
            )
        
        # Add to follow-up items - ONLY when there are ACTUAL detected gaps
        follow_up_items.append({
            "type": "employment_gaps",
            "requirement_key": "employment_history_verification",
            "description": f"{len(detected_gaps)} employment gap(s) detected ({sum(g.get('duration_months', 0) for g in detected_gaps):.0f} months total) - explanation will be requested",
            "status": "review_required",
            "gap_count": len(detected_gaps),
            "total_gap_months": sum(g.get("duration_months", 0) for g in detected_gaps),
            "is_admin_only": True  # Flag to filter from applicant-facing display
        })
        
        logger.info(f"Detected {len(detected_gaps)} employment gaps for {app_id}")
    
    # NOTE: Removed misleading "Applicant declared employment gaps" warning
    # The gap flag on the form (has_employment_gaps) is now only used internally
    # We only show gap warnings when there are ACTUAL detected gaps from date analysis
    
    # ==================== 5. LOG AUDIT TRAIL ====================
    
    await db.audit_log.insert_one({
        "id": str(uuid.uuid4()),
        "user_id": "system",
        "action": "application_submitted",
        "entity_type": "applicant",
        "entity_id": app_id,
        "details": {
            "applicant_reference": applicant_ref,
            "email": form.email,
            "role_applied": form.role_applied,
            "application_source": "online_structured",
            "follow_up_items_count": len(follow_up_items),
            # Explicit audit that NO clearance was granted
            "clearance_granted": False,
            "approval_granted": False,
            "work_ready_status": False,
            "employee_code_assigned": False,
            "user_account_created": False
        },
        "timestamp": now
    })
    
    logger.info(f"Structured application submitted: {applicant_ref} for {form.email}")
    
    # Filter follow-up items for applicant-facing display (remove admin-only items)
    applicant_facing_items = [
        item for item in follow_up_items 
        if not item.get("is_admin_only") and item.get("type") in [
            "reference", "right_to_work", "identity", "proof_of_address"
        ]
    ]
    
    # Send confirmation email with magic link to applicant portal
    try:
        # Generate magic link token for worker portal access
        frontend_url = os.environ.get('FRONTEND_URL', 'https://app.osabeacares.co.uk')
        magic_token_data = {
            "employee_id": app_id,
            "email": form.email.lower(),
            "type": "worker_login",
            "exp": datetime.now(timezone.utc) + timedelta(days=7)  # 7 day expiry for new applicants
        }
        magic_token = jwt.encode(magic_token_data, JWT_SECRET, algorithm=JWT_ALGORITHM)
        
        # Store magic token
        await db.magic_tokens.insert_one({
            "token": magic_token,
            "employee_id": app_id,
            "email": form.email.lower(),
            "expires_at": (datetime.now(timezone.utc) + timedelta(days=7)).isoformat(),
            "used": False,
            "created_at": now,
            "purpose": "application_welcome"
        })
        
        portal_url = f"{frontend_url}/worker/verify?token={magic_token}"
        
        email_html = f"""
        <div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">
            <div style="background: #0F172A; padding: 24px; text-align: center;">
                <h1 style="color: white; margin: 0; font-size: 24px;">Osabea Healthcare</h1>
            </div>
            <div style="padding: 32px; background: #f8fafc;">
                <h2 style="color: #1e293b; margin-top: 0;">Welcome, {form.first_name}!</h2>
                <p style="color: #475569; line-height: 1.6;">
                    Thank you for submitting your application. Your reference number is:
                </p>
                <div style="background: white; border: 2px solid #e2e8f0; border-radius: 8px; padding: 16px; text-align: center; margin: 20px 0;">
                    <span style="font-size: 24px; font-weight: bold; color: #0F172A; letter-spacing: 2px;">{applicant_ref}</span>
                </div>
                
                <h3 style="color: #1e293b; margin-top: 24px;">Complete Your Onboarding</h3>
                <p style="color: #475569; line-height: 1.6;">
                    To proceed with your application, you'll need to complete some forms and upload documents. 
                    Click the button below to access your personal compliance portal:
                </p>
                
                <div style="text-align: center; margin: 30px 0;">
                    <a href="{portal_url}" style="background: #2563EB; color: white; padding: 14px 32px; text-decoration: none; border-radius: 8px; font-weight: bold; display: inline-block;">
                        Access My Portal
                    </a>
                </div>
                
                <div style="background: #fef3c7; border-left: 4px solid #f59e0b; padding: 16px; margin: 24px 0;">
                    <p style="color: #92400e; margin: 0; font-weight: bold;">What you'll need to provide:</p>
                    <ul style="color: #92400e; margin: 8px 0 0 0; padding-left: 20px;">
                        <li>Health Questionnaire</li>
                        <li>Personal Information</li>
                        <li>HMRC Starter Checklist (for payroll)</li>
                        <li>Right to Work documents</li>
                        <li>DBS certificate or DBS application</li>
                        <li>Proof of identity</li>
                        <li>Proof of address (2 documents)</li>
                    </ul>
                </div>
                
                <p style="color: #64748b; font-size: 14px;">
                    This link expires in 7 days. If you need a new link, visit <a href="{frontend_url}/worker/login" style="color: #2563EB;">the worker portal</a> and enter your email.
                </p>
                
                <hr style="border: none; border-top: 1px solid #e2e8f0; margin: 24px 0;">
                <p style="color: #94a3b8; font-size: 12px; text-align: center;">
                    Osabea Healthcare Solutions | Compliance Portal<br/>
                    Questions? Contact recruitment@osabeacares.co.uk
                </p>
            </div>
        </div>
        """
        
        # Send via Resend
        if resend.api_key:
            await asyncio.to_thread(resend.Emails.send, {
                "from": SENDER_EMAIL,
                "to": [form.email],
                "subject": f"Welcome to Osabea Healthcare - Application {applicant_ref}",
                "html": email_html
            })
            logger.info(f"Welcome email with portal link sent to {form.email} for application {applicant_ref}")
        else:
            logger.warning(f"Resend API key not configured - structured application welcome email not sent for {form.email}")
    except Exception as e:
        # Log but don't fail the submission if email fails
        logger.warning(f"Failed to send welcome email to {form.email}: {e}")
    
    return {
        "status": "submitted",
        "message": "Your application has been submitted successfully. Our recruitment team will review it and contact you.",
        "reference": applicant_ref,
        "applicant_id": app_id,
        "next_steps": [
            "Our team will review your application within 5 working days",
            "We may contact your references for verification",
            "You may be invited for an interview"
        ],
        "follow_up_items": applicant_facing_items,
        "important_notes": [
            "This submission does NOT constitute a job offer",
            "All information will be verified before any employment decision",
            "You will be contacted if additional information is required"
        ]
    }


@api_router.post("/applications/cv-upload")
async def upload_application_cv(file: UploadFile = File(...)):
    """
    Upload CV for application (before full submission).
    Returns a file_id that can be included in the application form.
    
    This is a public endpoint - no authentication required.
    The CV is stored in a pending state until linked to an application.
    """
    if not file.filename:
        raise HTTPException(status_code=400, detail="No file provided")
    
    # Validate file type
    allowed_types = ['.pdf']
    file_ext = '.' + file.filename.split('.')[-1].lower() if '.' in file.filename else ''
    if file_ext not in allowed_types:
        raise HTTPException(status_code=400, detail="Only PDF CV files are supported")
    
    # Validate file size (max 10MB)
    content = await file.read()
    if len(content) > 10 * 1024 * 1024:
        raise HTTPException(status_code=400, detail="File too large. Maximum size: 10MB")
    
    now = datetime.now(timezone.utc).isoformat()
    doc_id = str(uuid.uuid4())
    
    # Upload to storage (try Supabase first, fallback to Emergent)
    file_url = None
    storage_path = None
    
    try:
        from supabase_storage import is_supabase_storage_configured, upload_to_supabase
        
        if is_supabase_storage_configured():
            # Use Supabase Storage
            upload_result = await upload_to_supabase(
                content, 
                file.filename,
                bucket="documents",
                folder="application-cvs"
            )
            file_url = upload_result.get('url')
            storage_path = upload_result.get('path')
            logger.info(f"CV uploaded to Supabase: {storage_path}")
        else:
            # Fallback to Emergent object storage
            storage_path = f"{APP_NAME}/cv/{uuid.uuid4()}/{file.filename}"
            content_type = file.content_type or 'application/pdf'
            upload_result = put_object(storage_path, content, content_type)
            file_url = upload_result.get('url') or f"{STORAGE_URL}/objects/{storage_path}"
            logger.info(f"CV uploaded to Emergent storage")
            
    except Exception as e:
        logger.error(f"CV upload failed: {e}")
        raise HTTPException(status_code=500, detail=f"Failed to upload file: {str(e)}")
    
    if not file_url:
        raise HTTPException(status_code=500, detail="Upload succeeded but no URL returned")
    
    # Create pending document record
    doc_data = {
        "id": doc_id,
        "employee_id": None,  # Will be linked on application submission
        "document_type_id": None,
        "document_type_name": "CV / Resume",
        "category": "Application Documents",
        "requirement_id": "cv",
        "requirement_name": "CV / Resume",
        "document_subtype": "cv",
        "file_name": file.filename,
        "original_filename": file.filename,
        "file_url": file_url,
        "storage_path": storage_path,
        "file_size": len(content),
        "file_type": file_ext,
        "status": DocumentStatus.UPLOADED,
        "verified": False,
        "upload_source": "application_cv",
        "created_at": now,
        "updated_at": now
    }
    
    await db.employee_documents.insert_one(doc_data)
    
    # AI EXTRACTION: Extract employment history from CV immediately
    extraction_result = None
    try:
        extraction_result = await _extract_cv_employment_history_helper(content, file.filename, None)
        
        if extraction_result.get("status") == "success":
            # Store extraction in the document record for later use
            await db.employee_documents.update_one(
                {"id": doc_id},
                {"$set": {
                    "cv_extraction": {
                        "status": "completed",
                        "employment_history": extraction_result.get("employment_history", []),
                        "education": extraction_result.get("education", []),
                        "skills": extraction_result.get("skills", []),
                        "full_name": extraction_result.get("full_name"),
                        "gaps_detected": extraction_result.get("gaps_detected", []),
                        "total_jobs_found": extraction_result.get("total_jobs_found", 0),
                        "extracted_at": now
                    }
                }}
            )
            logger.info(f"CV extraction completed: {extraction_result.get('total_jobs_found', 0)} jobs found")
    except Exception as e:
        logger.warning(f"CV extraction failed during application upload: {e}")
        # Continue without extraction - can be done later
    
    response = {
        "file_id": doc_id,
        "file_name": file.filename,
        "message": "CV uploaded successfully. Include this file_id in your application."
    }
    
    # Add extraction info to response if successful
    if extraction_result and extraction_result.get("status") == "success":
        response["extraction"] = {
            "jobs_found": extraction_result.get("total_jobs_found", 0),
            "gaps_detected": len([g for g in extraction_result.get("gaps_detected", []) if g.get("needs_explanation")]),
            "employment_history": extraction_result.get("employment_history", [])[:5],  # First 5 jobs for preview
            "full_name": extraction_result.get("full_name")
        }
        response["message"] = f"CV uploaded and analyzed. Found {extraction_result.get('total_jobs_found', 0)} jobs."
    
    return response


# ==================== UNIVERSAL DOCUMENT EXTRACTION PIPELINE ====================
# Phase 1: Training Certificates → Phase 2: DBS, RTW, ID → Phase 3: Proof of Address
# 
# Core Rules:
# - Extraction = assistive draft only
# - Verified structured record = source of truth
# - Extraction never directly marks document verified or employee ready
# - All extracted values require admin review before entering authoritative fields

class DocumentExtractionType(str, Enum):
    TRAINING_CERTIFICATE = "training_certificate"
    DBS = "dbs"
    RIGHT_TO_WORK = "right_to_work"
    ID = "id"
    PROOF_OF_ADDRESS = "proof_of_address"
    OTHER = "other"


class ExtractionStatus(str, Enum):
    PENDING = "pending"
    COMPLETED = "completed"
    FAILED = "failed"
    NEEDS_REVIEW = "needs_review"


class ReviewStatus(str, Enum):
    AWAITING_REVIEW = "awaiting_review"
    APPROVED = "approved"
    EDITED = "edited"
    REJECTED = "rejected"


class ExtractionSourceType(str, Enum):
    EXPLICIT = "explicit"
    INFERRED_POLICY = "inferred_policy"
    DERIVED_TEXT = "derived_text"
    NOT_FOUND = "not_found"


class ExtractionIssueSeverity(str, Enum):
    INFO = "info"
    WARNING = "warning"
    BLOCKER = "blocker"


# Training renewal policies (internal policy mapping)
TRAINING_RENEWAL_POLICIES = {
    "moving_and_handling": {"months": 12, "title_keywords": ["moving", "handling", "manual handling"]},
    "medication": {"months": 12, "title_keywords": ["medication", "medicine", "administration"]},
    "safeguarding_adults": {"months": 36, "title_keywords": ["safeguarding adult"]},
    "safeguarding_children": {"months": 36, "title_keywords": ["safeguarding child", "child protection"]},
    "infection_control": {"months": 12, "title_keywords": ["infection", "control", "ppe"]},
    "fire_safety": {"months": 12, "title_keywords": ["fire safety", "fire awareness"]},
    "first_aid": {"months": 36, "title_keywords": ["first aid"]},
    "food_hygiene": {"months": 36, "title_keywords": ["food hygiene", "food safety"]},
    "health_and_safety": {"months": 12, "title_keywords": ["health and safety", "h&s"]},
    "mental_capacity": {"months": 12, "title_keywords": ["mental capacity", "mca"]},
    "cpr_bls": {"months": 12, "title_keywords": ["cpr", "bls", "basic life support"]},
}


class DocumentExtractionService:
    """
    Universal extraction framework for all document types.
    
    Principles:
    - Extraction is ASSISTIVE only - never auto-verifies
    - All extracted values require admin review
    - Canonical structured records remain source of truth
    - Extraction record provides audit trail
    """
    
    EXTRACTOR_VERSION = "1.0.0"
    
    @staticmethod
    async def run_extraction(document_id: str, force_rerun: bool = False) -> dict:
        """
        Main entry point for document extraction.
        
        Args:
            document_id: ID of the uploaded document OR a file_id from evidence_files
            force_rerun: If True, re-runs extraction even if one exists
            
        Returns:
            Extraction record
        """
        # Check for existing extraction
        existing = await db.document_extractions.find_one(
            {"document_id": document_id},
            {"_id": 0}
        )
        if existing and not force_rerun:
            if existing.get("extraction_status") in ["completed", "needs_review"]:
                return existing
        
        # Get document - first try direct ID match
        document = await db.employee_documents.find_one({"id": document_id}, {"_id": 0})
        
        # BUGFIX: If not found, try looking up by file_id in evidence_files array
        if not document:
            document = await db.employee_documents.find_one(
                {"evidence_files.file_id": document_id},
                {"_id": 0}
            )
            # If found, update document_id to the actual document ID
            if document:
                # Find the specific evidence file to get its file_url
                evidence_file = next(
                    (ef for ef in document.get("evidence_files", []) if ef.get("file_id") == document_id),
                    None
                )
                # Store the file_id for reference but use document.id as authoritative
                document_id = document.get("id")
                if evidence_file:
                    # Use the specific evidence file's URL if available
                    document["_evidence_file"] = evidence_file
        
        # Also check training_records for training certificates
        if not document:
            training_record = await db.training_records.find_one(
                {"$or": [
                    {"id": document_id},
                    {"evidence_files.file_id": document_id}
                ]},
                {"_id": 0}
            )
            if training_record:
                # Convert training record to document-like structure
                evidence_file = next(
                    (ef for ef in training_record.get("evidence_files", []) if ef.get("file_id") == document_id),
                    training_record.get("evidence_files", [{}])[0] if training_record.get("evidence_files") else None
                )
                if evidence_file:
                    document = {
                        "id": document_id,
                        "employee_id": training_record.get("employee_id"),
                        "file_url": evidence_file.get("file_url") or training_record.get("certificate_url"),
                        "requirement_id": training_record.get("requirement_id"),
                        "document_type_name": training_record.get("training_name"),
                        "_is_training": True,
                        "_training_record_id": training_record.get("id")
                    }
        
        if not document:
            raise HTTPException(
                status_code=404, 
                detail=f"Document not found for id {document_id}. The document may have been removed or the ID is invalid."
            )
        
        # Get employee for name matching
        employee = await db.employees.find_one(
            {"id": document.get("employee_id")},
            {"_id": 0, "id": 1, "first_name": 1, "last_name": 1}
        )
        employee_name = f"{employee.get('first_name', '')} {employee.get('last_name', '')}".strip() if employee else ""
        
        # Create extraction record
        extraction_id = str(uuid.uuid4())
        now = datetime.now(timezone.utc).isoformat()
        
        extraction = {
            "id": extraction_id,
            "document_id": document_id,
            "employee_id": document.get("employee_id"),
            "document_type": DocumentExtractionService._classify_document_type(document),
            "extraction_status": ExtractionStatus.PENDING.value,
            "extractor_version": DocumentExtractionService.EXTRACTOR_VERSION,
            "extracted_fields": {},
            "field_metadata": {},
            "issues": [],
            "raw_text_excerpt": None,
            "extracted_at": now,
            "review_status": ReviewStatus.AWAITING_REVIEW.value,
            "reviewed_by": None,
            "reviewed_at": None,
            "approved_field_values": None
        }
        
        try:
            # Download document - prefer specific evidence file URL if available
            evidence_file = document.get("_evidence_file")
            if evidence_file:
                file_url = evidence_file.get("file_url")
            else:
                file_url = document.get("file_url")
                # If no direct URL, check evidence_files
                if not file_url and document.get("evidence_files"):
                    active_file = next(
                        (ef for ef in document.get("evidence_files", []) if ef.get("status") in [None, "active"]),
                        document.get("evidence_files", [{}])[0] if document.get("evidence_files") else None
                    )
                    if active_file:
                        file_url = active_file.get("file_url")
            
            if not file_url:
                extraction["extraction_status"] = ExtractionStatus.FAILED.value
                extraction["issues"].append({
                    "code": "no_file_url",
                    "detail": "Document file URL not found",
                    "severity": ExtractionIssueSeverity.BLOCKER.value
                })
                await DocumentExtractionService._save_extraction(extraction)
                return extraction
            
            # Get API key
            api_key = os.environ.get('EMERGENT_LLM_KEY')
            if not api_key:
                extraction["extraction_status"] = ExtractionStatus.FAILED.value
                extraction["issues"].append({
                    "code": "no_api_key",
                    "detail": "LLM API key not configured",
                    "severity": ExtractionIssueSeverity.BLOCKER.value
                })
                await DocumentExtractionService._save_extraction(extraction)
                return extraction
            
            # Get file content using internal object storage
            file_path = document.get("file_url")
            if not file_path:
                extraction["extraction_status"] = ExtractionStatus.FAILED.value
                extraction["issues"].append({
                    "code": "no_file_url",
                    "detail": "Document file URL not found",
                    "severity": ExtractionIssueSeverity.BLOCKER.value
                })
                await DocumentExtractionService._save_extraction(extraction)
                return extraction
            
            try:
                file_content, content_type = get_object(file_path)
            except Exception as e:
                extraction["extraction_status"] = ExtractionStatus.FAILED.value
                extraction["issues"].append({
                    "code": "download_failed",
                    "detail": f"Failed to retrieve document from storage: {str(e)}",
                    "severity": ExtractionIssueSeverity.BLOCKER.value
                })
                await DocumentExtractionService._save_extraction(extraction)
                return extraction
            
            # Determine file type from content_type or filename
            file_ext = ".pdf"
            if content_type:
                if "jpeg" in content_type or "jpg" in content_type:
                    file_ext = ".jpg"
                elif "png" in content_type:
                    file_ext = ".png"
                elif "webp" in content_type:
                    file_ext = ".webp"
            original_filename = document.get("original_filename", "").lower()
            if original_filename.endswith(".pdf"):
                file_ext = ".pdf"
            elif any(original_filename.endswith(ext) for ext in [".jpg", ".jpeg"]):
                file_ext = ".jpg"
            elif original_filename.endswith(".png"):
                file_ext = ".png"
            
            # Convert to images for vision processing
            images_to_process = await DocumentExtractionService._convert_to_images(
                file_content, 
                file_ext
            )
            
            if not images_to_process:
                extraction["extraction_status"] = ExtractionStatus.FAILED.value
                extraction["issues"].append({
                    "code": "conversion_failed",
                    "detail": "Could not convert document to images for processing",
                    "severity": ExtractionIssueSeverity.BLOCKER.value
                })
                await DocumentExtractionService._save_extraction(extraction)
                return extraction
            
            # Run document-type-specific extraction
            doc_type = extraction["document_type"]
            
            if doc_type == DocumentExtractionType.TRAINING_CERTIFICATE.value:
                result = await DocumentExtractionService._extract_training_certificate(
                    images_to_process, api_key, employee_name
                )
            elif doc_type == DocumentExtractionType.DBS.value:
                result = await DocumentExtractionService._extract_dbs(
                    images_to_process, api_key, employee_name
                )
            elif doc_type == DocumentExtractionType.RIGHT_TO_WORK.value:
                result = await DocumentExtractionService._extract_rtw(
                    images_to_process, api_key, employee_name
                )
            elif doc_type == DocumentExtractionType.ID.value:
                result = await DocumentExtractionService._extract_id(
                    images_to_process, api_key, employee_name
                )
            elif doc_type == DocumentExtractionType.PROOF_OF_ADDRESS.value:
                result = await DocumentExtractionService._extract_proof_of_address(
                    images_to_process, api_key, employee_name
                )
            else:
                result = await DocumentExtractionService._extract_generic(
                    images_to_process, api_key, employee_name
                )
            
            # Update extraction with results
            extraction["extracted_fields"] = result.get("fields", {})
            extraction["field_metadata"] = result.get("metadata", {})
            extraction["issues"].extend(result.get("issues", []))
            extraction["raw_text_excerpt"] = result.get("raw_text_excerpt")
            
            # Check for name mismatch
            extracted_name = result.get("fields", {}).get("holder_name", "")
            if extracted_name and employee_name:
                name_match = DocumentExtractionService._check_name_match(extracted_name, employee_name)
                if not name_match:
                    extraction["issues"].append({
                        "code": "holder_name_mismatch",
                        "detail": f"Document holder '{extracted_name}' differs from employee '{employee_name}'",
                        "severity": ExtractionIssueSeverity.WARNING.value
                    })
            
            # Determine extraction status
            blocker_issues = [i for i in extraction["issues"] if i.get("severity") == "blocker"]
            if blocker_issues:
                extraction["extraction_status"] = ExtractionStatus.NEEDS_REVIEW.value
            else:
                extraction["extraction_status"] = ExtractionStatus.COMPLETED.value
            
            await DocumentExtractionService._save_extraction(extraction)
            return extraction
            
        except Exception as e:
            logger.error(f"Document extraction failed for {document_id}: {e}")
            extraction["extraction_status"] = ExtractionStatus.FAILED.value
            extraction["issues"].append({
                "code": "extraction_error",
                "detail": str(e),
                "severity": ExtractionIssueSeverity.BLOCKER.value
            })
            await DocumentExtractionService._save_extraction(extraction)
            return extraction
    
    @staticmethod
    async def _save_extraction(extraction: dict):
        """Save or update extraction record."""
        await db.document_extractions.update_one(
            {"document_id": extraction["document_id"]},
            {"$set": extraction},
            upsert=True
        )
    
    @staticmethod
    def _classify_document_type(document: dict) -> str:
        """Classify document type based on metadata."""
        doc_type = document.get("document_type_id", "").lower()
        doc_type_name = document.get("document_type_name", "").lower()
        doc_name = document.get("file_name", "").lower()
        original_name = document.get("original_filename", "").lower()
        category = document.get("category", "").lower()
        req_id = document.get("requirement_id", "").lower()
        
        all_text = f"{doc_type} {doc_type_name} {doc_name} {original_name} {category} {req_id}"
        
        # Training certificates
        if any(kw in all_text for kw in ["training", "certificate", "course", "accreditation"]):
            if "dbs" not in all_text:  # Avoid misclassifying DBS certificates
                return DocumentExtractionType.TRAINING_CERTIFICATE.value
        
        # DBS
        if "dbs" in all_text or "disclosure" in all_text or "barring" in all_text:
            return DocumentExtractionType.DBS.value
        
        # Right to Work
        if any(kw in all_text for kw in ["rtw", "right_to_work", "right to work", "visa", "brp", "residence", "permit", "share_code", "share code"]):
            return DocumentExtractionType.RIGHT_TO_WORK.value
        
        # ID
        if any(kw in all_text for kw in ["passport", "driving", "license", "licence", "id_document", "identity", "national_id"]):
            return DocumentExtractionType.ID.value
        
        # Proof of address
        if any(kw in all_text for kw in ["address", "utility", "bill", "statement", "council_tax", "proof_of_address"]):
            return DocumentExtractionType.PROOF_OF_ADDRESS.value
        
        return DocumentExtractionType.OTHER.value
    
    @staticmethod
    async def _convert_to_images(file_content: bytes, file_type: str) -> List[str]:
        """Convert document to base64 images for vision processing."""
        images = []
        file_ext = file_type.lower().replace(".", "")
        
        if file_ext == "pdf":
            import fitz
            try:
                pdf_doc = fitz.open(stream=file_content, filetype="pdf")
                for page_num in range(min(pdf_doc.page_count, 3)):  # Max 3 pages
                    page = pdf_doc[page_num]
                    pix = page.get_pixmap(matrix=fitz.Matrix(2, 2))
                    img_bytes = pix.tobytes("png")
                    img_base64 = base64.b64encode(img_bytes).decode()
                    images.append(img_base64)
                pdf_doc.close()
            except Exception as e:
                logger.error(f"PDF conversion failed: {e}")
        elif file_ext in ["png", "jpg", "jpeg", "webp"]:
            img_base64 = base64.b64encode(file_content).decode()
            images.append(img_base64)
        else:
            # Try as binary
            img_base64 = base64.b64encode(file_content).decode()
            images.append(img_base64)
        
        return images
    
    @staticmethod
    def _check_name_match(extracted: str, expected: str) -> bool:
        """Check if extracted name reasonably matches employee name."""
        if not extracted or not expected:
            return True  # Can't check
        
        ext_parts = set(extracted.lower().split())
        exp_parts = set(expected.lower().split())
        
        # Check if at least one name part matches
        common = ext_parts.intersection(exp_parts)
        return len(common) >= 1
    
    @staticmethod
    async def _call_gemini_vision(image_base64: str, prompt: str) -> Optional[str]:
        """Call Gemini Vision API directly with production-grade prompts."""
        try:
            api_key = os.environ.get("GEMINI_API_KEY")
            if not api_key:
                logger.error("GEMINI_API_KEY not set")
                return None
            
            client = genai.Client(api_key=api_key)
            
            # Determine image media type
            if image_base64.startswith('/9j/'):
                media_type = "image/jpeg"
            elif image_base64.startswith('iVBOR'):
                media_type = "image/png"
            elif image_base64.startswith('JVBERi'):
                media_type = "application/pdf"
            else:
                media_type = "image/png"
            
            response = client.models.generate_content(
                model="gemini-2.5-flash",
                contents=[
                    {
                        "role": "user",
                        "parts": [
                            {"text": prompt},
                            {"inline_data": {"mime_type": media_type, "data": image_base64}}
                        ]
                    }
                ]
            )
            
            return response.text
        except Exception as e:
            logger.error(f"Gemini Vision call failed: {e}")
            return None
    
    @staticmethod
    def _parse_json_response(response_text: str) -> dict:
        """Parse JSON from model response with JSON guard."""
        if not response_text:
            return {}
        
        # Remove markdown code blocks if present
        text = response_text
        if "```json" in text:
            text = text.split("```json")[1].split("```")[0]
        elif "```" in text:
            text = text.split("```")[1].split("```")[0]
        
        # JSON Guard - models sometimes add text before JSON
        match = re.search(r"\{.*\}", text, re.S)
        if match:
            try:
                return json.loads(match.group())
            except json.JSONDecodeError:
                pass
        
        try:
            return json.loads(text.strip())
        except json.JSONDecodeError:
            return {}
    
    @staticmethod
    async def _extract_training_certificate(
        images: List[str], 
        api_key: str, 
        employee_name: str
    ) -> dict:
        """Extract training certificate fields using Gemini Vision."""
        fields = {}
        metadata = {}
        issues = []
        
        try:
            prompt = """You are a document extraction specialist analyzing training certificates.

Extract the following fields from the training certificate:
- holder_name: Name of the certificate holder
- training_title: Title/name of the training course
- provider_name: Training provider/organization
- completion_date: Date training was completed (format: YYYY-MM-DD)
- expiry_date: Expiry date if explicitly stated (format: YYYY-MM-DD), null if not found
- duration_text: Duration of training (e.g., "3 hours", "1 day")
- reference_number: Certificate/reference number if present
- accreditation: Any accreditation body mentioned

IMPORTANT:
- Return dates in YYYY-MM-DD format
- If a field is not found, set it to null
- If expiry is not explicitly stated, do NOT guess it - leave null
- Set confidence for each field (0.0-1.0)

Return JSON only:
{
  "holder_name": {"value": "string or null", "confidence": 0.0-1.0},
  "training_title": {"value": "string or null", "confidence": 0.0-1.0},
  "provider_name": {"value": "string or null", "confidence": 0.0-1.0},
  "completion_date": {"value": "YYYY-MM-DD or null", "confidence": 0.0-1.0},
  "expiry_date": {"value": "YYYY-MM-DD or null", "confidence": 0.0-1.0},
  "duration_text": {"value": "string or null", "confidence": 0.0-1.0},
  "reference_number": {"value": "string or null", "confidence": 0.0-1.0},
  "accreditation": {"value": "string or null", "confidence": 0.0-1.0}
}

Extract all fields from this training certificate. Return JSON only."""
            
            result = await DocumentExtractionService._call_gemini_vision(images[0], prompt)
            
            if result:
                # Parse JSON response
                try:
                    json_match = re.search(r'\{[\s\S]*\}', result)
                    if json_match:
                        data = json.loads(json_match.group())
                        
                        for field_name, field_data in data.items():
                            if isinstance(field_data, dict):
                                value = field_data.get("value")
                                confidence = field_data.get("confidence", 0.5)
                            else:
                                value = field_data
                                confidence = 0.5
                            
                            fields[field_name] = value
                            metadata[field_name] = {
                                "source_type": "explicit" if value else "not_found",
                                "confidence": confidence,
                                "raw_evidence": None
                            }
                except json.JSONDecodeError as e:
                    logger.error(f"Failed to parse extraction JSON: {e}")
                    issues.append({
                        "code": "parse_error",
                        "detail": "Could not parse extraction results",
                        "severity": "warning"
                    })
            
            # Check for low confidence
            for field_name, meta in metadata.items():
                if meta.get("confidence", 0) < 0.5 and fields.get(field_name):
                    issues.append({
                        "code": "low_confidence_extraction",
                        "detail": f"Low confidence ({meta.get('confidence'):.0%}) for {field_name}",
                        "severity": "info"
                    })
            
            # Try to infer expiry from internal policy if not explicit
            if not fields.get("expiry_date") and fields.get("completion_date"):
                training_title = fields.get("training_title", "").lower()
                for code, policy in TRAINING_RENEWAL_POLICIES.items():
                    if any(kw in training_title for kw in policy.get("title_keywords", [])):
                        try:
                            completion = datetime.fromisoformat(fields["completion_date"])
                            inferred_expiry = completion + timedelta(days=policy["months"] * 30)
                            fields["expiry_date"] = inferred_expiry.strftime("%Y-%m-%d")
                            fields["inferred_training_code"] = code
                            metadata["expiry_date"] = {
                                "source_type": "inferred_policy",
                                "confidence": 0.9,
                                "raw_evidence": f"Internal {policy['months']}-month renewal policy for {code}"
                            }
                            issues.append({
                                "code": "expiry_inferred_from_policy",
                                "detail": f"Expiry date inferred from internal {policy['months']}-month policy",
                                "severity": "info"
                            })
                            break
                        except:
                            pass
            
            # Check for missing critical fields
            if not fields.get("completion_date"):
                issues.append({
                    "code": "missing_completion_date",
                    "detail": "Completion date not found on certificate",
                    "severity": "warning"
                })
            
            if not fields.get("training_title"):
                issues.append({
                    "code": "training_title_unclear",
                    "detail": "Training title could not be determined",
                    "severity": "warning"
                })
            
        except Exception as e:
            logger.error(f"Training certificate extraction error: {e}")
            issues.append({
                "code": "extraction_error",
                "detail": str(e),
                "severity": "warning"
            })
        
        return {"fields": fields, "metadata": metadata, "issues": issues}
    
    @staticmethod
    async def _extract_dbs(images: List[str], api_key: str, employee_name: str) -> dict:
        """Extract DBS certificate fields using OpenAI directly with production prompts."""
        fields = {}
        metadata = {}
        issues = []
        
        # Production-grade DBS prompt
        prompt = """Extract DBS certificate information from the document.

Return JSON only.

Fields:

certificate_number
applicant_name
issue_date
check_type (basic, standard, enhanced)
status (clear, information_present)

Rules:

If the certificate states "No information recorded", status = clear.
If offences or cautions appear, status = information_present.
Certificate numbers are 12 digits.
Use ISO date format YYYY-MM-DD.

Return JSON only.

Example:

{
  "certificate_number": "001234567890",
  "applicant_name": "Jane Smith",
  "issue_date": "2025-10-12",
  "check_type": "enhanced",
  "status": "clear"
}"""
        
        try:
            result = await DocumentExtractionService._call_gemini_vision(images[0], prompt)
            
            if result:
                data = DocumentExtractionService._parse_json_response(result)
                if data:
                    # Map to expected field names
                    field_mapping = {
                        "certificate_number": "certificate_number",
                        "applicant_name": "holder_name",
                        "issue_date": "issue_date",
                        "check_type": "disclosure_type",
                        "status": "result_status"
                    }
                    for src_field, value in data.items():
                        target_field = field_mapping.get(src_field, src_field)
                        fields[target_field] = value
                        metadata[target_field] = {
                            "source_type": "explicit" if value else "not_found",
                            "confidence": 0.95 if value else 0.0
                        }
                else:
                    issues.append({"code": "parse_error", "detail": "Failed to parse response", "severity": "warning"})
            
            # DBS-specific validation
            if fields.get("certificate_number"):
                cert_num = str(fields["certificate_number"]).replace(" ", "")
                if not re.match(r'^\d{12}$', cert_num):
                    issues.append({
                        "code": "invalid_certificate_number",
                        "detail": "Certificate number should be 12 digits",
                        "severity": "warning"
                    })
            
            if not fields.get("issue_date"):
                issues.append({
                    "code": "no_explicit_expiry",
                    "detail": "DBS certificates don't expire, but your organization may have a renewal policy",
                    "severity": "info"
                })
        
        except Exception as e:
            issues.append({"code": "extraction_error", "detail": str(e), "severity": "warning"})
        
        return {"fields": fields, "metadata": metadata, "issues": issues}
    
    @staticmethod
    async def _extract_dbs_enhanced(images: List[str], api_key: str, employee_name: str) -> dict:
        """
        Enhanced DBS certificate/Update Service extraction for the 3-layer DBS model.
        Uses OpenAI directly.
        """
        fields = {}
        metadata = {}
        issues = []
        
        system_prompt = """You are a document extraction specialist analyzing DBS (Disclosure and Barring Service) documents.

You may be analyzing either:
1. A DBS Certificate (printed document)
2. A DBS Update Service screenshot (online check result)

For DBS CERTIFICATES, extract:
- certificate_number: 12-digit DBS certificate number
- dbs_level: Level (Basic, Standard, Enhanced, Enhanced with Barred Lists)
- issue_date: Certificate issue date (YYYY-MM-DD)
- name_on_certificate: Full name as shown
- workforce: Workforce type if shown (Adult, Child, Adult and Child)
- result_status: "clear" if no information, "information_present" if there are disclosures
- information_summary: Brief summary if information is present

For DBS UPDATE SERVICE SCREENSHOTS, extract:
- certificate_number: The certificate number being checked
- update_service_status: "active" if registered, "not_registered" or "expired" if not
- update_service_check_result: "no_change" if "No change to disclose", "changed" if there are changes
- last_status_check_date: Date of the check (YYYY-MM-DD)
- result_summary: Brief description of the result shown

IMPORTANT:
- DBS certificates do NOT have an expiry date
- The 12-digit certificate number may have spaces (e.g., "0012 3456 7890")
- Return dates in YYYY-MM-DD format
- Look for any indication of information/disclosures on the certificate

Return JSON only, no markdown:
{
  "document_type": {"value": "dbs_certificate" or "update_service_screenshot", "confidence": 0.0-1.0},
  "certificate_number": {"value": "string or null", "confidence": 0.0-1.0},
  "dbs_level": {"value": "basic/standard/enhanced/enhanced_barred or null", "confidence": 0.0-1.0},
  "issue_date": {"value": "YYYY-MM-DD or null", "confidence": 0.0-1.0},
  "name_on_certificate": {"value": "string or null", "confidence": 0.0-1.0},
  "workforce": {"value": "adult/child/adult_and_child or null", "confidence": 0.0-1.0},
  "result_status": {"value": "clear/information_present or null", "confidence": 0.0-1.0},
  "information_summary": {"value": "string or null", "confidence": 0.0-1.0},
  "update_service_status": {"value": "active/not_registered/expired or null", "confidence": 0.0-1.0},
  "update_service_check_result": {"value": "no_change/changed or null", "confidence": 0.0-1.0},
  "last_status_check_date": {"value": "YYYY-MM-DD or null", "confidence": 0.0-1.0},
  "result_summary": {"value": "string or null", "confidence": 0.0-1.0}
}"""
        
        user_prompt = f"Extract all DBS information from this document. {'Expected holder name: ' + employee_name if employee_name else ''} Return JSON only."
        
        try:
            result = await DocumentExtractionService._call_gemini_vision(
                images[0],
                system_prompt,
                user_prompt
            )
            
            if result:
                try:
                    # Handle markdown code blocks
                    json_text = result
                    if "```json" in result:
                        json_text = result.split("```json")[1].split("```")[0]
                    elif "```" in result:
                        json_text = result.split("```")[1].split("```")[0]
                    
                    json_match = re.search(r'\{[\s\S]*\}', json_text)
                    if json_match:
                        data = json.loads(json_match.group())
                        for field_name, field_data in data.items():
                            if isinstance(field_data, dict):
                                value = field_data.get("value")
                                confidence = field_data.get("confidence", 0.5)
                            else:
                                value = field_data
                                confidence = 0.5
                            
                            fields[field_name] = value
                            metadata[field_name] = {
                                "source_type": "explicit" if value else "not_found",
                                "confidence": confidence
                            }
                except json.JSONDecodeError as e:
                    logger.error(f"DBS extraction JSON parse error: {e}")
                    issues.append({"code": "parse_error", "detail": str(e), "severity": "warning"})
            
            # DBS-specific validation
            cert_num = fields.get("certificate_number")
            if cert_num:
                clean_num = str(cert_num).replace(" ", "").replace("-", "")
                if not re.match(r'^\d{12}$', clean_num):
                    issues.append({
                        "code": "invalid_certificate_number",
                        "detail": f"Certificate number '{cert_num}' should be 12 digits",
                        "severity": "warning"
                    })
                else:
                    fields["certificate_number"] = clean_num
            
            # Name mismatch check
            if employee_name and fields.get("name_on_certificate"):
                extracted_name = fields.get("name_on_certificate", "").lower()
                expected_parts = employee_name.lower().split()
                matches = sum(1 for part in expected_parts if part in extracted_name)
                if matches < len(expected_parts) // 2:
                    issues.append({
                        "code": "name_mismatch",
                        "detail": f"Name on certificate '{fields.get('name_on_certificate')}' may not match employee '{employee_name}'",
                        "severity": "warning"
                    })
            
            # Information present warning
            if fields.get("result_status") == "information_present":
                issues.append({
                    "code": "information_present",
                    "detail": "This DBS certificate shows information/disclosures. Manual review required.",
                    "severity": "warning"
                })
            
            # Policy-based renewal note
            if fields.get("document_type") == "dbs_certificate" and fields.get("issue_date"):
                issues.append({
                    "code": "no_statutory_expiry",
                    "detail": "DBS certificates have no statutory expiry. Set a policy-based recheck date (typically 3 years).",
                    "severity": "info"
                })
            
            # Update Service specific validation
            if fields.get("document_type") == "update_service_screenshot":
                if fields.get("update_service_check_result") == "changed":
                    issues.append({
                        "code": "update_service_changed",
                        "detail": "Update Service shows changes - request a new DBS certificate disclosure.",
                        "severity": "warning"
                    })
        
        except Exception as e:
            logger.error(f"DBS enhanced extraction error: {e}")
            issues.append({"code": "extraction_error", "detail": str(e), "severity": "warning"})
        
        return {"fields": fields, "metadata": metadata, "issues": issues}
    
    @staticmethod
    async def _extract_identity_enhanced(images: List[str], api_key: str, employee_name: str, employee_dob: str = None) -> dict:
        """
        Enhanced Identity document extraction for the 3-layer Identity model.
        
        Extracts fields needed for the Identity Result Panel:
        - Document type (passport, driving licence, national ID, BRP)
        - Full name, DOB, document number
        - Issue and expiry dates
        - Nationality
        """
        fields = {}
        metadata = {}
        issues = []
        
        try:
            prompt = f"""You are a document extraction specialist analyzing identity documents.

You may be analyzing:
1. Passport (UK or international)
2. Driving Licence (UK photocard)
3. National ID Card
4. Biometric Residence Permit (BRP)

Extract the following fields:
- document_type: Type of document (passport, driving_licence, national_id, brp)
- full_name_on_document: Full name as shown
- date_of_birth: DOB (YYYY-MM-DD)
- document_number: Passport number, licence number, etc.
- issue_date: Document issue date (YYYY-MM-DD)
- expiry_date: Document expiry date (YYYY-MM-DD)
- nationality: Nationality/country code
- gender: Gender if shown (M/F)
- place_of_birth: Place of birth if shown

IMPORTANT:
- Return dates in YYYY-MM-DD format
- For UK driving licences, the number is on the front
- For passports, the number is usually in the top right of the data page

Return JSON only:
{{
  "document_type": {{"value": "string or null", "confidence": 0.0-1.0}},
  "full_name_on_document": {{"value": "string or null", "confidence": 0.0-1.0}},
  "date_of_birth": {{"value": "YYYY-MM-DD or null", "confidence": 0.0-1.0}},
  "document_number": {{"value": "string or null", "confidence": 0.0-1.0}},
  "issue_date": {{"value": "YYYY-MM-DD or null", "confidence": 0.0-1.0}},
  "expiry_date": {{"value": "YYYY-MM-DD or null", "confidence": 0.0-1.0}},
  "nationality": {{"value": "string or null", "confidence": 0.0-1.0}},
  "gender": {{"value": "string or null", "confidence": 0.0-1.0}},
  "place_of_birth": {{"value": "string or null", "confidence": 0.0-1.0}}
}}

Extract all identity information from this document. {'Expected name: ' + employee_name if employee_name else ''} {'Expected DOB: ' + employee_dob if employee_dob else ''} Return JSON only."""
            
            result = await DocumentExtractionService._call_gemini_vision(images[0], prompt)
            
            if result:
                try:
                    json_match = re.search(r'\{[\s\S]*\}', result)
                    if json_match:
                        data = json.loads(json_match.group())
                        for field_name, field_data in data.items():
                            if isinstance(field_data, dict):
                                value = field_data.get("value")
                                confidence = field_data.get("confidence", 0.5)
                            else:
                                value = field_data
                                confidence = 0.5
                            
                            fields[field_name] = value
                            metadata[field_name] = {
                                "source_type": "explicit" if value else "not_found",
                                "confidence": confidence
                            }
                except json.JSONDecodeError as e:
                    logger.error(f"Identity extraction JSON parse error: {e}")
                    issues.append({"code": "parse_error", "detail": str(e), "severity": "warning"})
            
            # Identity-specific validation
            # Name mismatch check
            if employee_name and fields.get("full_name_on_document"):
                extracted_name = fields.get("full_name_on_document", "").lower()
                expected_parts = employee_name.lower().split()
                matches = sum(1 for part in expected_parts if part in extracted_name)
                if matches < len(expected_parts) // 2:
                    issues.append({
                        "code": "name_mismatch",
                        "detail": f"Name on document '{fields.get('full_name_on_document')}' may not match expected '{employee_name}'",
                        "severity": "warning"
                    })
                    fields["name_matches_application"] = False
                else:
                    fields["name_matches_application"] = True
            
            # DOB mismatch check
            if employee_dob and fields.get("date_of_birth"):
                if fields.get("date_of_birth") != employee_dob:
                    issues.append({
                        "code": "dob_mismatch",
                        "detail": f"DOB on document '{fields.get('date_of_birth')}' does not match expected '{employee_dob}'",
                        "severity": "warning"
                    })
                    fields["dob_matches_application"] = False
                else:
                    fields["dob_matches_application"] = True
            
            # Expiry check
            if fields.get("expiry_date"):
                try:
                    from datetime import datetime, timezone
                    expiry_dt = datetime.fromisoformat(fields["expiry_date"].replace('Z', '+00:00')).date()
                    today = datetime.now(timezone.utc).date()
                    days_until_expiry = (expiry_dt - today).days
                    
                    if days_until_expiry < 0:
                        issues.append({
                            "code": "document_expired",
                            "detail": f"Document expired {abs(days_until_expiry)} days ago",
                            "severity": "error"
                        })
                    elif days_until_expiry <= 30:
                        issues.append({
                            "code": "document_expiring_soon",
                            "detail": f"Document expires in {days_until_expiry} days",
                            "severity": "warning"
                        })
                except (ValueError, TypeError):
                    pass
        
        except Exception as e:
            logger.error(f"Identity extraction error: {e}")
            issues.append({"code": "extraction_error", "detail": str(e), "severity": "warning"})
        
        return {"fields": fields, "metadata": metadata, "issues": issues}
    
