@api_router.post("/request-document")
async def request_document(
    employee_id: str,
    document_type_id: str,
    message: Optional[str] = None,
    due_date: Optional[str] = None,
    send_email: bool = True,
    user: dict = Depends(require_manager_or_admin)
):
    employee = await db.employees.find_one({"id": employee_id}, {"_id": 0})
    if not employee:
        raise HTTPException(status_code=404, detail="Employee not found")
    
    doc_type = await db.document_types.find_one({"id": document_type_id}, {"_id": 0})
    if not doc_type:
        raise HTTPException(status_code=404, detail="Document type not found")
    
    now = datetime.now(timezone.utc).isoformat()
    
    # Create or update document record
    existing_doc = await db.employee_documents.find_one({"employee_id": employee_id, "document_type_id": document_type_id})
    
    if existing_doc:
        await db.employee_documents.update_one(
            {"id": existing_doc['id']},
            {"$set": {"status": DocumentStatus.REQUESTED, "notes": message}}
        )
        doc_id = existing_doc['id']
    else:
        doc_id = str(uuid.uuid4())
        doc_data = {
            "id": doc_id,
            "employee_id": employee_id,
            "document_type_id": document_type_id,
            "document_type_name": doc_type['name'],
            "category": doc_type['category'],
            "file_url": None,
            "original_filename": None,
            "status": DocumentStatus.REQUESTED,
            "uploaded_by": None,
            "uploaded_at": None,
            "reviewed_by": None,
            "reviewed_at": None,
            "expiry_date": None,
            "notes": message,
            "version_number": 1,
            "created_at": now
        }
        await db.employee_documents.insert_one(doc_data)
    
    await log_audit_action(user['user_id'], "request_document", "employee_document", doc_id, {"document_type": doc_type['name'], "employee_id": employee_id})
    
    # Send email notification
    if send_email and resend.api_key:
        try:
            await asyncio.to_thread(resend.Emails.send, {
                "from": SENDER_EMAIL,
                "to": [employee['email']],
                "reply_to": REPLY_TO_EMAIL,
                "subject": "Document Request - Osabea Recruitment Team",
                "html": f"""
                <h2>Document Request</h2>
                <p>Dear {employee['first_name']},</p>
                <p>We need you to upload the following document to complete your requirements:</p>
                <p><strong>{doc_type['name']}</strong></p>
                {f'<p>{message}</p>' if message else ''}
                {f'<p>Due date: {due_date}</p>' if due_date else ''}
                <p>Please log in to your portal and upload the requested document.</p>
                <p>Thank you,<br>Osabea Recruitment Team</p>
                """
            })
        except Exception as e:
            logger.error(f"Failed to send document request email: {e}")
    
    return {"message": "Document request created", "document_id": doc_id}

# ==================== ADMIN DOCUMENT REQUEST ENDPOINTS ====================

@api_router.post("/employees/{employee_id}/request-document")
async def request_document_from_employee(
    employee_id: str,
    requirement_id: str,
    message: Optional[str] = None,
    due_days: int = 14,
    force_resend: bool = False,
    user: dict = Depends(require_manager_or_admin)
):
    """
    Request a specific document using the email automation system.
    
    Args:
        force_resend: If True, supersede any existing active request and send new email
    
    Returns:
        status: 'sent', 'resent', 'duplicate_blocked', or 'error'
    """
    employee = await db.employees.find_one({"id": employee_id}, {"_id": 0})
    if not employee:
        raise HTTPException(status_code=404, detail="Employee not found")
    
    # Get requirement name from document_types or use requirement_id
    doc_type = await db.document_types.find_one({"id": requirement_id}, {"_id": 0, "name": 1})
    requirement_name = doc_type.get("name") if doc_type else requirement_id
    
    try:
        context = {"custom_message": message} if message else None
        result = await EmailRequestService.create_request(
            person_id=employee_id,
            person_type="employee",
            requirement_id=requirement_id,
            request_type=RequestType.UPLOAD_DOCUMENT,
            due_days=due_days,
            context=context,
            admin_id=user['user_id'],
            force_resend=force_resend
        )
        
        if result.get("status") == "error":
            raise HTTPException(status_code=400, detail=result.get("reason", "Failed"))
        
        # Return the actual status from EmailRequestService
        response_status = result.get("status")  # 'sent', 'resent', 'duplicate_blocked', etc.
        
        # Only log audit for actual sends
        if response_status in ["sent", "resent"]:
            await log_audit_action(user['user_id'], "document_requested", "employee", employee_id, {
                "requirement_id": requirement_id, 
                "requirement_name": requirement_name, 
                "request_id": result.get("request_id"),
                "is_resend": response_status == "resent",
                "superseded_request_id": result.get("superseded_request_id")
            })
        
        # Build response message
        if response_status == "sent":
            message_text = f"Request sent to {employee['email']}"
        elif response_status == "resent":
            message_text = f"Request resent to {employee['email']} (previous request superseded)"
        elif response_status == "duplicate_blocked":
            message_text = result.get("reason", "An active request already exists")
        else:
            message_text = result.get("reason", "Request processed")
        
        return {
            "status": response_status,
            "request_id": result.get("request_id"),
            "existing_request_id": result.get("existing_request_id"),
            "superseded_request_id": result.get("superseded_request_id"),
            "message": message_text,
            "requirement": requirement_name,
            "due_date": result.get("due_date")
        }
    except Exception as e:
        logger.error(f"Failed to create document request: {e}")
        raise HTTPException(status_code=500, detail=str(e))


class BatchDocumentRequest(BaseModel):
    """Request model for batch document requests."""
    requirement_ids: List[str] = Field(..., description="List of requirement IDs to request")
    requirements: List[dict] = Field(default=[], description="Full requirement details for email")
    custom_message: Optional[str] = Field(None, description="Custom message to include in email")
    due_days: int = Field(default=14, description="Days until due date")


@api_router.post("/employees/{employee_id}/request-documents/batch")
async def request_documents_batch(
    employee_id: str,
    request: BatchDocumentRequest,
    user: dict = Depends(require_manager_or_admin)
):
    """
    Send a SINGLE consolidated email requesting multiple documents.
    
    This replaces the old behavior of sending multiple individual emails.
    Creates one batch request record and sends one email with all requirements.
    """
    employee = await db.employees.find_one({"id": employee_id}, {"_id": 0})
    if not employee:
        raise HTTPException(status_code=404, detail="Employee not found")
    
    if not employee.get("email"):
        raise HTTPException(status_code=400, detail="Employee has no email address")
    
    if not request.requirement_ids:
        raise HTTPException(status_code=400, detail="No requirements specified")
    
    now = datetime.now(timezone.utc)
    due_date = now + timedelta(days=request.due_days)
    
    # Create a single batch request record
    batch_request_id = f"batch_req_{uuid.uuid4().hex[:12]}"
    
    batch_record = {
        "id": batch_request_id,
        "employee_id": employee_id,
        "request_type": "batch_document_request",
        "requirement_ids": request.requirement_ids,
        "requirements": request.requirements,
        "status": "pending",
        "created_at": now.isoformat(),
        "created_by": user['user_id'],
        "due_date": due_date.isoformat(),
        "custom_message": request.custom_message,
        "email_sent": False
    }
    
    await db.email_requests.insert_one(batch_record)
    
    # Build consolidated email content
    employee_name = f"{employee.get('first_name', '')} {employee.get('last_name', '')}".strip() or "there"
    
    requirements_html = ""
    requirements_text = ""
    for i, req in enumerate(request.requirements, 1):
        req_name = req.get('name', req.get('id', 'Document'))
        req_desc = req.get('description', '')
        requirements_html += f"""
        <tr style="border-bottom: 1px solid #e5e7eb;">
            <td style="padding: 12px; font-weight: 500; color: #1f2937;">{i}. {req_name}</td>
            <td style="padding: 12px; color: #6b7280;">{req_desc or 'Required document'}</td>
        </tr>
        """
        requirements_text += f"{i}. {req_name}\n   {req_desc or 'Required document'}\n\n"
    
    # Get upload portal URL
    upload_url = f"{os.environ.get('FRONTEND_URL', 'https://app.osabeacares.co.uk')}/public/upload/{employee_id}"
    
    custom_message_html = ""
    if request.custom_message:
        custom_message_html = f"""
        <div style="background: #fef3c7; border-left: 4px solid #f59e0b; padding: 16px; margin: 20px 0; border-radius: 4px;">
            <p style="margin: 0; color: #92400e; font-weight: 500;">Message from your employer:</p>
            <p style="margin: 8px 0 0 0; color: #78350f;">{request.custom_message}</p>
        </div>
        """
    
    email_html = f"""
    <!DOCTYPE html>
    <html>
    <head>
        <meta charset="utf-8">
        <meta name="viewport" content="width=device-width, initial-scale=1.0">
    </head>
    <body style="font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif; line-height: 1.6; color: #374151; max-width: 600px; margin: 0 auto; padding: 20px;">
        <div style="background: linear-gradient(135deg, #4f46e5 0%, #7c3aed 100%); padding: 30px; border-radius: 12px 12px 0 0; text-align: center;">
            <h1 style="color: white; margin: 0; font-size: 24px;">Documents Required</h1>
        </div>
        
        <div style="background: white; padding: 30px; border: 1px solid #e5e7eb; border-top: none; border-radius: 0 0 12px 12px;">
            <p style="font-size: 16px; margin-bottom: 20px;">Hi {employee_name},</p>
            
            <p>We need you to upload the following documents to complete your compliance file:</p>
            
            {custom_message_html}
            
            <table style="width: 100%; border-collapse: collapse; margin: 20px 0; background: #f9fafb; border-radius: 8px; overflow: hidden;">
                <thead>
                    <tr style="background: #f3f4f6;">
                        <th style="padding: 12px; text-align: left; color: #4b5563; font-weight: 600;">Document</th>
                        <th style="padding: 12px; text-align: left; color: #4b5563; font-weight: 600;">Details</th>
                    </tr>
                </thead>
                <tbody>
                    {requirements_html}
                </tbody>
            </table>
            
            <p style="color: #6b7280;"><strong>Due by:</strong> {due_date.strftime('%d %B %Y')}</p>
            
            <div style="text-align: center; margin: 30px 0;">
                <a href="{upload_url}" style="display: inline-block; background: linear-gradient(135deg, #4f46e5 0%, #7c3aed 100%); color: white; padding: 14px 32px; border-radius: 8px; text-decoration: none; font-weight: 600; font-size: 16px;">
                    Upload Documents
                </a>
            </div>
            
            <p style="color: #9ca3af; font-size: 14px; margin-top: 30px; padding-top: 20px; border-top: 1px solid #e5e7eb;">
                If you have any questions, please contact your manager.
            </p>
        </div>
    </body>
    </html>
    """
    
    # Send email via Resend
    resend_api_key = os.environ.get("RESEND_API_KEY")
    email_sent = False
    
    if resend_api_key:
        try:
            import resend
            resend.api_key = resend_api_key
            
            from_email = os.environ.get("FROM_EMAIL", "compliance@osabeacares.co.uk")
            
            email_response = resend.Emails.send({
                "from": f"Compliance Team <{from_email}>",
                "to": [employee['email']],
                "subject": f"Action Required: {len(request.requirement_ids)} Document(s) Needed",
                "html": email_html
            })
            
            logger.info(f"Batch request email sent to {employee['email']}: {email_response}")
            email_sent = True
            
        except Exception as e:
            logger.error(f"Failed to send batch request email: {e}")
    else:
        logger.warning("RESEND_API_KEY not configured - email not sent")
    
    # Update batch record
    await db.email_requests.update_one(
        {"id": batch_request_id},
        {"$set": {
            "email_sent": email_sent,
            "email_sent_at": now.isoformat() if email_sent else None,
            "status": "sent" if email_sent else "pending"
        }}
    )
    
    # Log audit
    await log_audit_action(user['user_id'], "batch_document_request", "employee", employee_id, {
        "batch_request_id": batch_request_id,
        "requirement_count": len(request.requirement_ids),
        "requirement_ids": request.requirement_ids,
        "email_sent": email_sent,
        "due_date": due_date.isoformat()
    })
    
    return {
        "success": True,
        "batch_request_id": batch_request_id,
        "requirement_count": len(request.requirement_ids),
        "email_sent": email_sent,
        "due_date": due_date.isoformat(),
        "message": f"Request for {len(request.requirement_ids)} document(s) sent to {employee['email']}" if email_sent else "Request created (email not configured)"
    }


@api_router.post("/employees/{employee_id}/request-missing-items")
async def request_all_missing_items(employee_id: str, user: dict = Depends(require_manager_or_admin)):
    """Request all missing requirements from an employee."""
    employee = await db.employees.find_one({"id": employee_id}, {"_id": 0})
    if not employee:
        raise HTTPException(status_code=404, detail="Employee not found")
    
    # Get compliance requirements
    compliance_data = await get_compliance_requirements(employee_id, user)
    requirements = compliance_data.get("requirements", [])
    
    missing_items = [{"id": req["id"], "name": req["name"]} for req in requirements if req.get("status") in ["missing", "not_started", "required"]]
    
    if not missing_items:
        return {"status": "no_action", "message": "No missing items found"}
    
    created_requests = []
    for item in missing_items:
        try:
            result = await EmailRequestService.create_request(
                person_id=employee_id, person_type="employee", requirement_id=item["id"],
                request_type=RequestType.UPLOAD_DOCUMENT, due_days=14
            )
            if result.get("status") != "error":
                created_requests.append({"requirement_id": item["id"], "requirement_name": item["name"], "request_id": result.get("request_id")})
        except Exception as e:
            logger.error(f"Failed for {item['id']}: {e}")
    
    await log_audit_action(user['user_id'], "bulk_document_request", "employee", employee_id, {
        "total_items": len(missing_items), "requests_created": len(created_requests)
    })
    
    return {"status": "success", "message": f"Requested {len(created_requests)} items", "requests": created_requests}


@api_router.get("/employees/{employee_id}/document-requests")
async def get_employee_document_requests(employee_id: str, user: dict = Depends(get_current_user)):
    """Get document request history for an employee."""
    requests = await db.email_requests.find({"person_id": employee_id}, {"_id": 0}).sort("created_at", -1).to_list(100)
    
    # Get all document types for name lookup
    doc_types = {dt["id"]: dt["name"] async for dt in db.document_types.find({}, {"_id": 0, "id": 1, "name": 1})}
    
    for req in requests:
        req_id = req.get("requirement_id")
        req["requirement_name"] = doc_types.get(req_id, req_id)
    
    return requests


