@api_router.get("/bulk/requests/attributed")
async def get_attributed_requests(
    source: Optional[str] = None,  # 'manual' or 'scheduled'
    schedule_id: Optional[str] = None,
    limit: int = 100,
    user: dict = Depends(require_manager_or_admin)
):
    """
    Get requests with source attribution.
    Shows which requests were created manually vs by schedules.
    """
    query = {"person_type": "employee"}
    
    if source:
        query["created_source"] = source
    
    if schedule_id:
        query["schedule_id"] = schedule_id
    
    requests = await db.email_requests.find(query, {"_id": 0}).sort("created_at", -1).limit(limit).to_list(limit)
    
    # Enrich with employee names
    emp_ids = list(set(r.get("person_id") for r in requests if r.get("person_id")))
    if emp_ids:
        employees = await EmployeesRepository.list_employees(
            filter_dict={"id": {"$in": emp_ids}},
            projection={"_id": 0, "id": 1, "first_name": 1, "last_name": 1, "email": 1}
        )
        emp_map = {e["id"]: e for e in employees}
        
        for req in requests:
            emp = emp_map.get(req.get("person_id"), {})
            req["employee_name"] = f"{emp.get('first_name', '')} {emp.get('last_name', '')}".strip() or "Unknown"
            req["employee_email"] = emp.get("email", "")
    
    return {
        "requests": requests,
        "total": len(requests)
    }


# ==================== APSCHEDULER SETUP ====================
# Durable scheduler with periodic execution

scheduler = AsyncIOScheduler()

async def scheduled_bulk_request_job():
    """
    Periodic job to run all due scheduled bulk requests.
    Runs every hour to catch up on any missed schedules.
    """
    try:
        logger.info("Running scheduled bulk request check...")
        result = await ScheduledBulkRequestService.run_due_schedules()
        logger.info(f"Scheduled run complete: {result.get('schedules_executed')} schedules executed, "
                   f"{result.get('total_requests_created')} requests created")
    except Exception as e:
        logger.error(f"Scheduled bulk request job failed: {e}")


def start_scheduler():
    """Start the APScheduler with durable job."""
    if not scheduler.running:
        # Run every hour at minute 15 (avoid exact hour boundaries)
        scheduler.add_job(
            scheduled_bulk_request_job,
            CronTrigger(minute=15),  # Every hour at :15
            id="scheduled_bulk_requests",
            replace_existing=True,
            misfire_grace_time=3600  # Allow catch-up within 1 hour
        )
        
        # Add comprehensive expiry reminder job (runs daily at 8am)
        # This handles BOTH training AND documents (DBS, RTW, Professional Registration)
        scheduler.add_job(
            comprehensive_expiry_reminder_job,
            CronTrigger(hour=8, minute=0),  # Daily at 8:00 AM
            id="comprehensive_expiry_reminders",
            replace_existing=True,
            misfire_grace_time=7200  # Allow catch-up within 2 hours
        )
        
        # Legacy training-only job (kept for backwards compatibility, runs at 8:30am)
        scheduler.add_job(
            training_expiry_reminder_job,
            CronTrigger(hour=8, minute=30),  # Daily at 8:30 AM
            id="training_expiry_reminders",
            replace_existing=True,
            misfire_grace_time=7200  # Allow catch-up within 2 hours
        )
        
        scheduler.start()
        logger.info("APScheduler started: bulk requests (hourly), comprehensive expiry reminders (8am daily), training reminders (8:30am daily)")


# ==================== TRAINING EXPIRY REMINDER SYSTEM ====================

TRAINING_EXPIRY_REMINDER_DAYS = 60  # Send reminder when training expires within 60 days

async def get_expiring_trainings(days_threshold: int = 60) -> List[dict]:
    """
    Get all trainings expiring within the specified number of days.
    Returns list of trainings grouped by employee.
    """
    now = datetime.now(timezone.utc)
    threshold_date = now + timedelta(days=days_threshold)
    
    # Get all active training records expiring within threshold
    pipeline = [
        {
            "$match": {
                "expiry_date": {
                    "$exists": True,
                    "$ne": None,
                    "$lte": threshold_date.isoformat(),
                    "$gt": now.isoformat()
                },
                "record_status": {"$ne": "superseded"}
            }
        },
        {
            "$lookup": {
                "from": "employees",
                "localField": "employee_id",
                "foreignField": "id",
                "as": "employee"
            }
        },
        {
            "$unwind": "$employee"
        },
        {
            "$match": {
                "employee.status": {"$ne": "archived"}
            }
        },
        {
            "$project": {
                "_id": 0,
                "training_id": "$id",
                "training_name": 1,
                "expiry_date": 1,
                "employee_id": 1,
                "employee_name": {
                    "$concat": ["$employee.first_name", " ", "$employee.last_name"]
                },
                "employee_email": "$employee.email",
                "mandatory": 1,
                "is_mandatory": 1
            }
        },
        {
            "$sort": {"expiry_date": 1}
        }
    ]
    
    expiring_trainings = await db.training_records.aggregate(pipeline).to_list(1000)
    return expiring_trainings


