@app.on_event("startup")
async def startup():
    try:
        init_storage()
    except Exception as e:
        logger.error(f"Storage initialization failed: {e}")
    
    # Initialize CQC Compliance Services
    try:
        init_audit_service(db)
        init_compliance_status_service(db)
        init_health_service(db)
        logger.info("CQC Compliance services initialized (Audit, Status, Health)")
    except Exception as e:
        logger.error(f"CQC Compliance services initialization failed: {e}")
    
    # Auto-seed organisation policies and insurance if empty
    try:
        policy_count = await db.org_policies.count_documents({})
        if policy_count == 0:
            now = datetime.now(timezone.utc).isoformat()
            for policy in CORE_POLICIES:
                policy_doc = {
                    "id": str(uuid.uuid4()),
                    "name": policy["name"],
                    "category": policy["category"],
                    "version": "v1.0",
                    "status": "missing",
                    "file_url": None,
                    "original_filename": None,
                    "review_date": None,
                    "last_reviewed_at": None,
                    "reviewed_by": None,
                    "notes": None,
                    "created_at": now,
                    "updated_at": now,
                    "created_by": "system"
                }
                await db.org_policies.insert_one(policy_doc)
            logger.info(f"Auto-seeded {len(CORE_POLICIES)} organisation policies")
    except Exception as e:
        logger.error(f"Auto-seeding policies failed: {e}")


@app.on_event("startup")
async def startup_db_client():
    """Auto-seed compliance items on startup"""
    try:
        insurance_count = await db.insurance_docs.count_documents({})
        if insurance_count == 0:
            now = datetime.now(timezone.utc).isoformat()
            for ins in INSURANCE_TYPES:
                doc = {
                    "id": str(uuid.uuid4()),
                    "name": ins["name"],
                    "insurance_type": ins["type"],
                    "status": "missing",
                    "file_url": None,
                    "original_filename": None,
                    "expiry_date": None,
                    "policy_number": None,
                    "provider": None,
                    "notes": None,
                    "created_at": now,
                    "updated_at": now
                }
                await db.insurance_docs.insert_one(doc)
            logger.info(f"Auto-seeded {len(INSURANCE_TYPES)} insurance documents")
        
        # Phase 1: Auto-seed training catalogue from MANDATORY_ITEMS
        catalogue_count = await db.training_catalogue.count_documents({})
        if catalogue_count == 0:
            result = await ensure_training_catalogue_exists()
            # Create indexes
            await db.training_catalogue.create_index("id", unique=True)
            await db.training_catalogue.create_index("active")
            await db.employee_training_assignments.create_index([("employee_id", 1), ("training_id", 1)], unique=True)
            await db.employee_training_assignments.create_index("employee_id")
            logger.info(f"Phase 1: Auto-seeded training catalogue with {result['seeded']} items")
    except Exception as e:
        logger.error(f"Auto-seeding failed: {e}")

@app.on_event("shutdown")
async def shutdown_db_client():
    client.close()


@app.on_event("startup")
async def startup_read_source_pool():
    """Initialize Supabase Postgres pool if configured."""
    try:
        pool = await get_pg_pool()
        if pool:
            logger.info("Read source switch: Supabase Postgres pool ready")
        else:
            logger.info("Read source switch: Using MongoDB only (SUPABASE_DB_URL not configured)")
    except Exception as e:
        logger.warning(f"Read source switch: Postgres pool init failed, using Mongo fallback: {e}")


@app.on_event("shutdown")
async def shutdown_read_source_pool():
    """Close Supabase Postgres pool."""
    try:
        await close_pg_pool()
    except Exception as e:
        logger.error(f"Read source switch: Pool shutdown error: {e}")


@app.on_event("startup")
async def startup_scheduler():
    """Start APScheduler for scheduled bulk requests."""
    try:
        start_scheduler()
        logger.info("Scheduled bulk request scheduler started")
    except Exception as e:
        logger.error(f"Failed to start scheduler: {e}")


@app.on_event("shutdown")
async def shutdown_scheduler():
    """Gracefully shutdown the scheduler."""
    try:
        if scheduler.running:
            scheduler.shutdown(wait=False)
            logger.info("Scheduler shutdown complete")
    except Exception as e:
        logger.error(f"Scheduler shutdown error: {e}")
